RICETTE_DB=[{id:"tpl_1021",nome:"Pasta al pesto genovese",nome_en:"Pasta with Genoese pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare basilico, pinoli, aglio, pecorino, parmigiano e olio a freddo. Cuocere le trofie in acqua salata. Scolare al dente, mantecare con il pesto aggiungendo un cucchiaio di acqua di cottura.",note_en:"Blend basil, pine nuts, garlic, pecorino, parmesan and oil cold. Cook trofie in salted water. Drain al dente, toss with pesto adding a spoonful of cooking water.",ingredienti:[{nome:"Trofie",qt:"320g"},{nome:"Basilico fresco",qt:"60g"},{nome:"Pinoli",qt:"40g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Pecorino grattugiato",qt:"20g"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Pasta al pesto genovese (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:13,gs:3,g:18,z:2,ch:55,fi:2.5,ca:120,fe:2,mg:40,k2:200,na:180,zn:1.2,fo:30,se:8,col:8}},{id:"tpl_1022",nome:"Pasta e fagioli napoletana",nome_en:"Neapolitan pasta and beans",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio, rosmarino e pomodoro. Aggiungere fagioli borlotti lessati e brodo. Cuocere 15 minuti. Aggiungere pasta mista corta e cuocere al dente. Finire con olio crudo e pepe.",note_en:"Sauté garlic, rosemary and tomato. Add boiled borlotti beans and stock. Cook 15 minutes. Add mixed short pasta and cook al dente. Finish with raw oil and pepper.",ingredienti:[{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Pasta mista",qt:"200g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"500ml"}],_dbEntry:{n:"Pasta e fagioli napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:1,g:7,z:3,ch:52,fi:9,ca:70,fe:3.5,mg:60,k2:580,na:320,zn:1.5,fo:120,se:6,col:0}},{id:"tpl_1023",nome:"Risotto ai funghi porcini",nome_en:"Porcini mushroom risotto",categoria:"Primo piatto",porzioni:4,note:"Ammollare i porcini secchi 30 minuti. Soffriggere scalogno, aggiungere riso e tostare. Sfumare con vino bianco. Aggiungere brodo caldo mestolo per mestolo. Aggiungere i porcini ammollati. Mantecare con burro e parmigiano.",note_en:"Soak dried porcini 30 minutes. Sauté shallot, add rice and toast. Deglaze with white wine. Add hot stock ladle by ladle. Add soaked porcini. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Porcini secchi",qt:"30g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano grattugiato",qt:"50g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto ai funghi porcini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:5,g:10,z:2,ch:60,fi:1.5,ca:110,fe:1.5,mg:30,k2:220,na:350,zn:1,fo:25,se:10,col:30}},{id:"tpl_1024",nome:"Spaghetti alla carbonara",nome_en:"Spaghetti carbonara",categoria:"Primo piatto",porzioni:4,note:"Rosolare guanciale a cubetti in padella senza olio fino a croccante. Sbattere tuorli con pecorino e pepe nero. Cuocere gli spaghetti al dente, scolare tenendo acqua di cottura. Mantecare fuori fuoco amalgamando uova e guanciale con poca acqua di cottura.",note_en:"Brown diced guanciale in pan without oil until crispy. Beat egg yolks with pecorino and black pepper. Cook spaghetti al dente, drain keeping cooking water. Toss off heat combining eggs and guanciale with a little cooking water.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Guanciale",qt:"150g"},{nome:"Tuorli d uovo",qt:"6"},{nome:"Pecorino romano",qt:"80g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Spaghetti alla carbonara (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:22,gs:8,g:20,z:1,ch:55,fi:1,ca:200,fe:2,mg:35,k2:250,na:700,zn:2.5,fo:60,se:20,col:320}},{id:"tpl_1025",nome:"Lasagne al forno classiche",nome_en:"Classic baked lasagne",categoria:"Primo piatto",porzioni:6,note:"Preparare ragu di carne con macinato, pomodoro e soffritto. Preparare besciamella. Alternare strati di pasta, ragu, besciamella e parmigiano in teglia. Cuocere in forno a 180 C per 45 minuti.",note_en:"Prepare meat ragu with mince, tomato and soffritto. Make bechamel. Alternate layers of pasta, ragu, bechamel and parmesan in baking dish. Bake at 180 C for 45 minutes.",ingredienti:[{nome:"Lasagne fresche",qt:"400g"},{nome:"Macinato misto",qt:"400g"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Latte intero",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"80g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Lasagne al forno classiche (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:6,g:16,z:4,ch:38,fi:2,ca:220,fe:2.5,mg:35,k2:420,na:480,zn:3,fo:40,se:18,col:85}},{id:"tpl_1026",nome:"Minestra di ceci e rosmarino",nome_en:"Chickpea and rosemary soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio e rosmarino in olio. Aggiungere ceci lessati e brodo. Frullare meta della zuppa per darle cremosita. Aggiungere pasta corta o pasta mista. Cuocere al dente e servire con olio crudo.",note_en:"Sauté garlic and rosemary in oil. Add cooked chickpeas and stock. Blend half the soup for creaminess. Add short pasta. Cook al dente and serve with raw oil.",ingredienti:[{nome:"Ceci cotti",qt:"500g"},{nome:"Pasta corta",qt:"160g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Minestra di ceci e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:15,gs:1,g:8,z:2,ch:52,fi:11,ca:80,fe:4,mg:65,k2:600,na:280,zn:2,fo:140,se:5,col:0}},{id:"tpl_1027",nome:"Risotto alla milanese",nome_en:"Milanese saffron risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla in burro e midollo. Tostare il riso, sfumare con vino bianco. Aggiungere brodo caldo a mestoli. A meta cottura aggiungere lo zafferano sciolto in brodo caldo. Mantecare con burro freddo e parmigiano.",note_en:"Sauté onion in butter and marrow. Toast rice, deglaze with white wine. Add hot stock in ladles. Halfway through add saffron dissolved in hot stock. Stir in cold butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Cipolla bianca",qt:"1"},{nome:"Midollo di bue",qt:"30g"},{nome:"Burro",qt:"60g"},{nome:"Parmigiano",qt:"60g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo di carne",qt:"1L"}],_dbEntry:{n:"Risotto alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:12,gs:7,g:14,z:2,ch:58,fi:.5,ca:130,fe:1.5,mg:28,k2:200,na:400,zn:1.2,fo:20,se:8,col:45}},{id:"tpl_1028",nome:"Pasta al pomodoro fresco",nome_en:"Pasta with fresh tomato",categoria:"Primo piatto",porzioni:4,note:"Scottare i pomodori in acqua bollente, pelarli e tagliarli a pezzi. Soffriggere aglio in olio, aggiungere pomodori e cuocere 15 minuti. Cuocere la pasta al dente. Condire con il sugo e basilico fresco.",note_en:"Blanch tomatoes in boiling water, peel and chop. Sauté garlic in oil, add tomatoes and cook 15 minutes. Cook pasta al dente. Dress with sauce and fresh basil.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori maturi",qt:"600g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Pasta al pomodoro fresco (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:11,gs:1,g:8,z:5,ch:60,fi:3,ca:40,fe:2,mg:38,k2:380,na:160,zn:.9,fo:35,se:7,col:0}},{id:"tpl_1029",nome:"Gnocchi al gorgonzola e noci",nome_en:"Gnocchi with gorgonzola and walnuts",categoria:"Primo piatto",porzioni:4,note:"Sciogliere il gorgonzola a fuoco basso con panna e poco latte. Aggiustare di sale e pepe. Cuocere gli gnocchi in acqua salata finche vengono a galla. Scolare e condire con la crema di gorgonzola. Aggiungere gherigli di noce tritati.",note_en:"Melt gorgonzola over low heat with cream and a little milk. Season with salt and pepper. Cook gnocchi in salted water until they float. Drain and dress with gorgonzola cream. Add chopped walnuts.",ingredienti:[{nome:"Gnocchi di patate",qt:"600g"},{nome:"Gorgonzola dolce",qt:"150g"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Gherigli di noce",qt:"50g"},{nome:"Latte",qt:"50ml"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Gnocchi al gorgonzola e noci (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:14,gs:9,g:18,z:2,ch:52,fi:2,ca:180,fe:1.5,mg:45,k2:280,na:520,zn:1.8,fo:25,se:6,col:55}},{id:"tpl_1030",nome:"Penne all arrabbiata",nome_en:"Penne arrabbiata",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in abbondante olio. Aggiungere pomodori pelati spezzettati e cuocere 20 minuti. Cuocere le penne al dente. Scolare e saltare nel sugo. Aggiungere prezzemolo tritato.",note_en:"Sauté garlic and chilli in plenty of oil. Add chopped peeled tomatoes and cook 20 minutes. Cook penne al dente. Drain and toss in sauce. Add chopped parsley.",ingredienti:[{nome:"Penne rigate",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Penne all arrabbiata (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:11,gs:1,g:10,z:4,ch:60,fi:3,ca:35,fe:2.2,mg:38,k2:380,na:200,zn:.9,fo:30,se:7,col:0}},{id:"tpl_1031",nome:"Ribollita toscana",nome_en:"Tuscan ribollita",categoria:"Primo piatto",porzioni:6,note:"Soffriggere cipolla, carota, sedano. Aggiungere fagioli cannellini, cavolo nero, verza, pane raffermo e brodo. Cuocere 40 minuti. Aggiustare di sale. La ribollita si riscalda il giorno dopo con olio crudo.",note_en:"Sauté onion, carrot, celery. Add cannellini beans, cavolo nero, savoy cabbage, stale bread and stock. Cook 40 minutes. Season with salt. Ribollita is reheated the next day with raw oil.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Cavolo nero",qt:"300g"},{nome:"Verza",qt:"200g"},{nome:"Pane raffermo toscano",qt:"200g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo vegetale",qt:"800ml"}],_dbEntry:{n:"Ribollita toscana (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:1,g:7,z:4,ch:44,fi:10,ca:100,fe:3.5,mg:55,k2:550,na:360,zn:1.5,fo:110,se:4,col:0}},{id:"tpl_1032",nome:"Pasta con le sarde",nome_en:"Pasta with sardines",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla con finocchietto selvatico. Aggiungere sarde fresche pulite, pinoli, uvetta e zafferano. Cuocere 10 minuti. Cuocere i bucatini al dente, condire con il sugo. Tostare pangrattato in olio e spolverare sul piatto.",note_en:"Sauté onion with wild fennel. Add cleaned fresh sardines, pine nuts, raisins and saffron. Cook 10 minutes. Cook bucatini al dente, dress with sauce. Toast breadcrumbs in oil and sprinkle over dish.",ingredienti:[{nome:"Bucatini",qt:"320g"},{nome:"Sarde fresche",qt:"300g"},{nome:"Finocchietto selvatico",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Pinoli",qt:"30g"},{nome:"Uvetta",qt:"30g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Pangrattato",qt:"40g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con le sarde (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:20,gs:2,g:12,z:5,ch:58,fi:3,ca:120,fe:2.5,mg:50,k2:380,na:280,zn:1.5,fo:45,se:30,col:45}},{id:"tpl_1033",nome:"Risotto al radicchio e speck",nome_en:"Risotto with radicchio and speck",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Aggiungere speck a cubetti e rosolare. Aggiungere radicchio tagliato e far appassire. Tostare il riso e sfumare con vino rosso. Aggiungere brodo caldo. Mantecare con burro e parmigiano.",note_en:"Sauté shallot in butter. Add diced speck and brown. Add sliced radicchio and wilt. Toast rice and deglaze with red wine. Add hot stock. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Vialone Nano",qt:"320g"},{nome:"Radicchio",qt:"200g"},{nome:"Speck",qt:"100g"},{nome:"Scalogno",qt:"2"},{nome:"Vino rosso",qt:"100ml"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto al radicchio e speck (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:15,gs:5,g:11,z:3,ch:58,fi:1.5,ca:100,fe:2,mg:28,k2:280,na:650,zn:1.5,fo:30,se:12,col:35}},{id:"tpl_1034",nome:"Zuppa di lenticchie rosse",nome_en:"Red lentil soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e curcuma in olio. Aggiungere lenticchie rosse lavate e brodo. Cuocere 25 minuti. Frullare fino a crema liscia. Aggiustare di sale e pepe. Servire con pane tostato e olio al rosmarino.",note_en:"Sauté onion, garlic and turmeric in oil. Add washed red lentils and stock. Cook 25 minutes. Blend to smooth cream. Season with salt and pepper. Serve with toasted bread and rosemary oil.",ingredienti:[{nome:"Lenticchie rosse",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zuppa di lenticchie rosse (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:17,gs:.8,g:5,z:3,ch:48,fi:10,ca:55,fe:4,mg:65,k2:620,na:350,zn:2,fo:160,se:6,col:0}},{id:"tpl_1035",nome:"Pasta con broccoli e acciughe",nome_en:"Pasta with broccoli and anchovies",categoria:"Primo piatto",porzioni:4,note:"Lessare i broccoli in acqua salata, tenere lacqua di cottura per la pasta. Soffriggere aglio, acciughe e peperoncino in olio fino a sciogliere le acciughe. Cuocere la pasta nell acqua dei broccoli. Saltare tutto insieme.",note_en:"Boil broccoli in salted water, keep cooking water for pasta. Sauté garlic, anchovies and chilli in oil until anchovies dissolve. Cook pasta in broccoli water. Toss everything together.",ingredienti:[{nome:"Orecchiette",qt:"320g"},{nome:"Broccoli",qt:"400g"},{nome:"Acciughe sott olio",qt:"6"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con broccoli e acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:15,gs:1.5,g:10,z:3,ch:55,fi:5,ca:80,fe:2.5,mg:55,k2:450,na:380,zn:1.5,fo:90,se:12,col:12}},{id:"tpl_1036",nome:"Risi e bisi veneti",nome_en:"Venetian rice and peas",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla e pancetta in burro. Aggiungere piselli freschi e brodo. Aggiungere il riso e cuocere aggiungendo brodo. Il piatto deve risultare piu morbido di un risotto. Mantecare con burro e parmigiano.",note_en:"Sauté onion and pancetta in butter. Add fresh peas and stock. Add rice and cook adding stock. Dish should be softer than a risotto. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Vialone Nano",qt:"280g"},{nome:"Piselli freschi",qt:"400g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Brodo vegetale",qt:"1.2L"}],_dbEntry:{n:"Risi e bisi veneti (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:14,gs:4,g:10,z:5,ch:54,fi:5,ca:100,fe:2,mg:40,k2:350,na:420,zn:1.2,fo:60,se:8,col:35}},{id:"tpl_1037",nome:"Pasta alla norma",nome_en:"Pasta alla Norma",categoria:"Primo piatto",porzioni:4,note:"Friggere melanzane a cubetti in olio abbondante, scolare su carta. Preparare sugo di pomodoro con aglio e basilico. Cuocere la pasta al dente. Condire con sugo, melanzane fritte e ricotta salata grattugiata.",note_en:"Fry diced aubergine in plenty of oil, drain on paper. Prepare tomato sauce with garlic and basil. Cook pasta al dente. Dress with sauce, fried aubergine and grated salted ricotta.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Melanzane",qt:"400g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Ricotta salata",qt:"80g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio per friggere",qt:"200ml"}],_dbEntry:{n:"Pasta alla norma (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:13,gs:2,g:14,z:5,ch:62,fi:4,ca:100,fe:2,mg:38,k2:400,na:280,zn:1,fo:40,se:8,col:10}},{id:"tpl_1038",nome:"Zuppa di farro e verdure",nome_en:"Farro and vegetable soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, carota, sedano e aglio. Aggiungere farro perlato, pomodori a cubetti e brodo vegetale. Cuocere 40 minuti. Aggiungere erbe aromatiche. Servire con olio extravergine a crudo.",note_en:"Sauté onion, carrot, celery and garlic. Add pearled farro, diced tomatoes and vegetable stock. Cook 40 minutes. Add aromatic herbs. Serve with raw extra virgin olive oil.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori a pezzetti",qt:"200g"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Erbe miste",qt:"q.b."}],_dbEntry:{n:"Zuppa di farro e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:10,gs:.5,g:5,z:4,ch:48,fi:7,ca:50,fe:2.5,mg:55,k2:450,na:320,zn:1.5,fo:55,se:6,col:0}},{id:"tpl_1039",nome:"Pasta e patate alla napoletana",nome_en:"Neapolitan pasta and potatoes",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e rosmarino. Aggiungere patate a cubetti e pomodori. Versare brodo e cuocere 20 minuti. Aggiungere pasta mista e finire la cottura. Il piatto deve essere cremoso. Finire con pecorino e olio.",note_en:"Sauté onion, garlic and rosemary. Add diced potatoes and tomatoes. Pour in stock and cook 20 minutes. Add mixed pasta and finish cooking. Dish should be creamy. Finish with pecorino and oil.",ingredienti:[{nome:"Pasta mista",qt:"200g"},{nome:"Patate",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"800ml"}],_dbEntry:{n:"Pasta e patate alla napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:10,gs:1.5,g:7,z:3,ch:58,fi:4,ca:80,fe:2,mg:40,k2:700,na:380,zn:1,fo:35,se:5,col:8}},{id:"tpl_1040",nome:"Risotto al limone e gamberi",nome_en:"Lemon and prawn risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere gamberi sgusciati, rosolare e togliere. Tostare il riso, sfumare con prosecco. Aggiungere brodo di pesce. A cottura quasi ultimata rimettere i gamberi. Mantecare con olio e scorza di limone.",note_en:"Sauté shallot in oil. Add peeled prawns, brown and remove. Toast rice, deglaze with prosecco. Add fish stock. Near end of cooking return prawns. Stir in oil and lemon zest.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Limone",qt:"2"},{nome:"Prosecco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Risotto al limone e gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:18,gs:1.5,g:8,z:2,ch:54,fi:.5,ca:80,fe:2,mg:45,k2:380,na:380,zn:2,fo:35,se:25,col:120}},{id:"tpl_1041",nome:"Strozzapreti al ragu di salsiccia",nome_en:"Strozzapreti with sausage ragu",categoria:"Primo piatto",porzioni:4,note:"Rosolare la salsiccia sbriciolata con cipolla e aglio. Sfumare con vino rosso. Aggiungere pomodoro e cuocere 30 minuti. Cuocere gli strozzapreti al dente. Condire con il ragu e pecorino grattugiato.",note_en:"Brown crumbled sausage with onion and garlic. Deglaze with red wine. Add tomato and cook 30 minutes. Cook strozzapreti al dente. Dress with ragu and grated pecorino.",ingredienti:[{nome:"Strozzapreti",qt:"320g"},{nome:"Salsiccia",qt:"250g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"100ml"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Strozzapreti al ragu di salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:20,gs:5,g:15,z:4,ch:56,fi:2.5,ca:90,fe:2.5,mg:35,k2:380,na:580,zn:2.5,fo:30,se:15,col:55}},{id:"tpl_1042",nome:"Pasta al tonno e capperi",nome_en:"Pasta with tuna and capers",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere tonno sgocciolato sbriciolato. Aggiungere capperi, olive, pomodorini. Cuocere 10 minuti. Cuocere la pasta al dente. Condire con il sugo e prezzemolo fresco.",note_en:"Sauté garlic in oil, add drained crumbled tuna. Add capers, olives, cherry tomatoes. Cook 10 minutes. Cook pasta al dente. Dress with sauce and fresh parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Tonno sott olio",qt:"200g"},{nome:"Capperi",qt:"30g"},{nome:"Olive nere",qt:"60g"},{nome:"Pomodorini",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta al tonno e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:22,gs:2,g:10,z:3,ch:54,fi:2.5,ca:50,fe:2,mg:45,k2:450,na:680,zn:1.5,fo:35,se:35,col:30}},{id:"tpl_1043",nome:"Pasta alla gricia",nome_en:"Pasta alla gricia",categoria:"Primo piatto",porzioni:4,note:"Rosolare il guanciale tagliato a listelli in padella senza olio fino a croccante. Cuocere i rigatoni al dente, scolare tenendo acqua di cottura. Mantecare in padella con guanciale, pecorino grattugiato e pepe nero. Aggiungere acqua di cottura per ottenere una crema.",note_en:"Brown guanciale strips in pan without oil until crispy. Cook rigatoni al dente, drain keeping cooking water. Toss in pan with guanciale, grated pecorino and black pepper. Add cooking water to achieve a cream.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Guanciale",qt:"150g"},{nome:"Pecorino romano",qt:"80g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla gricia (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:19,gs:7,g:16,z:1,ch:58,fi:1,ca:170,fe:1.5,mg:30,k2:220,na:700,zn:2,fo:20,se:15,col:55}},{id:"tpl_1044",nome:"Zuppa di cipolle gratinata",nome_en:"Gratineed onion soup",categoria:"Primo piatto",porzioni:4,note:"Affettare cipolle e cuocere lentamente in burro per 40 minuti fino a caramellare. Sfumare con vino bianco. Aggiungere brodo di carne. Versare in ciotole da forno, coprire con pane tostato e formaggio groviera. Gratinare in forno a 200 C.",note_en:"Slice onions and cook slowly in butter for 40 minutes until caramelised. Deglaze with white wine. Add beef stock. Pour into oven bowls, cover with toasted bread and gruyere. Gratinee in oven at 200 C.",ingredienti:[{nome:"Cipolle",qt:"800g"},{nome:"Brodo di carne",qt:"800ml"},{nome:"Burro",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Pane raffermo",qt:"100g"},{nome:"Groviera",qt:"100g"}],_dbEntry:{n:"Zuppa di cipolle gratinata (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:5,g:12,z:10,ch:35,fi:3,ca:250,fe:1,mg:30,k2:280,na:650,zn:1.5,fo:30,se:6,col:40}},{id:"tpl_1045",nome:"Risotto agli asparagi",nome_en:"Asparagus risotto",categoria:"Primo piatto",porzioni:4,note:"Cuocere gli asparagi, tenere le punte e frullare i gambi con poco brodo. Soffriggere scalogno, tostare riso e sfumare con vino bianco. Aggiungere brodo e la crema di asparagi. A meta cottura aggiungere le punte. Mantecare con burro e parmigiano.",note_en:"Cook asparagus, keep tips and blend stalks with a little stock. Sauté shallot, toast rice and deglaze with white wine. Add stock and asparagus cream. Halfway add tips. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Asparagi",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto agli asparagi (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:4,g:9,z:3,ch:59,fi:2.5,ca:90,fe:2,mg:30,k2:300,na:350,zn:1,fo:80,se:5,col:25}},{id:"tpl_1046",nome:"Pasta con zucchine e fiori",nome_en:"Pasta with courgettes and flowers",categoria:"Primo piatto",porzioni:4,note:"Affettare le zucchine e saltare in olio con aglio. Aggiungere i fiori di zucca puliti. Cuocere la pasta al dente. Amalgamare con le zucchine, aggiungere pecorino e menta fresca.",note_en:"Slice courgettes and sauté in oil with garlic. Add cleaned courgette flowers. Cook pasta al dente. Combine with courgettes, add pecorino and fresh mint.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Zucchine",qt:"400g"},{nome:"Fiori di zucca",qt:"8"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pecorino",qt:"50g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con zucchine e fiori (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:13,gs:2,g:9,z:4,ch:56,fi:3,ca:120,fe:2,mg:42,k2:380,na:240,zn:1.2,fo:50,se:8,col:10}},{id:"tpl_1047",nome:"Minestrone alla genovese",nome_en:"Genoese minestrone",categoria:"Primo piatto",porzioni:6,note:"Soffriggere le verdure a cubetti. Aggiungere fagioli, patate e brodo. Cuocere 30 minuti. Aggiungere pasta corta e cuocere al dente. Condire con un cucchiaio di pesto genovese. Servire tiepido.",note_en:"Sauté diced vegetables. Add beans, potatoes and stock. Cook 30 minutes. Add short pasta and cook al dente. Dress with a spoonful of Genoese pesto. Serve warm.",ingredienti:[{nome:"Verdure miste stagionali",qt:"600g"},{nome:"Fagioli borlotti cotti",qt:"250g"},{nome:"Patate",qt:"200g"},{nome:"Pasta corta",qt:"100g"},{nome:"Pesto genovese",qt:"80g"},{nome:"Brodo vegetale",qt:"1.5L"}],_dbEntry:{n:"Minestrone alla genovese (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:1,g:8,z:5,ch:42,fi:8,ca:80,fe:2.5,mg:50,k2:500,na:380,zn:1.2,fo:90,se:5,col:3}},{id:"tpl_1048",nome:"Pasta al forno siciliana",nome_en:"Sicilian baked pasta",categoria:"Primo piatto",porzioni:6,note:"Cuocere pasta al dente. Preparare sugo di carne con macinato e pomodoro. In teglia alternare pasta, sugo, piselli, uova sode affettate e caciocavallo. Chiudere con sugo e formaggio. Cuocere in forno a 180 C per 30 minuti.",note_en:"Cook pasta al dente. Prepare meat sauce with mince and tomato. In baking dish alternate pasta, sauce, peas, sliced hard-boiled eggs and caciocavallo. Top with sauce and cheese. Bake at 180 C for 30 minutes.",ingredienti:[{nome:"Rigatoni",qt:"400g"},{nome:"Macinato di manzo",qt:"300g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Piselli",qt:"100g"},{nome:"Uova sode",qt:"3"},{nome:"Caciocavallo",qt:"150g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Pasta al forno siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:22,gs:5,g:14,z:4,ch:52,fi:3,ca:180,fe:3,mg:38,k2:380,na:480,zn:3,fo:45,se:18,col:140}},{id:"tpl_1049",nome:"Spaghetti alle vongole in bianco",nome_en:"Spaghetti with clams in white sauce",categoria:"Primo piatto",porzioni:4,note:"Far aprire le vongole in padella coperta con aglio e vino bianco. Filtrare il liquido. Soffriggere aglio e prezzemolo. Aggiungere il liquido delle vongole. Cuocere gli spaghetti al dente. Saltare in padella con le vongole e il loro liquido.",note_en:"Open clams in covered pan with garlic and white wine. Filter liquid. Sauté garlic and parsley. Add clam liquid. Cook spaghetti al dente. Toss in pan with clams and their liquid.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Vongole",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Spaghetti alle vongole in bianco (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:18,gs:1.5,g:10,z:2,ch:52,fi:1,ca:80,fe:3.5,mg:45,k2:380,na:380,zn:2,fo:30,se:22,col:35}},{id:"tpl_1050",nome:"Risotto al nero di seppia",nome_en:"Black squid ink risotto",categoria:"Primo piatto",porzioni:4,note:"Pulire le seppie tenendo il sacchetto del nero. Rosolare cipolla e aglio in olio. Aggiungere le seppie a pezzi e sfumare con vino bianco. Tostare il riso nella base. Aggiungere brodo di pesce e il nero di seppia. Mantecare con olio crudo.",note_en:"Clean squid keeping ink sac. Brown onion and garlic in oil. Add squid pieces and deglaze with white wine. Toast rice in base. Add fish stock and squid ink. Stir in raw oil.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Seppie",qt:"400g"},{nome:"Nero di seppia",qt:"2 bustine"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"120ml"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo di pesce",qt:"1L"}],_dbEntry:{n:"Risotto al nero di seppia (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:20,gs:1.5,g:9,z:2,ch:52,fi:.5,ca:50,fe:2.5,mg:50,k2:420,na:380,zn:2,fo:25,se:30,col:80}},{id:"tpl_1051",nome:"Pasta al pistacchio di Bronte",nome_en:"Pasta with Bronte pistachio",categoria:"Primo piatto",porzioni:4,note:"Frullare pistacchi con aglio, olio e poca acqua per creare il pesto. Rosolare la salsiccia sbriciolata. Cuocere i rigatoni al dente. Mantecare con pesto di pistacchio, salsiccia e un mestolo di acqua di cottura.",note_en:"Blend pistachios with garlic, oil and a little water to make pesto. Brown crumbled sausage. Cook rigatoni al dente. Toss with pistachio pesto, sausage and a ladle of cooking water.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pistacchi di Bronte",qt:"100g"},{nome:"Salsiccia",qt:"200g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Pasta al pistacchio di Bronte (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:20,gs:4,g:22,z:3,ch:55,fi:3,ca:80,fe:2.5,mg:55,k2:520,na:480,zn:2,fo:35,se:10,col:40}},{id:"tpl_1052",nome:"Minestra di orzo e verdure",nome_en:"Barley and vegetable soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere le verdure a cubetti. Aggiungere orzo perlato, pomodori e brodo. Cuocere 40 minuti mescolando spesso. Condire con olio extravergine e prezzemolo. Servire caldo con parmigiano a parte.",note_en:"Sauté diced vegetables. Add pearled barley, tomatoes and stock. Cook 40 minutes stirring often. Season with extra virgin olive oil and parsley. Serve hot with parmesan on the side.",ingredienti:[{nome:"Orzo perlato",qt:"250g"},{nome:"Carote",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori",qt:"200g"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Minestra di orzo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:.5,g:5,z:4,ch:50,fi:7,ca:45,fe:2.5,mg:45,k2:420,na:310,zn:1.5,fo:35,se:8,col:0}},{id:"tpl_1053",nome:"Caserecce al pesto di rucola",nome_en:"Caserecce with rocket pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare rucola, pinoli, aglio, parmigiano e olio per il pesto. Cuocere le caserecce al dente. Scolare tenendo acqua di cottura. Mantecare con il pesto di rucola, aggiungendo acqua di cottura per ammorbidire. Guarnire con scaglie di parmigiano.",note_en:"Blend rocket, pine nuts, garlic, parmesan and oil for pesto. Cook caserecce al dente. Drain keeping cooking water. Toss with rocket pesto, adding cooking water to soften. Garnish with parmesan shavings.",ingredienti:[{nome:"Caserecce",qt:"320g"},{nome:"Rucola",qt:"80g"},{nome:"Pinoli",qt:"30g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Caserecce al pesto di rucola (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:3,g:17,z:2,ch:58,fi:2,ca:120,fe:2,mg:38,k2:250,na:200,zn:1.2,fo:50,se:8,col:8}},{id:"tpl_1054",nome:"Riso pilaf con verdure",nome_en:"Vegetable pilaf rice",categoria:"Primo piatto",porzioni:4,note:"Tostare il riso Basmati in burro con cipolla. Aggiungere brodo bollente in quantita doppia rispetto al riso. Chiudere il coperchio e cuocere a fuoco bassissimo 18 minuti senza mai aprire. Sgranare con una forchetta e aggiungere verdure saltate.",note_en:"Toast Basmati rice in butter with onion. Add boiling stock in double the amount of rice. Cover and cook on very low heat 18 minutes without opening. Fluff with fork and add sautéed vegetables.",ingredienti:[{nome:"Riso Basmati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Burro",qt:"30g"},{nome:"Verdure miste",qt:"250g"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Spezie aromatiche",qt:"q.b."}],_dbEntry:{n:"Riso pilaf con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:7,gs:2,g:6,z:4,ch:58,fi:3,ca:45,fe:1.5,mg:35,k2:280,na:280,zn:.8,fo:30,se:5,col:10}},{id:"tpl_1055",nome:"Pasta con peperoni arrostiti",nome_en:"Pasta with roasted peppers",categoria:"Primo piatto",porzioni:4,note:"Arrostire i peperoni in forno o sul gas, pelarli e tagliarli a listarelle. Soffriggere aglio in olio, aggiungere i peperoni, acciughe e capperi. Cuocere la pasta al dente. Saltare tutto insieme con prezzemolo.",note_en:"Roast peppers in oven or on gas, peel and slice. Sauté garlic in oil, add peppers, anchovies and capers. Cook pasta al dente. Toss everything together with parsley.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Peperoni rossi",qt:"4"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con peperoni arrostiti (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:1.5,g:9,z:6,ch:60,fi:3,ca:50,fe:2.5,mg:45,k2:420,na:420,zn:1,fo:55,se:10,col:8}},{id:"tpl_1056",nome:"Zuppa di pane toscana",nome_en:"Tuscan bread soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodori maturi spezzettati. Aggiungere pane toscano raffermo spezzettato e brodo vegetale. Cuocere mescolando finche il pane si ammorbidisce. Aggiustare di sale e pepe. Servire con olio crudo.",note_en:"Sauté garlic in oil, add roughly chopped ripe tomatoes. Add crumbled stale Tuscan bread and vegetable stock. Cook stirring until bread softens. Season with salt and pepper. Serve with raw oil.",ingredienti:[{nome:"Pane toscano raffermo",qt:"300g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Zuppa di pane toscana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:7,gs:1,g:10,z:5,ch:44,fi:4,ca:55,fe:2,mg:30,k2:350,na:440,zn:.8,fo:30,se:5,col:0}},{id:"tpl_1057",nome:"Pasta alla sorrentina",nome_en:"Pasta alla sorrentina",categoria:"Primo piatto",porzioni:4,note:"Preparare sugo di pomodoro fresco con basilico. Cuocere i rigatoni al dente. In teglia alternare pasta, sugo, mozzarella a cubetti e parmigiano. Cuocere in forno a 200 C per 15 minuti finche la mozzarella fila.",note_en:"Make fresh tomato sauce with basil. Cook rigatoni al dente. In baking dish alternate pasta, sauce, diced mozzarella and parmesan. Bake at 200 C for 15 minutes until mozzarella melts and stretches.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Mozzarella",qt:"200g"},{nome:"Parmigiano",qt:"50g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta alla sorrentina (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:5,g:14,z:5,ch:56,fi:2.5,ca:250,fe:1.5,mg:38,k2:350,na:380,zn:2,fo:35,se:12,col:40}},{id:"tpl_1058",nome:"Pasta con la mollica di pane",nome_en:"Pasta with toasted breadcrumbs",categoria:"Primo piatto",porzioni:4,note:"Tostare la mollica di pane in olio con aglio e acciughe fino a doratura. Condire con peperoncino. Cuocere la pasta al dente. Scolare e condire con la mollica tostata, aglio e prezzemolo.",note_en:"Toast breadcrumbs in oil with garlic and anchovies until golden. Season with chilli. Cook pasta al dente. Drain and dress with toasted crumbs, garlic and parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Mollica di pane",qt:"80g"},{nome:"Acciughe",qt:"4"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con la mollica di pane (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:12,gs:1.5,g:12,z:2,ch:60,fi:2,ca:45,fe:2.5,mg:35,k2:230,na:420,zn:.9,fo:25,se:8,col:5}},{id:"tpl_1059",nome:"Risotto zucca e amaretti",nome_en:"Pumpkin and amaretti risotto",categoria:"Primo piatto",porzioni:4,note:"Arrostire la zucca in forno. Soffriggere scalogno in burro, tostare il riso, sfumare con vino bianco. Aggiungere brodo e la polpa di zucca schiacciata. Mantecare con burro e parmigiano. Servire con amaretti sbriciolati.",note_en:"Roast pumpkin in oven. Sauté shallot in butter, toast rice, deglaze with white wine. Add stock and mashed pumpkin flesh. Stir in butter and parmesan. Serve with crumbled amaretti.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Zucca",qt:"400g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"50g"},{nome:"Amaretti",qt:"30g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto zucca e amaretti (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:11,gs:5,g:11,z:8,ch:62,fi:2,ca:100,fe:1.5,mg:30,k2:380,na:350,zn:1,fo:28,se:6,col:30}},{id:"tpl_1060",nome:"Pasta con ragù alla bolognese",nome_en:"Pasta with Bolognese ragu",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, carota, sedano. Aggiungere macinato misto e rosolare. Sfumare con vino rosso. Aggiungere pomodori e latte. Cuocere a fuoco lento almeno 2 ore. Servire con tagliatelle al uovo e parmigiano.",note_en:"Sauté onion, carrot, celery. Add mixed mince and brown. Deglaze with red wine. Add tomatoes and milk. Cook on low heat at least 2 hours. Serve with egg tagliatelle and parmesan.",ingredienti:[{nome:"Tagliatelle all uovo",qt:"320g"},{nome:"Macinato misto",qt:"400g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Vino rosso",qt:"100ml"},{nome:"Latte",qt:"50ml"},{nome:"Parmigiano",qt:"50g"}],_dbEntry:{n:"Pasta con ragu alla bolognese (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:25,gs:5,g:14,z:4,ch:52,fi:2.5,ca:120,fe:3,mg:40,k2:480,na:420,zn:3.5,fo:50,se:18,col:75}},{id:"tpl_1061",nome:"Minestrone di primavera",nome_en:"Spring minestrone",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla e aglio. Aggiungere carote, piselli, asparagi a pezzetti, spinaci e brodo. Cuocere 20 minuti. Aggiungere pasta corta o pastina. Servire con parmigiano e olio extravergine a crudo.",note_en:"Sauté onion and garlic. Add carrots, peas, chopped asparagus, spinach and stock. Cook 20 minutes. Add short pasta or pastina. Serve with parmesan and raw extra virgin olive oil.",ingredienti:[{nome:"Pastina",qt:"120g"},{nome:"Piselli",qt:"150g"},{nome:"Asparagi",qt:"200g"},{nome:"Carote",qt:"2"},{nome:"Spinaci freschi",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Minestrone di primavera (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:10,gs:.5,g:4,z:5,ch:46,fi:7,ca:80,fe:2.5,mg:48,k2:480,na:330,zn:1.2,fo:100,se:5,col:5}},{id:"tpl_1062",nome:"Pasta alla puttanesca",nome_en:"Pasta puttanesca",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere acciughe fino a scioglierle. Aggiungere olive nere, capperi e pomodori. Cuocere 20 minuti. Cuocere gli spaghetti al dente e saltarli nel sugo. Finire con prezzemolo.",note_en:"Sauté garlic in oil, add anchovies until dissolved. Add black olives, capers and tomatoes. Cook 20 minutes. Cook spaghetti al dente and toss in sauce. Finish with parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Acciughe",qt:"6"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta alla puttanesca (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:1.5,g:10,z:4,ch:58,fi:3,ca:55,fe:2.5,mg:40,k2:420,na:850,zn:1,fo:30,se:10,col:8}},{id:"tpl_1063",nome:"Risotto ai gamberi e lime",nome_en:"Prawn and lime risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere gamberi sgusciati e rosolare brevemente, togliere. Tostare il riso, sfumare con vino bianco. Aggiungere brodo di pesce. Mantecare con olio, succo e scorza di lime. Aggiungere i gamberi.",note_en:"Sauté shallot in oil. Add peeled prawns and brown briefly, remove. Toast rice, deglaze with white wine. Add fish stock. Stir in oil, lime juice and zest. Add prawns.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Lime",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Risotto ai gamberi e lime (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:17,gs:1,g:7,z:2,ch:54,fi:.5,ca:70,fe:2,mg:45,k2:380,na:360,zn:1.8,fo:30,se:28,col:115}},{id:"tpl_1064",nome:"Pasta alla checca",nome_en:"Pasta alla checca",categoria:"Primo piatto",porzioni:4,note:"Tagliare pomodori a cubetti, condire con aglio, basilico, olio e sale. Marinare 30 minuti a temperatura ambiente. Cuocere la pasta al dente, scolare e condire immediatamente con il sugo freddo. Aggiungere mozzarella a cubetti.",note_en:"Dice tomatoes, season with garlic, basil, oil and salt. Marinate 30 minutes at room temperature. Cook pasta al dente, drain and immediately dress with cold sauce. Add diced mozzarella.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Mozzarella",qt:"150g"},{nome:"Basilico",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Pasta alla checca (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:3,g:14,z:4,ch:58,fi:2.5,ca:220,fe:1.5,mg:35,k2:380,na:280,zn:1.5,fo:40,se:10,col:25}},{id:"tpl_1065",nome:"Pasta con crema di melanzane",nome_en:"Pasta with aubergine cream",categoria:"Primo piatto",porzioni:4,note:"Grigliare le melanzane, frullarle con aglio, tahini, succo di limone e olio per una crema. Cuocere la pasta al dente. Mantecare con la crema di melanzane, aggiungendo acqua di cottura. Guarnire con pomodorini e menta.",note_en:"Grill aubergines, blend with garlic, tahini, lemon juice and oil for a cream. Cook pasta al dente. Toss with aubergine cream, adding cooking water. Garnish with cherry tomatoes and mint.",ingredienti:[{nome:"Pennette",qt:"320g"},{nome:"Melanzane",qt:"500g"},{nome:"Tahini",qt:"30g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pomodorini",qt:"100g"}],_dbEntry:{n:"Pasta con crema di melanzane (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:12,gs:1.5,g:11,z:5,ch:60,fi:5,ca:55,fe:2.5,mg:48,k2:420,na:220,zn:1.2,fo:50,se:6,col:0}},{id:"tpl_1066",nome:"Soup di pomodoro e basilico",nome_en:"Tomato and basil soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla e aglio in olio. Aggiungere pomodori pelati e brodo vegetale. Cuocere 20 minuti. Frullare fino a crema liscia. Condire con basilico fresco e olio extravergine. Servire con crostini di pane.",note_en:"Brown onion and garlic in oil. Add peeled tomatoes and vegetable stock. Cook 20 minutes. Blend to smooth cream. Season with fresh basil and extra virgin olive oil. Serve with bread croutons.",ingredienti:[{nome:"Pomodori pelati",qt:"800g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane per crostini",qt:"100g"}],_dbEntry:{n:"Soup di pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:1,g:8,z:8,ch:32,fi:3.5,ca:50,fe:2,mg:30,k2:480,na:340,zn:.5,fo:30,se:5,col:0}},{id:"tpl_1067",nome:"Pasta con il baccala",nome_en:"Pasta with salt cod",categoria:"Primo piatto",porzioni:4,note:"Dissalare il baccala 48 ore cambiando l acqua. Soffriggere aglio, cipolla e pomodorini. Aggiungere il baccala a pezzi e cuocere 15 minuti. Cuocere la pasta al dente. Saltare nel sugo con prezzemolo e olive.",note_en:"Desalt cod for 48 hours changing water. Sauté garlic, onion and cherry tomatoes. Add cod pieces and cook 15 minutes. Cook pasta al dente. Toss in sauce with parsley and olives.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Baccala dissalato",qt:"400g"},{nome:"Pomodorini",qt:"250g"},{nome:"Olive nere",qt:"50g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con il baccala (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:22,gs:1.5,g:9,z:3,ch:52,fi:2.5,ca:60,fe:2,mg:50,k2:520,na:680,zn:1.5,fo:30,se:28,col:45}},{id:"tpl_1068",nome:"Risotto alla crema di scampi",nome_en:"Scampi cream risotto",categoria:"Primo piatto",porzioni:4,note:"Sgusciare gli scampi. Preparare un fumetto con i carapaci. Soffriggere scalogno, tostare il riso, sfumare con brandy. Aggiungere il fumetto di scampi. Mantecare con burro e la polpa degli scampi saltata brevemente.",note_en:"Shell langoustines. Make a bisque with the shells. Sauté shallot, toast rice, flambé with brandy. Add langoustine bisque. Stir in butter and briefly sautéed langoustine flesh.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Scampi",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Brandy",qt:"50ml"},{nome:"Burro",qt:"40g"},{nome:"Pomodori",qt:"100g"},{nome:"Erbe aromatiche",qt:"q.b."}],_dbEntry:{n:"Risotto alla crema di scampi (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:3,g:9,z:2,ch:52,fi:.5,ca:80,fe:2,mg:50,k2:420,na:480,zn:2,fo:40,se:30,col:140}},{id:"tpl_1069",nome:"Pasta fredda al pesto e pomodorini",nome_en:"Cold pasta with pesto and cherry tomatoes",categoria:"Primo piatto",porzioni:4,note:"Cuocere la pasta al dente, sciacquare con acqua fredda. Condire con pesto genovese, pomodorini halved, olive e mozzarella. Lasciare riposare in frigorifero 30 minuti prima di servire.",note_en:"Cook pasta al dente, rinse with cold water. Dress with Genoese pesto, halved cherry tomatoes, olives and mozzarella. Rest in refrigerator 30 minutes before serving.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Pesto genovese",qt:"80g"},{nome:"Pomodorini",qt:"200g"},{nome:"Mozzarella",qt:"125g"},{nome:"Olive",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pasta fredda al pesto e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:4,g:16,z:4,ch:56,fi:3,ca:200,fe:2,mg:38,k2:300,na:420,zn:1.5,fo:40,se:8,col:20}},{id:"tpl_1070",nome:"Pasta con crema di piselli e menta",nome_en:"Pasta with pea and mint cream",categoria:"Primo piatto",porzioni:4,note:"Cuocere i piselli in acqua salata. Frullarli con menta, parmigiano e olio fino a crema. Cuocere la pasta al dente. Mantecare con la crema di piselli aggiungendo acqua di cottura. Guarnire con piselli interi e menta fresca.",note_en:"Cook peas in salted water. Blend with mint, parmesan and oil to a cream. Cook pasta al dente. Toss with pea cream adding cooking water. Garnish with whole peas and fresh mint.",ingredienti:[{nome:"Mezze penne",qt:"320g"},{nome:"Piselli freschi",qt:"500g"},{nome:"Menta fresca",qt:"15g"},{nome:"Parmigiano",qt:"50g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con crema di piselli e menta (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:16,gs:2,g:10,z:5,ch:58,fi:7,ca:80,fe:2.5,mg:45,k2:380,na:200,zn:1.2,fo:70,se:5,col:5}},{id:"tpl_1071",nome:"Fusilli con pomodorini e ricotta",nome_en:"Fusilli with cherry tomatoes and ricotta",categoria:"Primo piatto",porzioni:4,note:"Saltare i pomodorini in olio con aglio fino a far scoppiare. Cuocere i fusilli al dente. Scolare e mantecare con i pomodorini, ricotta fresca, basilico e olio. Aggiungere parmigiano se gradito.",note_en:"Sauté cherry tomatoes in oil with garlic until they burst. Cook fusilli al dente. Drain and toss with cherry tomatoes, fresh ricotta, basil and oil. Add parmesan if desired.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Pomodorini",qt:"300g"},{nome:"Ricotta fresca",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Fusilli con pomodorini e ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:15,gs:2.5,g:11,z:4,ch:58,fi:2.5,ca:150,fe:1.5,mg:35,k2:320,na:220,zn:1,fo:35,se:8,col:18}},{id:"tpl_1072",nome:"Pasta al pesto di pistacchi",nome_en:"Pasta with pistachio pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare pistacchi non salati tostati con aglio, basilico, parmigiano e olio per fare il pesto. Cuocere la pasta al dente. Mantecare con il pesto di pistacchi e acqua di cottura.",note_en:"Blend toasted unsalted pistachios with garlic, basil, parmesan and oil to make pesto. Cook pasta al dente. Toss with pistachio pesto and cooking water.",ingredienti:[{nome:"Linguine",qt:"320g"},{nome:"Pistacchi non salati",qt:"100g"},{nome:"Basilico",qt:"20g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Pasta al pesto di pistacchi (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:16,gs:3,g:22,z:3,ch:56,fi:3.5,ca:120,fe:2.5,mg:60,k2:500,na:180,zn:1.5,fo:35,se:5,col:5}},{id:"tpl_1073",nome:"Tagliatelle al tartufo nero",nome_en:"Tagliatelle with black truffle",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in burro e olio. Aggiungere tartufo nero grattugiato o a lamelle. Cuocere le tagliatelle fresche. Mantecare con burro, tartufo e parmigiano. Servire immediatamente.",note_en:"Sauté garlic in butter and oil. Add grated or sliced black truffle. Cook fresh tagliatelle. Toss with butter, truffle and parmesan. Serve immediately.",ingredienti:[{nome:"Tagliatelle fresche",qt:"400g"},{nome:"Tartufo nero",qt:"40g"},{nome:"Burro",qt:"60g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Parmigiano",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Tagliatelle al tartufo nero (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:15,gs:9,g:18,z:2,ch:56,fi:1.5,ca:130,fe:2,mg:25,k2:200,na:350,zn:1.5,fo:25,se:5,col:120}},{id:"tpl_1074",nome:"Zuppa di zucca e zenzero",nome_en:"Pumpkin and ginger soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla in olio. Aggiungere zucca a cubetti, zenzero fresco grattugiato e brodo vegetale. Cuocere 25 minuti. Frullare fino a crema vellutata. Aggiustare di sale. Servire con panna acida e semi di zucca tostati.",note_en:"Brown onion in oil. Add diced pumpkin, fresh grated ginger and vegetable stock. Cook 25 minutes. Blend to velvety cream. Season with salt. Serve with sour cream and toasted pumpkin seeds.",ingredienti:[{nome:"Zucca",qt:"600g"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Panna acida",qt:"50g"},{nome:"Semi di zucca",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zuppa di zucca e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:1.5,g:8,z:8,ch:28,fi:3,ca:55,fe:1.5,mg:30,k2:560,na:320,zn:.8,fo:35,se:5,col:8}},{id:"tpl_1075",nome:"Pasta con cozze e zafferano",nome_en:"Pasta with mussels and saffron",categoria:"Primo piatto",porzioni:4,note:"Far aprire le cozze in padella con aglio e vino bianco. Sgusciare la meta. Soffriggere scalogno, aggiungere zafferano sciolto in brodo. Cuocere gli spaghetti. Saltare con le cozze e il loro liquido filtrato.",note_en:"Open mussels in pan with garlic and white wine. Shell half. Sauté shallot, add saffron dissolved in stock. Cook spaghetti. Toss with mussels and their filtered liquid.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Cozze",qt:"800g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"150ml"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con cozze e zafferano (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:18,gs:1.5,g:9,z:2,ch:52,fi:2,ca:80,fe:4,mg:50,k2:380,na:480,zn:2.5,fo:35,se:30,col:38}},{id:"tpl_1076",nome:"Risotto al caprino e noci",nome_en:"Goat cheese and walnut risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Tostare il riso, sfumare con vino bianco. Aggiungere brodo vegetale. A cottura quasi ultimata aggiungere caprino a pezzi e noci tritate. Mantecare con burro. Servire con miele e noci intere.",note_en:"Sauté shallot in butter. Toast rice, deglaze with white wine. Add vegetable stock. Near end of cooking add crumbled goat cheese and chopped walnuts. Stir in butter. Serve with honey and whole walnuts.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Caprino fresco",qt:"150g"},{nome:"Noci",qt:"60g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Miele",qt:"20g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto al caprino e noci (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:6,g:16,z:4,ch:56,fi:1.5,ca:120,fe:1.5,mg:40,k2:280,na:350,zn:1.5,fo:30,se:6,col:28}},{id:"tpl_1077",nome:"Pasta e lenticchie",nome_en:"Pasta and lentils",categoria:"Primo piatto",porzioni:4,note:"Soffriggere sedano, carota e cipolla. Aggiungere lenticchie rosse o verdi e brodo. Cuocere 20 minuti. Aggiungere pasta corta e cuocere. Il piatto deve rimanere semi-brodoso. Condire con olio crudo, aglio e peperoncino.",note_en:"Sauté celery, carrot and onion. Add red or green lentils and stock. Cook 20 minutes. Add short pasta and cook. Dish should remain semi-soupy. Season with raw oil, garlic and chilli.",ingredienti:[{nome:"Pasta corta",qt:"200g"},{nome:"Lenticchie",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta e lenticchie (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:15,gs:.8,g:6,z:3,ch:52,fi:9,ca:55,fe:4,mg:60,k2:580,na:300,zn:2,fo:145,se:6,col:0}},{id:"tpl_1078",nome:"Pasta con bottarga di muggine",nome_en:"Pasta with grey mullet bottarga",categoria:"Primo piatto",porzioni:4,note:"Cuocere gli spaghetti al dente. Soffriggere aglio in olio. Scolare la pasta e mantecare con olio, aglio e bottarga grattugiata abbondante. Aggiungere poco prezzemolo e scorza di limone. Servire con bottarga a lamelle.",note_en:"Cook spaghetti al dente. Sauté garlic in oil. Drain pasta and toss with oil, garlic and generous grated bottarga. Add a little parsley and lemon zest. Serve with bottarga in slices.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Bottarga di muggine",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Limone",qt:"1"},{nome:"Prezzemolo",qt:"10g"}],_dbEntry:{n:"Pasta con bottarga di muggine (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:2,g:14,z:1,ch:56,fi:1,ca:50,fe:2,mg:38,k2:280,na:680,zn:1.5,fo:20,se:30,col:110}},{id:"tpl_1079",nome:"Vellutata di asparagi",nome_en:"Asparagus velouté",categoria:"Primo piatto",porzioni:4,note:"Lessare gli asparagi in acqua salata, tenere le punte. Frullare i gambi con scalogno soffritto, panna e brodo. Portare a consistenza vellutata. Aggiustare di sale e pepe. Servire con le punte e crostini.",note_en:"Boil asparagus in salted water, keep tips. Blend stalks with sautéed shallot, cream and stock. Bring to velvety consistency. Season with salt and pepper. Serve with tips and croutons.",ingredienti:[{nome:"Asparagi",qt:"600g"},{nome:"Scalogno",qt:"2"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Burro",qt:"30g"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Vellutata di asparagi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:7,gs:4,g:11,z:5,ch:22,fi:3.5,ca:60,fe:2.5,mg:25,k2:380,na:350,zn:.8,fo:90,se:5,col:35}},{id:"tpl_1080",nome:"Pasta ai quattro formaggi",nome_en:"Pasta with four cheeses",categoria:"Primo piatto",porzioni:4,note:"Sciogliere in padella gorgonzola, taleggio, fontina e parmigiano con un pocod di panna. Mescolare fino a crema omogenea. Cuocere la pasta al dente. Mantecare con la crema di formaggi e acqua di cottura.",note_en:"Melt gorgonzola, taleggio, fontina and parmesan in a pan with a little cream. Stir to smooth cream. Cook pasta al dente. Toss with cheese cream and cooking water.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Gorgonzola",qt:"80g"},{nome:"Taleggio",qt:"80g"},{nome:"Fontina",qt:"80g"},{nome:"Parmigiano",qt:"40g"},{nome:"Panna da cucina",qt:"80ml"}],_dbEntry:{n:"Pasta ai quattro formaggi (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:22,gs:11,g:20,z:3,ch:55,fi:1,ca:420,fe:1.5,mg:30,k2:200,na:780,zn:3,fo:20,se:10,col:75}},{id:"tpl_1081",nome:"Pasta con noci e gorgonzola",nome_en:"Pasta with walnuts and gorgonzola",categoria:"Primo piatto",porzioni:4,note:"Sciogliere il gorgonzola in panna. Tostare le noci in padella. Cuocere la pasta al dente. Mantecare con la crema di gorgonzola e le noci. Guarnire con rucola e pepe.",note_en:"Melt gorgonzola in cream. Toast walnuts in pan. Cook pasta al dente. Toss with gorgonzola cream and walnuts. Garnish with rocket and pepper.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Gorgonzola",qt:"150g"},{nome:"Noci",qt:"80g"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Rucola",qt:"30g"}],_dbEntry:{n:"Pasta con noci e gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:18,gs:9,g:22,z:2.5,ch:54,fi:2.5,ca:220,fe:1.5,mg:48,k2:300,na:600,zn:2,fo:28,se:8,col:45}},{id:"tpl_1082",nome:"Zuppa di pesce alla livornese",nome_en:"Livornese fish soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e peperoncino in olio. Aggiungere pomodori, cacciucco o misto di pesce e brodo. Cuocere 20 minuti. Servire su pane tostato strofinato con aglio.",note_en:"Sauté onion, garlic and chilli in oil. Add tomatoes, mixed fish and stock. Cook 20 minutes. Serve on toasted bread rubbed with garlic.",ingredienti:[{nome:"Pesce misto",qt:"600g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo di pesce",qt:"500ml"},{nome:"Pane",qt:"150g"}],_dbEntry:{n:"Zuppa di pesce alla livornese (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:28,gs:2,g:10,z:4,ch:22,fi:2,ca:80,fe:2.5,mg:50,k2:550,na:480,zn:2,fo:35,se:35,col:90}},{id:"tpl_1083",nome:"Pasta con crema di sedano rapa",nome_en:"Pasta with celeriac cream",categoria:"Primo piatto",porzioni:4,note:"Cuocere sedano rapa a cubetti in brodo fino a morbido. Frullare con parmigiano e olio fino a crema. Cuocere la pasta al dente. Mantecare con la crema di sedano rapa. Guarnire con nocciole tostate e prezzemolo.",note_en:"Cook diced celeriac in stock until soft. Blend with parmesan and oil to a cream. Cook pasta al dente. Toss with celeriac cream. Garnish with toasted hazelnuts and parsley.",ingredienti:[{nome:"Penne",qt:"320g"},{nome:"Sedano rapa",qt:"400g"},{nome:"Parmigiano",qt:"50g"},{nome:"Nocciole tostate",qt:"40g"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con crema di sedano rapa (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:14,gs:2,g:13,z:3,ch:58,fi:3,ca:110,fe:2,mg:40,k2:380,na:280,zn:1.5,fo:35,se:6,col:5}},{id:"tpl_1084",nome:"Pasta e ceci speziata",nome_en:"Spiced pasta and chickpeas",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio, cumino, curcuma e peperoncino in olio. Aggiungere ceci e pomodori. Cuocere 15 minuti. Aggiungere pasta corta e brodo. Cuocere al dente. Servire con foglie di coriandolo fresco.",note_en:"Sauté onion, garlic, cumin, turmeric and chilli in oil. Add chickpeas and tomatoes. Cook 15 minutes. Add short pasta and stock. Cook al dente. Serve with fresh coriander leaves.",ingredienti:[{nome:"Pasta corta",qt:"200g"},{nome:"Ceci cotti",qt:"400g"},{nome:"Pomodori",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta e ceci speziata (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:.8,g:6,z:3,ch:54,fi:10,ca:65,fe:4,mg:68,k2:560,na:300,zn:2,fo:130,se:6,col:0}},{id:"tpl_1085",nome:"Spaghetti al cartoccio con frutti di mare",nome_en:"Spaghetti en papillote with seafood",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere misto di frutti di mare, vino bianco e pomodorini. Cuocere 5 minuti. Mescolare con spaghetti a meta cottura. Chiudere in carta forno e cuocere in forno a 200 C per 12 minuti.",note_en:"Sauté garlic in oil, add mixed seafood, white wine and cherry tomatoes. Cook 5 minutes. Mix with halfway-cooked spaghetti. Seal in baking paper and bake at 200 C for 12 minutes.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Frutti di mare misti",qt:"500g"},{nome:"Pomodorini",qt:"200g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Spaghetti al cartoccio con frutti di mare (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:1.5,g:9,z:3,ch:52,fi:2,ca:80,fe:3,mg:48,k2:420,na:480,zn:2,fo:30,se:30,col:80}},{id:"tpl_1086",nome:"Pasta con broccoletti e salsiccia",nome_en:"Pasta with turnip tops and sausage",categoria:"Primo piatto",porzioni:4,note:"Lessare i broccoletti in acqua salata. Soffriggere la salsiccia sbriciolata con aglio e peperoncino. Cuocere le orecchiette nell acqua dei broccoletti. Saltare tutto insieme con olio abbondante.",note_en:"Boil turnip tops in salted water. Brown crumbled sausage with garlic and chilli. Cook orecchiette in the turnip top water. Toss everything together with plenty of oil.",ingredienti:[{nome:"Orecchiette",qt:"320g"},{nome:"Cime di rapa",qt:"400g"},{nome:"Salsiccia",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con broccoletti e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:20,gs:5,g:16,z:3,ch:56,fi:5,ca:120,fe:3,mg:55,k2:500,na:480,zn:2.5,fo:80,se:15,col:45}},{id:"tpl_1087",nome:"Minestrone estivo con basilico",nome_en:"Summer minestrone with basil",categoria:"Primo piatto",porzioni:4,note:"Cuocere zucchine, pomodori, melanzane, fagiolini e cipolla in brodo vegetale. Aggiungere pasta corta. Cuocere al dente. Condire con pesto di basilico fresco. Servire tiepido o freddo.",note_en:"Cook courgettes, tomatoes, aubergines, green beans and onion in vegetable stock. Add short pasta. Cook al dente. Dress with fresh basil pesto. Serve warm or cold.",ingredienti:[{nome:"Ditalini",qt:"150g"},{nome:"Zucchine",qt:"200g"},{nome:"Pomodori",qt:"200g"},{nome:"Melanzane",qt:"150g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pesto fresco",qt:"60g"},{nome:"Brodo vegetale",qt:"1.2L"}],_dbEntry:{n:"Minestrone estivo con basilico (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:9,gs:.8,g:7,z:5,ch:43,fi:6,ca:60,fe:2,mg:42,k2:450,na:310,zn:1,fo:55,se:5,col:2}},{id:"tpl_1088",nome:"Risotto con spinaci e fontina",nome_en:"Risotto with spinach and fontina",categoria:"Primo piatto",porzioni:4,note:"Lessare gli spinaci, strizzarli e frullarne meta. Soffriggere scalogno in burro, tostare il riso, sfumare con vino. Aggiungere brodo e la crema di spinaci. Mantecare con burro e fontina. Aggiungere gli spinaci interi rimasti.",note_en:"Boil spinach, squeeze out water and blend half. Sauté shallot in butter, toast rice, deglaze with wine. Add stock and spinach cream. Stir in butter and fontina. Add remaining whole spinach.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Spinaci freschi",qt:"400g"},{nome:"Fontina",qt:"100g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto con spinaci e fontina (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:6,g:12,z:3,ch:55,fi:3,ca:220,fe:2.5,mg:45,k2:350,na:480,zn:1.8,fo:120,se:8,col:40}},{id:"tpl_1089",nome:"Pasta con l aglio e olio",nome_en:"Pasta with garlic and oil",categoria:"Primo piatto",porzioni:4,note:"Affettare aglio finissimo e dorarlo in abbondante olio a fuoco dolcissimo. Aggiungere peperoncino. Cuocere gli spaghetti al dente, tenere acqua di cottura. Mantecare aglio olio e peperoncino con la pasta aggiungendo acqua. Finire con prezzemolo abbondante.",note_en:"Slice garlic very thin and brown in plenty of oil on very low heat. Add chilli. Cook spaghetti al dente, keep cooking water. Toss garlic oil and chilli with pasta adding water. Finish with plenty of parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"80ml"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Pasta con l aglio e olio (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:11,gs:1.5,g:16,z:1,ch:60,fi:1.5,ca:30,fe:2,mg:35,k2:220,na:120,zn:.8,fo:20,se:6,col:0}},{id:"tpl_1090",nome:"Trofie al pesto con fagiolini e patate",nome_en:"Trofie pesto with green beans and potatoes",categoria:"Primo piatto",porzioni:4,note:"Lessare le patate a cubetti e i fagiolini nella stessa acqua salata. Cuocere le trofie con le patate. Scolare tutto. Condire con pesto genovese, parmigiano e pecorino. Amalgamare bene.",note_en:"Boil diced potatoes and green beans in the same salted water. Cook trofie with potatoes. Drain everything. Dress with Genoese pesto, parmesan and pecorino. Mix well.",ingredienti:[{nome:"Trofie",qt:"320g"},{nome:"Patate",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pesto genovese",qt:"100g"},{nome:"Parmigiano",qt:"30g"},{nome:"Pecorino",qt:"20g"}],_dbEntry:{n:"Trofie al pesto con fagiolini e patate (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:3,g:16,z:3,ch:62,fi:5,ca:130,fe:2,mg:48,k2:420,na:350,zn:1.2,fo:50,se:6,col:6}},{id:"tpl_1091",nome:"Pasta con sugo di pomodoro e basilico",nome_en:"Pasta with tomato and basil sauce",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodori pelati e schiacciare. Cuocere 20 minuti. Aggiungere basilico fresco. Cuocere i rigatoni al dente. Condire con il sugo e parmigiano.",note_en:"Sauté garlic in oil, add peeled tomatoes and crush. Cook 20 minutes. Add fresh basil. Cook rigatoni al dente. Dress with sauce and parmesan.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Pasta con sugo di pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:13,gs:1,g:8,z:5,ch:60,fi:2.5,ca:90,fe:2,mg:35,k2:380,na:250,zn:1,fo:30,se:7,col:5}},{id:"tpl_1092",nome:"Vellutata di carote e zenzero",nome_en:"Carrot and ginger velouté",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla in olio. Aggiungere carote a pezzi e zenzero grattugiato. Versare brodo vegetale e cuocere 25 minuti. Frullare con latte di cocco. Aggiustare di sale e servire con semi di sesamo tostati.",note_en:"Brown onion in oil. Add carrot pieces and grated ginger. Pour in vegetable stock and cook 25 minutes. Blend with coconut milk. Season with salt and serve with toasted sesame seeds.",ingredienti:[{nome:"Carote",qt:"600g"},{nome:"Cipolla",qt:"1"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Latte di cocco",qt:"100ml"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Semi di sesamo",qt:"20g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Vellutata di carote e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:3,g:7,z:10,ch:26,fi:5,ca:55,fe:1.5,mg:30,k2:580,na:320,zn:.5,fo:30,se:4,col:0}},{id:"tpl_1093",nome:"Pasta con sugo di peperoni e pomodoro",nome_en:"Pasta with pepper and tomato sauce",categoria:"Primo piatto",porzioni:4,note:"Grigliare i peperoni e spellarli. Soffriggere cipolla, aggiungere peperoni e pomodori. Cuocere 20 minuti. Frullare meta del sugo per renderlo cremoso. Cuocere la pasta al dente e condire.",note_en:"Grill peppers and peel. Sauté onion, add peppers and tomatoes. Cook 20 minutes. Blend half the sauce to make it creamy. Cook pasta al dente and dress.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Peperoni rossi",qt:"3"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Pasta con sugo di peperoni e pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:11,gs:1,g:8,z:7,ch:60,fi:4,ca:45,fe:2,mg:42,k2:450,na:240,zn:.9,fo:50,se:6,col:0}},{id:"tpl_1094",nome:"Risotto con gamberetti e limone",nome_en:"Risotto with shrimps and lemon",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere i gamberetti sgusciati, sfumare con vino bianco. Togliere i gamberetti. Tostare il riso nella base, aggiungere brodo di pesce. Mantecare con olio, succo di limone e scorza. Rimettere i gamberetti.",note_en:"Sauté shallot in oil. Add peeled shrimps, deglaze with white wine. Remove shrimps. Toast rice in base, add fish stock. Stir in oil, lemon juice and zest. Return shrimps.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberetti",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Limone",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"}],_dbEntry:{n:"Risotto con gamberetti e limone (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:16,gs:1,g:7,z:2,ch:54,fi:.5,ca:70,fe:1.8,mg:42,k2:360,na:360,zn:1.5,fo:28,se:25,col:105}},{id:"tpl_1095",nome:"Pasta con agnello e rosmarino",nome_en:"Pasta with lamb and rosemary",categoria:"Primo piatto",porzioni:4,note:"Rosolare pezzi di agnello con rosmarino, aglio e cipolla. Sfumare con vino rosso. Aggiungere pomodori e cuocere 45 minuti. Cuocere la pasta al dente. Condire con il sugo di agnello e pecorino.",note_en:"Brown lamb pieces with rosemary, garlic and onion. Deglaze with red wine. Add tomatoes and cook 45 minutes. Cook pasta al dente. Dress with lamb sauce and pecorino.",ingredienti:[{nome:"Mezze maniche",qt:"320g"},{nome:"Agnello",qt:"300g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"100ml"},{nome:"Pecorino",qt:"40g"}],_dbEntry:{n:"Pasta con agnello e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:24,gs:5,g:14,z:4,ch:54,fi:2.5,ca:100,fe:3,mg:42,k2:450,na:400,zn:4,fo:35,se:18,col:70}},{id:"tpl_1096",nome:"Zuppa di verza e patate",nome_en:"Savoy cabbage and potato soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere pancetta con cipolla. Aggiungere verza a strisce, patate a cubetti e brodo. Cuocere 30 minuti. Aggiungere pastina o orzo. Servire con parmigiano e olio crudo.",note_en:"Brown pancetta with onion. Add shredded savoy cabbage, diced potatoes and stock. Cook 30 minutes. Add pastina or barley. Serve with parmesan and raw oil.",ingredienti:[{nome:"Pastina",qt:"120g"},{nome:"Verza",qt:"400g"},{nome:"Patate",qt:"300g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Zuppa di verza e patate (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:12,gs:2,g:7,z:4,ch:44,fi:5,ca:100,fe:1.5,mg:38,k2:580,na:420,zn:1,fo:55,se:5,col:18}},{id:"tpl_1097",nome:"Pasta con sugo alla pescatora",nome_en:"Pasta with fisherman sauce",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodorini, vino bianco e misto di cozze, vongole, gamberi e calamari. Coprire e cuocere 10 minuti. Cuocere gli spaghetti al dente. Saltare nel sugo con prezzemolo abbondante.",note_en:"Sauté garlic in oil, add cherry tomatoes, white wine and mixed mussels, clams, prawns and squid. Cover and cook 10 minutes. Cook spaghetti al dente. Toss in sauce with plenty of parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Cozze",qt:"300g"},{nome:"Vongole",qt:"300g"},{nome:"Gamberi",qt:"200g"},{nome:"Calamari",qt:"150g"},{nome:"Pomodorini",qt:"200g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con sugo alla pescatora (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:25,gs:1.5,g:9,z:3,ch:52,fi:2,ca:100,fe:4,mg:55,k2:480,na:500,zn:3,fo:40,se:35,col:95}},{id:"tpl_1098",nome:"Riso integrale con verdure e curcuma",nome_en:"Brown rice with vegetables and turmeric",categoria:"Primo piatto",porzioni:4,note:"Cuocere il riso integrale 35 minuti in acqua salata. Saltare le verdure con curcuma, zenzero e olio. Mescolare riso e verdure. Aggiustare di sale. Servire con salsa di yogurt e coriandolo.",note_en:"Cook brown rice 35 minutes in salted water. Sauté vegetables with turmeric, ginger and oil. Mix rice and vegetables. Season with salt. Serve with yoghurt sauce and coriander.",ingredienti:[{nome:"Riso integrale",qt:"300g"},{nome:"Verdure miste",qt:"350g"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Yogurt naturale",qt:"100g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Coriandolo fresco",qt:"10g"}],_dbEntry:{n:"Riso integrale con verdure e curcuma (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:.8,g:6,z:5,ch:56,fi:5,ca:55,fe:2,mg:55,k2:380,na:280,zn:1.2,fo:40,se:8,col:2}},{id:"tpl_1099",nome:"Pasta con sugo di carciofi e pancetta",nome_en:"Pasta with artichoke and pancetta sauce",categoria:"Primo piatto",porzioni:4,note:"Mondare i carciofi e tagliarli. Soffriggere pancetta, aglio e carciofi in olio. Sfumare con vino bianco. Cuocere 15 minuti. Cuocere la pasta al dente. Condire con il sugo, parmigiano e prezzemolo.",note_en:"Trim artichokes and slice. Sauté pancetta, garlic and artichokes in oil. Deglaze with white wine. Cook 15 minutes. Cook pasta al dente. Dress with sauce, parmesan and parsley.",ingredienti:[{nome:"Penne rigate",qt:"320g"},{nome:"Carciofi",qt:"4"},{nome:"Pancetta",qt:"80g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"80ml"},{nome:"Parmigiano",qt:"40g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con sugo di carciofi e pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:17,gs:3,g:11,z:3,ch:58,fi:5,ca:80,fe:2.5,mg:45,k2:380,na:480,zn:1.5,fo:65,se:8,col:20}},{id:"tpl_1100",nome:"Minestra di farro e fagioli",nome_en:"Farro and bean soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio, rosmarino e salvia. Aggiungere fagioli borlotti, farro perlato e brodo. Cuocere 40 minuti. Schiacciare una parte dei fagioli per addensare. Aggiustare di sale. Servire con olio extravergine e pane.",note_en:"Sauté garlic, rosemary and sage. Add borlotti beans, pearled farro and stock. Cook 40 minutes. Mash some beans to thicken. Season with salt. Serve with extra virgin oil and bread.",ingredienti:[{nome:"Farro perlato",qt:"200g"},{nome:"Fagioli borlotti cotti",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Salvia",qt:"4 foglie"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Minestra di farro e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:.5,g:5,z:3,ch:52,fi:10,ca:65,fe:3.5,mg:55,k2:550,na:310,zn:1.5,fo:115,se:6,col:0}},{id:"tpl_1101",nome:"Pasta con crema di ceci e rosmarino",nome_en:"Pasta with chickpea and rosemary cream",categoria:"Primo piatto",porzioni:4,note:"Frullare ceci cotti con brodo, rosmarino, aglio e olio fino a crema liscia. Cuocere la pasta al dente. Mantecare con la crema di ceci aggiungendo acqua di cottura. Guarnire con ceci interi soffritti e rosmarino croccante.",note_en:"Blend cooked chickpeas with stock, rosemary, garlic and oil to smooth cream. Cook pasta al dente. Toss with chickpea cream adding cooking water. Garnish with fried whole chickpeas and crispy rosemary.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Ceci cotti",qt:"400g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Brodo vegetale",qt:"300ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con crema di ceci e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:15,gs:1,g:9,z:2,ch:60,fi:9,ca:70,fe:4,mg:60,k2:560,na:240,zn:2,fo:140,se:5,col:0}},{id:"tpl_1102",nome:"Pasta alla sorrentina veloce",nome_en:"Quick pasta alla sorrentina",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodorini e cuocere 10 minuti. Cuocere la pasta al dente. Scolare e saltare con il sugo. Aggiungere mozzarella a cubetti e basilico. Il calore sciogliera la mozzarella.",note_en:"Sauté garlic in oil, add cherry tomatoes and cook 10 minutes. Cook pasta al dente. Drain and toss with sauce. Add diced mozzarella and basil. The heat will melt the mozzarella.",ingredienti:[{nome:"Paccheri",qt:"320g"},{nome:"Pomodorini",qt:"300g"},{nome:"Mozzarella",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Pasta alla sorrentina veloce (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:4,g:13,z:4,ch:58,fi:2.5,ca:240,fe:1.5,mg:38,k2:340,na:360,zn:2,fo:35,se:10,col:30}},{id:"tpl_1103",nome:"Pasta con le fave",nome_en:"Pasta with fava beans",categoria:"Primo piatto",porzioni:4,note:"Sgranare e spellare le fave. Soffriggere cipollotto, aglio e guanciale. Aggiungere le fave e un poco di brodo. Cuocere la pasta al dente. Condire con il sughetto di fave, pecorino e menta.",note_en:"Shell and skin fava beans. Sauté spring onion, garlic and guanciale. Add fava beans and a little stock. Cook pasta al dente. Dress with fava bean sauce, pecorino and mint.",ingredienti:[{nome:"Maccheroni",qt:"320g"},{nome:"Fave fresche sgranate",qt:"400g"},{nome:"Guanciale",qt:"80g"},{nome:"Cipollotto",qt:"2"},{nome:"Pecorino",qt:"50g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta con le fave (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:18,gs:3,g:10,z:3,ch:58,fi:8,ca:80,fe:3,mg:55,k2:560,na:420,zn:1.5,fo:160,se:8,col:22}},{id:"tpl_1104",nome:"Risotto con brie e noci",nome_en:"Risotto with brie and walnuts",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Tostare il riso, sfumare con vino bianco. Aggiungere brodo vegetale. A cottura quasi ultimata aggiungere brie a pezzi senza crosta. Mantecare con burro. Servire con gherigli di noce.",note_en:"Sauté shallot in butter. Toast rice, deglaze with white wine. Add vegetable stock. Near end of cooking add rindless brie pieces. Stir in butter. Serve with walnut halves.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Brie",qt:"150g"},{nome:"Noci",qt:"50g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto con brie e noci (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:8,g:18,z:2,ch:54,fi:1.5,ca:160,fe:1.5,mg:30,k2:230,na:450,zn:1.5,fo:25,se:6,col:50}},{id:"tpl_1105",nome:"Pasta con gamberi e pomodorini",nome_en:"Pasta with prawns and cherry tomatoes",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere gamberi sgusciati. Sfumare con vino bianco. Aggiungere pomodorini tagliati a meta e cuocere 10 minuti. Cuocere la pasta al dente e saltare nel sugo. Aggiungere prezzemolo.",note_en:"Sauté garlic in oil, add peeled prawns. Deglaze with white wine. Add halved cherry tomatoes and cook 10 minutes. Cook pasta al dente and toss in sauce. Add parsley.",ingredienti:[{nome:"Linguine",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Pomodorini",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"100ml"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con gamberi e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:1.5,g:8,z:3,ch:55,fi:2,ca:60,fe:2.5,mg:45,k2:420,na:340,zn:1.8,fo:35,se:25,col:110}},{id:"tpl_1106",nome:"Zuppa di fagioli e castagne",nome_en:"Bean and chestnut soup",categoria:"Primo piatto",porzioni:4,note:"Lessare le castagne. Cuocere i fagioli cannellini con rosmarino e aglio. Unire fagioli, castagne e brodo. Frullare meta. Cuocere 15 minuti. Servire con olio crudo e rametto di rosmarino.",note_en:"Boil chestnuts. Cook cannellini beans with rosemary and garlic. Combine beans, chestnuts and stock. Blend half. Cook 15 minutes. Serve with raw oil and rosemary sprig.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"350g"},{nome:"Castagne cotte",qt:"200g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Zuppa di fagioli e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:10,gs:.5,g:5,z:4,ch:50,fi:9,ca:60,fe:3,mg:55,k2:580,na:280,zn:1.5,fo:85,se:4,col:0}},{id:"tpl_1107",nome:"Pasta con le polpette di carne",nome_en:"Pasta with meat meatballs",categoria:"Primo piatto",porzioni:4,note:"Preparare polpette di macinato misto con uova, parmigiano e prezzemolo. Rosolare le polpette in olio. Preparare sugo di pomodoro. Cuocere le polpette nel sugo 20 minuti. Cuocere gli spaghetti al dente. Servire con polpette e sugo.",note_en:"Prepare mixed mince meatballs with eggs, parmesan and parsley. Brown meatballs in oil. Make tomato sauce. Cook meatballs in sauce 20 minutes. Cook spaghetti al dente. Serve with meatballs and sauce.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Macinato misto",qt:"400g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"50g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con le polpette di carne (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:26,gs:4,g:14,z:5,ch:55,fi:2.5,ca:110,fe:3,mg:42,k2:500,na:400,zn:4,fo:40,se:20,col:100}},{id:"tpl_1108",nome:"Pasta fredda con verdure grigliate",nome_en:"Cold pasta with grilled vegetables",categoria:"Primo piatto",porzioni:4,note:"Grigliare zucchine, melanzane e peperoni. Tagliare a pezzi e marinare con olio, aglio e basilico. Cuocere la pasta al dente, sciacquare in acqua fredda. Mescolare con le verdure grigliate e olive.",note_en:"Grill courgettes, aubergines and peppers. Cut into pieces and marinate with oil, garlic and basil. Cook pasta al dente, rinse in cold water. Mix with grilled vegetables and olives.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Zucchine",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Olive",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Pasta fredda con verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:11,gs:1.5,g:12,z:5,ch:60,fi:5,ca:55,fe:2,mg:45,k2:420,na:300,zn:1,fo:55,se:6,col:0}},{id:"tpl_1109",nome:"Risotto al pomodoro e basilico",nome_en:"Tomato and basil risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla in olio. Tostare il riso, sfumare con vino bianco. Aggiungere brodo caldo e passata di pomodoro. Cuocere 18 minuti. Mantecare con burro, parmigiano e basilico fresco.",note_en:"Sauté onion in oil. Toast rice, deglaze with white wine. Add hot stock and tomato passata. Cook 18 minutes. Stir in butter, parmesan and fresh basil.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico",qt:"15g"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"700ml"}],_dbEntry:{n:"Risotto al pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:4,g:9,z:5,ch:62,fi:2.5,ca:90,fe:1.5,mg:30,k2:380,na:320,zn:1,fo:28,se:7,col:25}},{id:"tpl_1110",nome:"Pasta con sugo di cinghiale",nome_en:"Pasta with wild boar sauce",categoria:"Primo piatto",porzioni:4,note:"Marinare il cinghiale con vino rosso e aromi. Rosolare con soffritto. Sfumare con la marinatura filtrata. Aggiungere pomodoro e cuocere 2 ore. Cuocere i pici o le pappardelle. Condire con il ragu.",note_en:"Marinate wild boar with red wine and aromatics. Brown with soffritto. Deglaze with strained marinade. Add tomato and cook 2 hours. Cook pici or pappardelle. Dress with ragu.",ingredienti:[{nome:"Pappardelle",qt:"320g"},{nome:"Cinghiale",qt:"500g"},{nome:"Vino rosso",qt:"300ml"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Rosmarino",qt:"q.b."}],_dbEntry:{n:"Pasta con sugo di cinghiale (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:28,gs:4,g:12,z:4,ch:52,fi:2.5,ca:60,fe:3.5,mg:38,k2:500,na:380,zn:4.5,fo:40,se:18,col:75}},{id:"tpl_1111",nome:"Pasta con pesto di rucola e noci",nome_en:"Pasta with rocket and walnut pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare rucola, noci, parmigiano, aglio e olio per creare il pesto. Cuocere le farfalle al dente. Mantecare con il pesto e acqua di cottura. Guarnire con pomodorini e scaglie di parmigiano.",note_en:"Blend rocket, walnuts, parmesan, garlic and oil to make pesto. Cook farfalle al dente. Toss with pesto and cooking water. Garnish with cherry tomatoes and parmesan shavings.",ingredienti:[{nome:"Farfalle",qt:"320g"},{nome:"Rucola",qt:"100g"},{nome:"Noci",qt:"50g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"70ml"},{nome:"Pomodorini",qt:"100g"}],_dbEntry:{n:"Pasta con pesto di rucola e noci (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:15,gs:3,g:19,z:3,ch:57,fi:2.5,ca:120,fe:2.5,mg:50,k2:340,na:220,zn:1.5,fo:50,se:8,col:5}},{id:"tpl_1112",nome:"Vellutata di funghi e timo",nome_en:"Mushroom and thyme velouté",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Aggiungere funghi misti tagliati e timo. Versare brodo e panna. Cuocere 20 minuti. Frullare fino a velluto. Aggiustare di sale. Servire con funghi trifolati e crostini.",note_en:"Sauté shallot in butter. Add sliced mixed mushrooms and thyme. Pour in stock and cream. Cook 20 minutes. Blend to velvet. Season with salt. Serve with trifolati mushrooms and croutons.",ingredienti:[{nome:"Funghi misti",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Timo",qt:"4 rametti"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Burro",qt:"30g"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Vellutata di funghi e timo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:5,g:12,z:3,ch:22,fi:3.5,ca:40,fe:2,mg:25,k2:450,na:350,zn:1,fo:30,se:8,col:40}},{id:"tpl_1113",nome:"Pasta con ricotta e limone",nome_en:"Pasta with ricotta and lemon",categoria:"Primo piatto",porzioni:4,note:"Amalgamare ricotta con scorza e succo di limone, parmigiano, sale e pepe. Cuocere i fusilli al dente. Scolare tenendo acqua di cottura. Mantecare con la crema di ricotta aggiungendo acqua per ammorbidire. Guarnire con foglie di basilico.",note_en:"Mix ricotta with lemon zest and juice, parmesan, salt and pepper. Cook fusilli al dente. Drain keeping cooking water. Toss with ricotta cream adding water to soften. Garnish with basil leaves.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Ricotta",qt:"200g"},{nome:"Limone",qt:"2"},{nome:"Parmigiano",qt:"40g"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Pasta con ricotta e limone (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:3,g:9,z:4,ch:60,fi:2,ca:160,fe:1.5,mg:30,k2:250,na:180,zn:1.2,fo:35,se:8,col:25}},{id:"tpl_1114",nome:"Zuppa di coda di bue",nome_en:"Oxtail soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare la coda a pezzi con verdure. Sfumare con vino rosso. Aggiungere brodo e cuocere 3 ore a fuoco lento. Disossare la coda e rimettere la carne nel brodo. Aggiustare di sale e servire con pasta corta.",note_en:"Brown oxtail pieces with vegetables. Deglaze with red wine. Add stock and cook 3 hours on low heat. Debone oxtail and return meat to broth. Season with salt and serve with short pasta.",ingredienti:[{nome:"Coda di bue",qt:"800g"},{nome:"Pasta corta",qt:"120g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Vino rosso",qt:"200ml"},{nome:"Brodo di carne",qt:"1L"}],_dbEntry:{n:"Zuppa di coda di bue (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:24,gs:4,g:11,z:3,ch:28,fi:2,ca:55,fe:3,mg:30,k2:420,na:420,zn:5,fo:20,se:15,col:90}},{id:"tpl_1115",nome:"Pasta e fagioli con le cotiche",nome_en:"Pasta and beans with pork rind",categoria:"Primo piatto",porzioni:4,note:"Sbollentare le cotiche e tagliarle a listarelle. Soffriggere cipolla, aglio e lardo. Aggiungere cotiche, fagioli borlotti e pomodori. Versare brodo e cuocere 1 ora. Aggiungere pasta mista e finire.",note_en:"Blanch pork rind and cut into strips. Sauté onion, garlic and lard. Add pork rind, borlotti beans and tomatoes. Pour in stock and cook 1 hour. Add mixed pasta and finish.",ingredienti:[{nome:"Pasta mista",qt:"200g"},{nome:"Fagioli borlotti",qt:"300g"},{nome:"Cotiche di maiale",qt:"150g"},{nome:"Lardo",qt:"50g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo",qt:"800ml"}],_dbEntry:{n:"Pasta e fagioli con le cotiche (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:4,g:12,z:3,ch:50,fi:8,ca:70,fe:3.5,mg:55,k2:580,na:500,zn:2.5,fo:105,se:8,col:35}},{id:"tpl_1116",nome:"Pasta al forno con carne e bechamel",nome_en:"Baked pasta with meat and bechamel",categoria:"Primo piatto",porzioni:6,note:"Preparare ragu di carne. Preparare besciamella. Cuocere la pasta al dente. In una teglia alternare strati di pasta, ragu e besciamella. Aggiungere parmigiano. Cuocere in forno a 180 C per 35 minuti.",note_en:"Make meat ragu. Make bechamel. Cook pasta al dente. In a baking dish alternate layers of pasta, ragu and bechamel. Add parmesan. Bake at 180 C for 35 minutes.",ingredienti:[{nome:"Maccheroni",qt:"400g"},{nome:"Macinato di manzo",qt:"400g"},{nome:"Latte",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"80g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Pasta al forno con carne e bechamel (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:22,gs:5,g:14,z:4,ch:50,fi:2.5,ca:200,fe:2.5,mg:35,k2:450,na:480,zn:3,fo:35,se:18,col:80}},{id:"tpl_1117",nome:"Pasta con sugo di verdure arrostite",nome_en:"Pasta with roasted vegetable sauce",categoria:"Primo piatto",porzioni:4,note:"Arrostire melanzane, zucchine e peperoni in forno con olio. Frullare meta per fare la base del sugo. Soffriggere aglio, aggiungere il sugo e le verdure a pezzi. Cuocere la pasta e saltare nel sugo.",note_en:"Roast aubergines, courgettes and peppers in oven with oil. Blend half for sauce base. Sauté garlic, add sauce and vegetable pieces. Cook pasta and toss in sauce.",ingredienti:[{nome:"Pasta corta",qt:"320g"},{nome:"Melanzane",qt:"200g"},{nome:"Zucchine",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Pasta con sugo di verdure arrostite (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:1.5,g:10,z:6,ch:60,fi:5.5,ca:50,fe:2,mg:45,k2:480,na:200,zn:1,fo:55,se:7,col:0}},{id:"tpl_1118",nome:"Pasta alla crema di parmigiano",nome_en:"Pasta with parmesan cream",categoria:"Primo piatto",porzioni:4,note:"Sciogliere parmigiano grattugiato con acqua calda di cottura della pasta e olio extravergine fino a crema. Cuocere la pasta al dente. Mantecare con la crema di parmigiano fuori dal fuoco. Aggiungere pepe nero abbondante.",note_en:"Dissolve grated parmesan with hot pasta cooking water and extra virgin oil until creamy. Cook pasta al dente. Toss off heat with parmesan cream. Add plenty of black pepper.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Parmigiano grattugiato",qt:"120g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla crema di parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:5,g:13,z:2,ch:58,fi:1,ca:350,fe:1.5,mg:30,k2:180,na:420,zn:2.5,fo:15,se:8,col:28}},{id:"tpl_1119",nome:"Minestrone invernale con legumi",nome_en:"Winter minestrone with legumes",categoria:"Primo piatto",porzioni:6,note:"Soffriggere sedano, cipolla e carota. Aggiungere cavolo, broccoli, fagioli, lenticchie e brodo. Cuocere 35 minuti. Aggiungere pasta corta. Servire con parmigiano e olio crudo.",note_en:"Sauté celery, onion and carrot. Add cabbage, broccoli, beans, lentils and stock. Cook 35 minutes. Add short pasta. Serve with parmesan and raw oil.",ingredienti:[{nome:"Pasta corta",qt:"160g"},{nome:"Fagioli misti cotti",qt:"300g"},{nome:"Lenticchie cotte",qt:"150g"},{nome:"Cavolo",qt:"200g"},{nome:"Broccoli",qt:"200g"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.5L"}],_dbEntry:{n:"Minestrone invernale con legumi (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:13,gs:.5,g:5,z:4,ch:46,fi:11,ca:80,fe:3.5,mg:60,k2:600,na:340,zn:1.8,fo:130,se:5,col:0}},{id:"tpl_1120",nome:"Pasta con sugo alle noci e panna",nome_en:"Pasta with walnut and cream sauce",categoria:"Primo piatto",porzioni:4,note:"Tostare le noci in padella. Frullarle con aglio, parmigiano e panna per fare la salsa. Cuocere i rigatoni al dente. Mantecare con la salsa di noci aggiungendo acqua di cottura. Guarnire con noci intere.",note_en:"Toast walnuts in pan. Blend with garlic, parmesan and cream to make sauce. Cook rigatoni al dente. Toss with walnut sauce adding cooking water. Garnish with whole walnuts.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Noci",qt:"100g"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pasta con sugo alle noci e panna (ricetta)",c:"Ricette",src:"RICETTE",k:470,p:16,gs:5,g:21,z:3,ch:55,fi:2.5,ca:130,fe:1.5,mg:45,k2:280,na:250,zn:1.5,fo:25,se:7,col:28}},{id:"tpl_1121",nome:"Pollo alla cacciatora",nome_en:"Hunter-style chicken",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di pollo in olio. Aggiungere cipolla, aglio, pomodori pelati, olive, capperi e vino rosso. Cuocere coperto a fuoco medio 45 minuti. Aggiustare di sale e guarnire con prezzemolo.",note_en:"Brown chicken pieces in oil. Add onion, garlic, peeled tomatoes, olives, capers and red wine. Cover and cook over medium heat 45 minutes. Season with salt and garnish with parsley.",ingredienti:[{nome:"Pollo a pezzi",qt:"1.2kg"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"120ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pollo alla cacciatora (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:32,gs:3,g:14,z:4,ch:6,fi:2,ca:40,fe:1.8,mg:38,k2:520,na:420,zn:2.5,fo:22,se:24,col:110}},{id:"tpl_1122",nome:"Ossobuco alla milanese",nome_en:"Milanese ossobuco",categoria:"Secondo piatto",porzioni:4,note:"Infarinare gli ossibuchi. Rosolare in burro e olio. Sfumare con vino bianco. Aggiungere brodo e cuocere 1.5 ore. Preparare gremolada con prezzemolo, aglio e scorza di limone. Servire con risotto alla milanese.",note_en:"Flour the ossobuco. Brown in butter and oil. Deglaze with white wine. Add stock and cook 1.5 hours. Prepare gremolata with parsley, garlic and lemon zest. Serve with Milanese risotto.",ingredienti:[{nome:"Ossobuco di vitello",qt:"4 pezzi"},{nome:"Farina",qt:"40g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Burro",qt:"40g"},{nome:"Brodo di carne",qt:"400ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Ossobuco alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:38,gs:6,g:16,z:2,ch:10,fi:.5,ca:55,fe:2.5,mg:40,k2:580,na:380,zn:5,fo:18,se:28,col:140}},{id:"tpl_1123",nome:"Scaloppine al limone",nome_en:"Lemon veal escalopes",categoria:"Secondo piatto",porzioni:4,note:"Battere e infarinare le scaloppine. Rosolare in burro e olio fino a doratura. Sfumare con succo di limone e poco brodo. Cuocere 2 minuti. Guarnire con fette di limone e prezzemolo.",note_en:"Flatten and flour the escalopes. Brown in butter and oil until golden. Deglaze with lemon juice and a little stock. Cook 2 minutes. Garnish with lemon slices and parsley.",ingredienti:[{nome:"Fesa di vitello",qt:"600g"},{nome:"Farina",qt:"40g"},{nome:"Limone",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Prezzemolo",qt:"15g"},{nome:"Brodo",qt:"80ml"}],_dbEntry:{n:"Scaloppine al limone (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:5,g:13,z:1,ch:8,fi:.2,ca:30,fe:1.5,mg:30,k2:420,na:280,zn:3.5,fo:15,se:22,col:120}},{id:"tpl_1124",nome:"Bistecca alla fiorentina",nome_en:"Florentine T-bone steak",categoria:"Secondo piatto",porzioni:2,note:"Portare la bistecca a temperatura ambiente. Grigliare su brace ardente 3-4 minuti per lato. Salare solo a fine cottura. Servire con olio extravergine, rosmarino e limone. La carne deve restare rosa al centro.",note_en:"Bring steak to room temperature. Grill on hot coals 3-4 minutes per side. Salt only at end of cooking. Serve with extra virgin oil, rosemary and lemon. Meat should remain pink in centre.",ingredienti:[{nome:"Bistecca Fiorentina",qt:"1kg"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sale grosso",qt:"q.b."},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Bistecca alla fiorentina (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:52,gs:8,g:24,z:0,ch:0,fi:0,ca:20,fe:3.5,mg:45,k2:700,na:200,zn:8,fo:12,se:38,col:145}},{id:"tpl_1125",nome:"Polpette di carne al sugo",nome_en:"Meatballs in tomato sauce",categoria:"Secondo piatto",porzioni:4,note:"Mescolare carne macinata, pane bagnato, uova, parmigiano, aglio e prezzemolo. Formare le polpette. Rosolare in olio. Cuocere nel sugo di pomodoro 30 minuti a fuoco lento.",note_en:"Mix minced meat, soaked bread, eggs, parmesan, garlic and parsley. Shape into meatballs. Brown in oil. Cook in tomato sauce 30 minutes on low heat.",ingredienti:[{nome:"Macinato misto",qt:"500g"},{nome:"Pane raffermo",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"50g"},{nome:"Passata di pomodoro",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Polpette di carne al sugo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:28,gs:5,g:18,z:5,ch:22,fi:2,ca:120,fe:3,mg:40,k2:580,na:520,zn:4,fo:35,se:20,col:130}},{id:"tpl_1126",nome:"Involtini di manzo con prosciutto e salvia",nome_en:"Beef rolls with ham and sage",categoria:"Secondo piatto",porzioni:4,note:"Battere le fettine di manzo. Disporre su ciascuna una fetta di prosciutto crudo e foglie di salvia. Arrotolare e fissare con stecchini. Rosolare in burro e olio. Sfumare con vino bianco. Cuocere 15 minuti.",note_en:"Flatten beef slices. Place on each a slice of raw ham and sage leaves. Roll up and secure with toothpicks. Brown in butter and oil. Deglaze with white wine. Cook 15 minutes.",ingredienti:[{nome:"Fettine di manzo",qt:"600g"},{nome:"Prosciutto crudo",qt:"120g"},{nome:"Salvia",qt:"16 foglie"},{nome:"Burro",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Involtini di manzo con prosciutto e salvia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:36,gs:5,g:16,z:1,ch:2,fi:0,ca:25,fe:2.5,mg:30,k2:480,na:650,zn:5,fo:10,se:25,col:110}},{id:"tpl_1127",nome:"Vitello tonnato",nome_en:"Veal with tuna sauce",categoria:"Secondo piatto",porzioni:6,note:"Cuocere il girello di vitello in brodo con verdure aromatiche 1.5 ore. Lasciare raffreddare nel brodo. Frullare tonno sott olio, capperi, acciughe, succo di limone e maionese. Affettare la carne sottilmente e nappare con la salsa tonnata.",note_en:"Cook veal topside in stock with aromatic vegetables 1.5 hours. Let cool in stock. Blend canned tuna, capers, anchovies, lemon juice and mayonnaise. Slice meat thinly and coat with tuna sauce.",ingredienti:[{nome:"Girello di vitello",qt:"800g"},{nome:"Tonno sott olio",qt:"160g"},{nome:"Capperi",qt:"40g"},{nome:"Acciughe",qt:"4"},{nome:"Maionese",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"}],_dbEntry:{n:"Vitello tonnato (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:34,gs:4,g:16,z:1,ch:3,fi:.3,ca:35,fe:2,mg:35,k2:450,na:580,zn:3.5,fo:15,se:32,col:120}},{id:"tpl_1128",nome:"Arrosto di maiale alle erbe",nome_en:"Herb-roasted pork loin",categoria:"Secondo piatto",porzioni:6,note:"Massaggiare la lonza con aglio tritato, rosmarino, salvia, sale e pepe. Legare e lasciare marinare 2 ore. Rosolare in olio da tutti i lati. Cuocere in forno a 180 C per 60 minuti. Lasciare riposare 10 minuti prima di affettare.",note_en:"Rub pork loin with minced garlic, rosemary, sage, salt and pepper. Tie and marinate 2 hours. Brown in oil on all sides. Bake at 180 C for 60 minutes. Rest 10 minutes before slicing.",ingredienti:[{nome:"Lonza di maiale",qt:"1kg"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Salvia",qt:"10 foglie"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Arrosto di maiale alle erbe (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:34,gs:4,g:14,z:0,ch:1,fi:.2,ca:20,fe:1.2,mg:32,k2:520,na:320,zn:3,fo:8,se:30,col:95}},{id:"tpl_1129",nome:"Agnello al forno con patate",nome_en:"Oven-roasted lamb with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Marinare i pezzi di agnello con aglio, rosmarino, olio e vino bianco per 2 ore. Disporre in teglia con patate a spicchi. Cuocere in forno a 190 C per 60-70 minuti rigirando a meta cottura.",note_en:"Marinate lamb pieces with garlic, rosemary, oil and white wine for 2 hours. Arrange in baking dish with wedge-cut potatoes. Bake at 190 C for 60-70 minutes turning halfway through.",ingredienti:[{nome:"Coscio di agnello a pezzi",qt:"1kg"},{nome:"Patate",qt:"600g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Vino bianco",qt:"150ml"}],_dbEntry:{n:"Agnello al forno con patate (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:35,gs:5,g:18,z:2,ch:28,fi:2.5,ca:35,fe:2.5,mg:45,k2:680,na:280,zn:5,fo:20,se:18,col:100}},{id:"tpl_1130",nome:"Spezzatino di manzo con piselli",nome_en:"Beef stew with peas",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il manzo a bocconcini e infarinare. Rosolare in olio con cipolla. Sfumare con vino rosso. Aggiungere pomodori e brodo. Cuocere 1.5 ore. Aggiungere i piselli negli ultimi 15 minuti.",note_en:"Cut beef into pieces and flour. Brown in oil with onion. Deglaze with red wine. Add tomatoes and stock. Cook 1.5 hours. Add peas in last 15 minutes.",ingredienti:[{nome:"Manzo per spezzatino",qt:"700g"},{nome:"Piselli",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"150ml"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Farina",qt:"30g"},{nome:"Brodo",qt:"300ml"}],_dbEntry:{n:"Spezzatino di manzo con piselli (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:35,gs:3,g:12,z:4,ch:18,fi:4,ca:45,fe:4,mg:50,k2:700,na:380,zn:5,fo:55,se:22,col:95}},{id:"tpl_1131",nome:"Coniglio alla ligure",nome_en:"Ligurian-style rabbit",categoria:"Secondo piatto",porzioni:4,note:"Rosolare il coniglio a pezzi in olio. Aggiungere aglio, olive taggiasche, pinoli, capperi e timo. Sfumare con vino bianco. Aggiungere poco brodo e cuocere coperto 50 minuti.",note_en:"Brown rabbit pieces in oil. Add garlic, Taggiasca olives, pine nuts, capers and thyme. Deglaze with white wine. Add a little stock and cook covered 50 minutes.",ingredienti:[{nome:"Coniglio",qt:"1.2kg"},{nome:"Olive taggiasche",qt:"100g"},{nome:"Pinoli",qt:"30g"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Timo",qt:"4 rametti"}],_dbEntry:{n:"Coniglio alla ligure (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:34,gs:3,g:15,z:1,ch:3,fi:1.5,ca:35,fe:2.2,mg:38,k2:550,na:480,zn:3.5,fo:18,se:20,col:95}},{id:"tpl_1132",nome:"Petto di pollo con limone e capperi",nome_en:"Chicken breast with lemon and capers",categoria:"Secondo piatto",porzioni:4,note:"Battere i petti di pollo. Infarinare leggermente. Cuocere in padella con olio 4 minuti per lato. Aggiungere capperi, succo di limone e prezzemolo. Cuocere 3 minuti ancora e servire.",note_en:"Flatten chicken breasts. Flour lightly. Cook in pan with oil 4 minutes per side. Add capers, lemon juice and parsley. Cook 3 more minutes and serve.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Limone",qt:"2"},{nome:"Capperi",qt:"40g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Farina",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Petto di pollo con limone e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:34,gs:1.5,g:7,z:1,ch:6,fi:.5,ca:25,fe:1.5,mg:35,k2:480,na:350,zn:2,fo:18,se:26,col:85}},{id:"tpl_1133",nome:"Saltimbocca alla romana",nome_en:"Saltimbocca alla romana",categoria:"Secondo piatto",porzioni:4,note:"Sovrapporre una fetta di prosciutto e una foglia di salvia su ogni fettina di vitello. Fissare con uno stecchino. Cuocere in burro dalla parte del prosciutto prima, poi girare. Sfumare con vino bianco e servire con il fondo di cottura.",note_en:"Place a slice of ham and a sage leaf on each veal fillet. Secure with a toothpick. Cook in butter ham-side first, then turn. Deglaze with white wine and serve with cooking juices.",ingredienti:[{nome:"Fesa di vitello",qt:"500g"},{nome:"Prosciutto crudo",qt:"100g"},{nome:"Salvia",qt:"12 foglie"},{nome:"Burro",qt:"50g"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Saltimbocca alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:32,gs:7,g:16,z:0,ch:1,fi:0,ca:20,fe:1.5,mg:28,k2:420,na:680,zn:3,fo:8,se:22,col:125}},{id:"tpl_1134",nome:"Braciole di maiale in umido",nome_en:"Braised pork chops",categoria:"Secondo piatto",porzioni:4,note:"Rosolare le braciole in olio con aglio. Aggiungere pomodori, vino bianco e rosmarino. Cuocere coperto a fuoco lento 40 minuti. Le braciole devono risultare tenere e il sugo ridotto.",note_en:"Brown pork chops in oil with garlic. Add tomatoes, white wine and rosemary. Cook covered on low heat 40 minutes. Chops should be tender and sauce reduced.",ingredienti:[{nome:"Braciole di maiale",qt:"4"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"120ml"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Braciole di maiale in umido (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:30,gs:4,g:16,z:4,ch:8,fi:1.5,ca:30,fe:1.8,mg:35,k2:580,na:320,zn:3.5,fo:15,se:25,col:95}},{id:"tpl_1135",nome:"Pollo al forno con verdure mediterranee",nome_en:"Oven chicken with Mediterranean vegetables",categoria:"Secondo piatto",porzioni:4,note:"Disporre i pezzi di pollo in teglia con zucchine, peperoni, pomodori, olive e aglio. Condire con olio, origano e vino bianco. Cuocere in forno a 200 C per 50-60 minuti.",note_en:"Arrange chicken pieces in baking dish with courgettes, peppers, tomatoes, olives and garlic. Season with oil, oregano and white wine. Bake at 200 C for 50-60 minutes.",ingredienti:[{nome:"Pollo a pezzi",qt:"1.2kg"},{nome:"Zucchine",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Pomodori",qt:"300g"},{nome:"Olive nere",qt:"60g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pollo al forno con verdure mediterranee (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:32,gs:3,g:14,z:5,ch:10,fi:3,ca:45,fe:2,mg:45,k2:620,na:320,zn:2.5,fo:28,se:22,col:100}},{id:"tpl_1136",nome:"Polpettone al forno",nome_en:"Baked meatloaf",categoria:"Secondo piatto",porzioni:6,note:"Mescolare macinato, uova, parmigiano, pane ammollato, aglio e prezzemolo. Formare un polpettone. Avvolgere con pancetta a fette. Cuocere in forno a 180 C per 50 minuti. Affettare e servire con sugo di cottura.",note_en:"Mix mince, eggs, parmesan, soaked bread, garlic and parsley. Shape into a loaf. Wrap with bacon slices. Bake at 180 C for 50 minutes. Slice and serve with cooking juices.",ingredienti:[{nome:"Macinato di manzo",qt:"600g"},{nome:"Pancetta a fette",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"60g"},{nome:"Pane raffermo",qt:"80g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"}],_dbEntry:{n:"Polpettone al forno (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:30,gs:6,g:20,z:2,ch:12,fi:.5,ca:100,fe:3,mg:35,k2:480,na:580,zn:4.5,fo:20,se:25,col:140}},{id:"tpl_1137",nome:"Fegato alla veneziana",nome_en:"Venetian liver with onions",categoria:"Secondo piatto",porzioni:4,note:"Affettare finemente le cipolle e stufarle in burro e olio a fuoco lento 20 minuti fino a caramellare. Aggiungere il fegato a fettine sottili. Cuocere a fuoco vivo 3 minuti per lato. Sfumare con poco aceto. Salare e guarnire con prezzemolo.",note_en:"Slice onions finely and stew in butter and oil on low heat 20 minutes until caramelised. Add thinly sliced liver. Cook on high heat 3 minutes per side. Deglaze with a little vinegar. Season and garnish with parsley.",ingredienti:[{nome:"Fegato di vitello",qt:"500g"},{nome:"Cipolle",qt:"500g"},{nome:"Burro",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto di vino bianco",qt:"20ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Fegato alla veneziana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:28,gs:5,g:12,z:6,ch:8,fi:1,ca:15,fe:12,mg:22,k2:450,na:280,zn:5,fo:320,se:40,col:380}},{id:"tpl_1138",nome:"Cotoletta alla milanese",nome_en:"Milanese breaded veal cutlet",categoria:"Secondo piatto",porzioni:4,note:"Battere le costolette di vitello. Passarle in uovo sbattuto e poi in pangrattato premendo bene. Friggere in abbondante burro chiarificato a 160 C fino a doratura da entrambi i lati. Scolare e salare. Servire con spicchi di limone.",note_en:"Flatten veal cutlets. Dip in beaten egg then press into breadcrumbs. Fry in plenty of clarified butter at 160 C until golden on both sides. Drain and salt. Serve with lemon wedges.",ingredienti:[{nome:"Costolette di vitello con osso",qt:"4"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Burro chiarificato",qt:"150g"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Cotoletta alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:35,gs:18,g:34,z:1,ch:18,fi:.5,ca:50,fe:2,mg:30,k2:380,na:380,zn:4,fo:12,se:22,col:220}},{id:"tpl_1139",nome:"Salsicce e fagioli all'uccelletto",nome_en:"Sausages with cannellini beans",categoria:"Secondo piatto",porzioni:4,note:"Bucherellare le salsicce e cuocerle in padella senza olio 10 minuti. Aggiungere aglio e salvia. Unire i fagioli cannellini con poco sugo di pomodoro. Cuocere insieme 15 minuti a fuoco lento.",note_en:"Pierce sausages and cook in pan without oil 10 minutes. Add garlic and sage. Add cannellini beans with a little tomato sauce. Cook together 15 minutes on low heat.",ingredienti:[{nome:"Salsicce di maiale",qt:"500g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Passata di pomodoro",qt:"150g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Salvia",qt:"6 foglie"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Salsicce e fagioli all uccelletto (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:26,gs:8,g:22,z:3,ch:22,fi:7,ca:70,fe:3.5,mg:60,k2:700,na:780,zn:3.5,fo:90,se:18,col:70}},{id:"tpl_1140",nome:"Petto di pollo al gorgonzola",nome_en:"Chicken breast with gorgonzola",categoria:"Secondo piatto",porzioni:4,note:"Cuocere i petti di pollo in padella con olio 5 minuti per lato. Togliere la carne e nella stessa padella sciogliere il gorgonzola con la panna. Rimettere il pollo nella salsa e cuocere 3 minuti. Guarnire con noci e erba cipollina.",note_en:"Cook chicken breasts in pan with oil 5 minutes per side. Remove meat and melt gorgonzola with cream in same pan. Return chicken to sauce and cook 3 minutes. Garnish with walnuts and chives.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Gorgonzola dolce",qt:"120g"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Noci",qt:"40g"},{nome:"Erba cipollina",qt:"15g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Petto di pollo al gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:38,gs:9,g:20,z:1,ch:2,fi:.5,ca:130,fe:1.5,mg:42,k2:520,na:480,zn:2.5,fo:15,se:28,col:120}},{id:"tpl_1141",nome:"Stracotto di manzo",nome_en:"Slow-braised beef",categoria:"Secondo piatto",porzioni:6,note:"Rosolare il pezzo di manzo intero con cipolla, carota e sedano. Sfumare con vino rosso. Aggiungere brodo e pomodori. Cuocere 3 ore a fuoco bassissimo coperto. La carne deve sfaldarsi. Servire con il fondo ristretto.",note_en:"Brown whole beef piece with onion, carrot and celery. Deglaze with red wine. Add stock and tomatoes. Cook 3 hours on very low heat covered. Meat should fall apart. Serve with reduced cooking juices.",ingredienti:[{nome:"Cappello del prete",qt:"1kg"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Vino rosso",qt:"300ml"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Brodo di carne",qt:"400ml"}],_dbEntry:{n:"Stracotto di manzo (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:38,gs:4,g:13,z:4,ch:8,fi:2,ca:30,fe:3.5,mg:42,k2:620,na:350,zn:6,fo:18,se:28,col:100}},{id:"tpl_1142",nome:"Tacchino in umido alle olive",nome_en:"Turkey stew with olives",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di tacchino in olio. Aggiungere cipolla, aglio, olive verdi, capperi, pomodori e vino bianco. Cuocere coperto 45 minuti. Aggiustare di sale e servire con polenta o patate lesse.",note_en:"Brown turkey pieces in oil. Add onion, garlic, green olives, capers, tomatoes and white wine. Cook covered 45 minutes. Season with salt and serve with polenta or boiled potatoes.",ingredienti:[{nome:"Petto di tacchino a pezzi",qt:"800g"},{nome:"Olive verdi",qt:"100g"},{nome:"Capperi",qt:"30g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Tacchino in umido alle olive (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:36,gs:2,g:10,z:4,ch:6,fi:2,ca:40,fe:2,mg:42,k2:580,na:520,zn:2.5,fo:20,se:30,col:85}},{id:"tpl_1143",nome:"Anatra all'arancia",nome_en:"Duck with orange",categoria:"Secondo piatto",porzioni:4,note:"Rosolare l'anatra a pezzi in padella. Trasferire in forno a 180 C per 40 minuti. Preparare salsa con succo e scorza di arancia, brodo e miele. Versare sulla carne e cuocere altri 20 minuti glassando.",note_en:"Brown duck pieces in pan. Transfer to oven at 180 C for 40 minutes. Make sauce with orange juice and zest, stock and honey. Pour over meat and cook 20 more minutes glazing.",ingredienti:[{nome:"Anatra a pezzi",qt:"1.2kg"},{nome:"Arance",qt:"3"},{nome:"Miele",qt:"30ml"},{nome:"Brodo di pollo",qt:"200ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Anatra all arancia (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:35,gs:7,g:22,z:8,ch:10,fi:.5,ca:30,fe:3,mg:35,k2:520,na:280,zn:4,fo:12,se:22,col:135}},{id:"tpl_1144",nome:"Pollo al marsala",nome_en:"Chicken with Marsala wine",categoria:"Secondo piatto",porzioni:4,note:"Infarinare i petti di pollo. Rosolare in burro e olio fino a doratura. Sfumare con vino Marsala e cuocere a fuoco vivace 5 minuti. Aggiungere funghi champignon a fette. Cuocere altri 10 minuti. Regolare di sale.",note_en:"Flour chicken breasts. Brown in butter and oil until golden. Deglaze with Marsala wine and cook on high heat 5 minutes. Add sliced champignon mushrooms. Cook another 10 minutes. Season with salt.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Funghi champignon",qt:"300g"},{nome:"Marsala",qt:"150ml"},{nome:"Burro",qt:"30g"},{nome:"Farina",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pollo al marsala (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:35,gs:4,g:12,z:3,ch:12,fi:1,ca:20,fe:2,mg:35,k2:520,na:280,zn:2.5,fo:18,se:28,col:95}},{id:"tpl_1145",nome:"Brasato al Barolo",nome_en:"Beef braised in Barolo wine",categoria:"Secondo piatto",porzioni:6,note:"Marinare il manzo nel Barolo con verdure aromatiche per 12 ore. Rosolare bene in olio. Aggiungere la marinatura filtrata. Cuocere a fuoco lentissimo 3 ore. Ristringere il fondo e servire con polenta.",note_en:"Marinate beef in Barolo with aromatic vegetables for 12 hours. Brown well in oil. Add strained marinade. Cook on very low heat 3 hours. Reduce cooking liquid and serve with polenta.",ingredienti:[{nome:"Cappello del prete",qt:"1kg"},{nome:"Vino Barolo",qt:"750ml"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Alloro",qt:"2 foglie"},{nome:"Chiodi di garofano",qt:"3"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Brasato al Barolo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:40,gs:4,g:14,z:5,ch:8,fi:2,ca:35,fe:4,mg:45,k2:680,na:320,zn:6.5,fo:20,se:30,col:110}},{id:"tpl_1146",nome:"Maialino al forno con patate e rosmarino",nome_en:"Roast suckling pig with potatoes and rosemary",categoria:"Secondo piatto",porzioni:6,note:"Massaggiare il maialino con aglio, rosmarino, sale, pepe e olio. Disporre con patate in teglia. Cuocere in forno a 200 C per 90 minuti. La cotenna deve risultare croccante. Bagnare con vino bianco a meta cottura.",note_en:"Rub suckling pig with garlic, rosemary, salt, pepper and oil. Arrange with potatoes in baking dish. Bake at 200 C for 90 minutes. Skin should be crispy. Baste with white wine halfway through.",ingredienti:[{nome:"Maialino da latte a pezzi",qt:"1.5kg"},{nome:"Patate",qt:"800g"},{nome:"Rosmarino",qt:"4 rametti"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Vino bianco",qt:"200ml"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Maialino al forno con patate e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:38,gs:8,g:24,z:2,ch:22,fi:2,ca:30,fe:2,mg:40,k2:720,na:380,zn:4.5,fo:12,se:28,col:120}},{id:"tpl_1147",nome:"Costine di maiale al forno con miele e soia",nome_en:"Pork ribs glazed with honey and soy",categoria:"Secondo piatto",porzioni:4,note:"Marinare le costine con soia, miele, aglio, zenzero e olio per 4 ore. Cuocere in forno a 180 C per 60 minuti coperte con carta stagnola. Scoprire e cuocere altri 20 minuti per glassare.",note_en:"Marinate ribs with soy, honey, garlic, ginger and oil for 4 hours. Bake at 180 C for 60 minutes covered with foil. Uncover and cook 20 more minutes to glaze.",ingredienti:[{nome:"Costine di maiale",qt:"1.2kg"},{nome:"Salsa di soia",qt:"60ml"},{nome:"Miele",qt:"50ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Olio di sesamo",qt:"20ml"}],_dbEntry:{n:"Costine di maiale al forno con miele e soia (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:32,gs:7,g:22,z:12,ch:14,fi:.2,ca:35,fe:1.8,mg:30,k2:480,na:820,zn:4,fo:8,se:22,col:95}},{id:"tpl_1148",nome:"Straccetti di manzo con rucola",nome_en:"Beef strips with rocket",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il manzo a straccetti sottili. Cuocere in padella caldissima con olio 2 minuti. Sfumare con limone. Disporre su letto di rucola fresca. Condire con parmigiano a scaglie, olio crudo e pepe.",note_en:"Cut beef into thin strips. Cook in very hot pan with oil 2 minutes. Deglaze with lemon. Arrange on fresh rocket. Dress with parmesan shavings, raw oil and pepper.",ingredienti:[{nome:"Manzo taglio magro",qt:"500g"},{nome:"Rucola",qt:"120g"},{nome:"Parmigiano a scaglie",qt:"50g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Straccetti di manzo con rucola (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:4,g:14,z:1,ch:2,fi:.5,ca:100,fe:3,mg:30,k2:480,na:260,zn:5,fo:35,se:22,col:85}},{id:"tpl_1149",nome:"Bocconcini di pollo al sesamo e miele",nome_en:"Chicken bites with sesame and honey",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il pollo a bocconcini. Marinare con soia, miele, aglio e zenzero 30 minuti. Passare nei semi di sesamo. Cuocere in padella con olio di sesamo 8-10 minuti. Servire con insalata di cetrioli.",note_en:"Cut chicken into bite-sized pieces. Marinate with soy, honey, garlic and ginger 30 minutes. Coat in sesame seeds. Cook in sesame oil pan 8-10 minutes. Serve with cucumber salad.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Semi di sesamo",qt:"60g"},{nome:"Salsa di soia",qt:"40ml"},{nome:"Miele",qt:"30ml"},{nome:"Zenzero",qt:"15g"},{nome:"Olio di sesamo",qt:"20ml"}],_dbEntry:{n:"Bocconcini di pollo al sesamo e miele (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:36,gs:2.5,g:12,z:8,ch:10,fi:1,ca:70,fe:2.5,mg:50,k2:500,na:620,zn:2.5,fo:20,se:30,col:85}},{id:"tpl_1150",nome:"Petto di tacchino panato al forno",nome_en:"Breaded turkey breast baked",categoria:"Secondo piatto",porzioni:4,note:"Battere le fettine di tacchino. Passare in uovo sbattuto con aglio e prezzemolo, poi in pangrattato. Disporre in teglia con olio e cuocere in forno a 200 C per 20 minuti rigirando a meta. Risulta croccante e leggero.",note_en:"Flatten turkey slices. Dip in beaten egg with garlic and parsley, then breadcrumbs. Place in oiled baking dish and bake at 200 C for 20 minutes turning halfway. Light and crispy result.",ingredienti:[{nome:"Petto di tacchino",qt:"600g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"80g"},{nome:"Parmigiano",qt:"40g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Petto di tacchino panato al forno (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:36,gs:2.5,g:9,z:1,ch:14,fi:.5,ca:80,fe:2,mg:35,k2:480,na:360,zn:2.5,fo:15,se:28,col:110}},{id:"tpl_1151",nome:"Branzino al forno alle erbe aromatiche",nome_en:"Herb-baked sea bass",categoria:"Secondo piatto",porzioni:4,note:"Incidere il branzino sui fianchi. Farcire la pancia con aglio, prezzemolo, limone e timo. Condire esternamente con olio, sale e pepe. Cuocere in forno a 200 C per 25-30 minuti. Servire con spicchi di limone.",note_en:"Score sea bass on sides. Fill belly with garlic, parsley, lemon and thyme. Season outside with oil, salt and pepper. Bake at 200 C for 25-30 minutes. Serve with lemon wedges.",ingredienti:[{nome:"Branzino intero",qt:"1kg"},{nome:"Limone",qt:"2"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Timo",qt:"4 rametti"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Branzino al forno alle erbe aromatiche (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:32,gs:1.5,g:10,z:1,ch:2,fi:.3,ca:45,fe:1.5,mg:40,k2:580,na:280,zn:1.5,fo:20,se:35,col:85}},{id:"tpl_1152",nome:"Baccalà alla livornese",nome_en:"Livorno-style salt cod",categoria:"Secondo piatto",porzioni:4,note:"Dissalare il baccalà 48 ore cambiando l'acqua. Infarinare e friggere in olio. Preparare sugo di pomodoro con aglio, olive nere e capperi. Cuocere il baccalà nel sugo 15 minuti a fuoco lento.",note_en:"Desalt cod 48 hours changing water. Flour and fry in oil. Make tomato sauce with garlic, black olives and capers. Cook cod in sauce 15 minutes on low heat.",ingredienti:[{nome:"Baccalà ammollato",qt:"700g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Farina",qt:"50g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Baccalà alla livornese (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:30,gs:2,g:12,z:4,ch:10,fi:2,ca:50,fe:1.5,mg:45,k2:620,na:620,zn:1.5,fo:18,se:42,col:75}},{id:"tpl_1153",nome:"Salmone in crosta di erbe",nome_en:"Herb-crusted salmon",categoria:"Secondo piatto",porzioni:4,note:"Mescolare pangrattato, prezzemolo, aneto, scorza di limone, aglio e olio. Pressare il composto sul filetto di salmone. Cuocere in forno a 200 C per 15-18 minuti. La crosta deve risultare dorata e croccante.",note_en:"Mix breadcrumbs, parsley, dill, lemon zest, garlic and oil. Press mixture onto salmon fillet. Bake at 200 C for 15-18 minutes. Crust should be golden and crispy.",ingredienti:[{nome:"Filetto di salmone",qt:"700g"},{nome:"Pangrattato",qt:"60g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aneto",qt:"15g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Salmone in crosta di erbe (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:34,gs:4,g:17,z:1,ch:6,fi:.5,ca:30,fe:1.2,mg:42,k2:620,na:220,zn:1,fo:25,se:48,col:95}},{id:"tpl_1154",nome:"Merluzzo al pomodoro e olive",nome_en:"Cod with tomato and olives",categoria:"Secondo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in olio. Aggiungere pomodori pelati e olive. Cuocere 10 minuti. Adagiare i filetti di merluzzo nel sugo. Cuocere coperto 12 minuti. Guarnire con prezzemolo e capperi.",note_en:"Sauté garlic and chilli in oil. Add peeled tomatoes and olives. Cook 10 minutes. Place cod fillets in sauce. Cook covered 12 minutes. Garnish with parsley and capers.",ingredienti:[{nome:"Filetti di merluzzo",qt:"700g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Merluzzo al pomodoro e olive (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:28,gs:1.5,g:9,z:4,ch:8,fi:2,ca:55,fe:1.5,mg:45,k2:680,na:480,zn:1.5,fo:22,se:38,col:65}},{id:"tpl_1155",nome:"Orata alla siciliana",nome_en:"Sicilian-style sea bream",categoria:"Secondo piatto",porzioni:4,note:"Farcire l'orata con aglio, limone e origano. Coprire con pomodorini, olive, capperi e patate. Condire con olio e vino bianco. Cuocere in forno a 200 C per 35 minuti.",note_en:"Fill sea bream with garlic, lemon and oregano. Cover with cherry tomatoes, olives, capers and potatoes. Dress with oil and white wine. Bake at 200 C for 35 minutes.",ingredienti:[{nome:"Orata intera",qt:"1kg"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Patate",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Orata alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:30,gs:2,g:10,z:4,ch:18,fi:2.5,ca:50,fe:2,mg:45,k2:720,na:380,zn:1.5,fo:28,se:32,col:80}},{id:"tpl_1156",nome:"Calamari ripieni al forno",nome_en:"Stuffed baked squid",categoria:"Secondo piatto",porzioni:4,note:"Pulire i calamari tenendo i mantelli interi. Preparare il ripieno con tentacoli tritati, pangrattato, prezzemolo, aglio, pinoli e uvetta. Farcire i mantelli e chiudere con stecchino. Cuocere in forno con pomodori e olio a 180 C per 25 minuti.",note_en:"Clean squid keeping mantles whole. Prepare stuffing with minced tentacles, breadcrumbs, parsley, garlic, pine nuts and raisins. Fill mantles and close with toothpick. Bake with tomatoes and oil at 180 C for 25 minutes.",ingredienti:[{nome:"Calamari medi",qt:"800g"},{nome:"Pangrattato",qt:"60g"},{nome:"Pinoli",qt:"25g"},{nome:"Uvetta",qt:"25g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pomodorini",qt:"200g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Calamari ripieni al forno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:26,gs:1.5,g:9,z:5,ch:16,fi:1.5,ca:50,fe:2.5,mg:50,k2:550,na:320,zn:2,fo:22,se:38,col:240}},{id:"tpl_1157",nome:"Gamberoni all'aglio e prezzemolo",nome_en:"King prawns with garlic and parsley",categoria:"Secondo piatto",porzioni:4,note:"Pulire i gamberoni lasciando la testa. Rosolare aglio in olio. Aggiungere i gamberoni e cuocere 3 minuti per lato. Sfumare con vino bianco. Aggiungere prezzemolo e peperoncino. Servire subito con pane tostato.",note_en:"Clean king prawns leaving heads on. Sauté garlic in oil. Add prawns and cook 3 minutes per side. Deglaze with white wine. Add parsley and chilli. Serve immediately with toasted bread.",ingredienti:[{nome:"Gamberoni",qt:"800g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"30g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Gamberoni all aglio e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:28,gs:1.5,g:10,z:1,ch:3,fi:.3,ca:80,fe:2,mg:45,k2:500,na:380,zn:2.5,fo:18,se:42,col:170}},{id:"tpl_1158",nome:"Polpo alla luciana",nome_en:"Neapolitan stewed octopus",categoria:"Secondo piatto",porzioni:4,note:"Mettere il polpo in casseruola con pomodorini, aglio, prezzemolo, olive, capperi e olio senza aggiungere acqua. Cuocere coperto a fuoco lentissimo 50 minuti nel suo liquido. Il polpo deve risultare tenerissimo.",note_en:"Place octopus in pan with cherry tomatoes, garlic, parsley, olives, capers and oil without adding water. Cook covered on very low heat 50 minutes in its own juices. Octopus should be very tender.",ingredienti:[{nome:"Polpo",qt:"1kg"},{nome:"Pomodorini",qt:"300g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Polpo alla luciana (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:28,gs:1.5,g:8,z:3,ch:5,fi:2,ca:60,fe:3.5,mg:55,k2:620,na:520,zn:2.5,fo:18,se:48,col:90}},{id:"tpl_1159",nome:"Sgombro al forno con erbe",nome_en:"Herb-baked mackerel",categoria:"Secondo piatto",porzioni:4,note:"Incidere gli sgombri puliti. Farcire con fettine di limone, aglio, prezzemolo e origano. Condire con olio e sale. Cuocere in forno a 200 C per 20 minuti. Ricco di Omega-3 e veloce da preparare.",note_en:"Score cleaned mackerel. Fill with lemon slices, garlic, parsley and oregano. Season with oil and salt. Bake at 200 C for 20 minutes. Rich in Omega-3 and quick to prepare.",ingredienti:[{nome:"Sgombri interi",qt:"4"},{nome:"Limone",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Sgombro al forno con erbe (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:26,gs:4,g:18,z:1,ch:2,fi:.3,ca:30,fe:1.5,mg:38,k2:480,na:220,zn:1.5,fo:12,se:45,col:80}},{id:"tpl_1160",nome:"Pesce spada alla siciliana",nome_en:"Sicilian-style swordfish",categoria:"Secondo piatto",porzioni:4,note:"Marinare le fette di pesce spada con olio, limone, aglio e origano 30 minuti. Cuocere in padella caldissima 3 minuti per lato. Condire con salmoriglio (olio, limone, aglio, origano) e servire con capperi.",note_en:"Marinate swordfish steaks with oil, lemon, garlic and oregano 30 minutes. Cook in very hot pan 3 minutes per side. Dress with salmoriglio (oil, lemon, garlic, oregano) and serve with capers.",ingredienti:[{nome:"Pesce spada",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Origano",qt:"2 cucchiaini"},{nome:"Capperi",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pesce spada alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:32,gs:2,g:13,z:1,ch:3,fi:.5,ca:30,fe:1.5,mg:42,k2:580,na:320,zn:1.5,fo:12,se:55,col:80}},{id:"tpl_1161",nome:"Branzino in crosta di sale",nome_en:"Sea bass in salt crust",categoria:"Secondo piatto",porzioni:4,note:"Coprire completamente il branzino con sale grosso misto ad albumi montati a neve. Cuocere in forno a 220 C per 30 minuti. Rompere la crosta al tavolo. La carne risulta succosa e saporita senza essere salata.",note_en:"Completely cover sea bass with coarse salt mixed with whisked egg whites. Bake at 220 C for 30 minutes. Break crust at the table. Meat is juicy and flavourful without being salty.",ingredienti:[{nome:"Branzino intero",qt:"1kg"},{nome:"Sale grosso",qt:"1.5kg"},{nome:"Albumi",qt:"3"},{nome:"Limone",qt:"1"},{nome:"Timo",qt:"3 rametti"},{nome:"Alloro",qt:"2 foglie"}],_dbEntry:{n:"Branzino in crosta di sale (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:32,gs:1,g:8,z:0,ch:1,fi:.2,ca:40,fe:1.2,mg:38,k2:560,na:280,zn:1.2,fo:18,se:35,col:80}},{id:"tpl_1162",nome:"Sogliola al burro e capperi",nome_en:"Sole with butter and capers",categoria:"Secondo piatto",porzioni:4,note:"Infarinare i filetti di sogliola. Cuocere in burro e olio 3 minuti per lato. Togliere il pesce e nella stessa padella aggiungere capperi, succo di limone e prezzemolo. Versare il burro ai capperi sulla sogliola.",note_en:"Flour sole fillets. Cook in butter and oil 3 minutes per side. Remove fish and in same pan add capers, lemon juice and parsley. Pour caper butter over sole.",ingredienti:[{nome:"Filetti di sogliola",qt:"700g"},{nome:"Capperi",qt:"40g"},{nome:"Burro",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Limone",qt:"1"},{nome:"Prezzemolo",qt:"15g"},{nome:"Farina",qt:"40g"}],_dbEntry:{n:"Sogliola al burro e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:28,gs:8,g:14,z:1,ch:8,fi:.3,ca:40,fe:1,mg:35,k2:450,na:420,zn:1,fo:15,se:30,col:115}},{id:"tpl_1163",nome:"Cozze al vino bianco e prezzemolo",nome_en:"Mussels with white wine and parsley",categoria:"Secondo piatto",porzioni:4,note:"Pulire e spazzolare le cozze. Soffriggere aglio e peperoncino in olio. Aggiungere le cozze e il vino bianco. Cuocere coperto a fuoco vivo 5 minuti finche si aprono. Aggiungere abbondante prezzemolo. Servire con pane tostato.",note_en:"Clean and scrub mussels. Sauté garlic and chilli in oil. Add mussels and white wine. Cook covered on high heat 5 minutes until they open. Add plenty of parsley. Serve with toasted bread.",ingredienti:[{nome:"Cozze",qt:"1.5kg"},{nome:"Vino bianco",qt:"200ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"30g"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Cozze al vino bianco e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:18,gs:1.5,g:8,z:2,ch:8,fi:.5,ca:70,fe:4,mg:45,k2:420,na:480,zn:2.5,fo:35,se:45,col:60}},{id:"tpl_1164",nome:"Trota salmonata al cartoccio",nome_en:"Salmon trout en papillote",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di trota su carta da forno. Aggiungere fettine di limone, aneto, pomodorini e olio. Chiudere a cartoccio. Cuocere in forno a 190 C per 18 minuti. Aprire il cartoccio al tavolo per godere dell'aroma.",note_en:"Place trout fillets on parchment paper. Add lemon slices, dill, cherry tomatoes and oil. Seal into parcel. Bake at 190 C for 18 minutes. Open parcel at table to enjoy the aroma.",ingredienti:[{nome:"Filetti di trota salmonata",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aneto fresco",qt:"20g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aglio",qt:"2 spicchi"}],_dbEntry:{n:"Trota salmonata al cartoccio (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:30,gs:3.5,g:14,z:2,ch:3,fi:.5,ca:35,fe:1.2,mg:38,k2:580,na:200,zn:1.5,fo:18,se:42,col:90}},{id:"tpl_1165",nome:"Tonno in crosta di sesamo con zenzero",nome_en:"Sesame-crusted tuna with ginger",categoria:"Secondo piatto",porzioni:4,note:"Impanare le bistecche di tonno nei semi di sesamo nero e bianco. Cuocere in padella caldissima con poco olio 2 minuti per lato. Il tonno deve restare rosato al centro. Servire con salsa di soia e zenzero grattugiato.",note_en:"Coat tuna steaks in black and white sesame seeds. Cook in very hot pan with little oil 2 minutes per side. Tuna should remain pink in centre. Serve with soy sauce and grated ginger.",ingredienti:[{nome:"Filetto di tonno fresco",qt:"600g"},{nome:"Semi di sesamo misti",qt:"80g"},{nome:"Salsa di soia",qt:"40ml"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Olio di sesamo",qt:"20ml"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Tonno in crosta di sesamo con zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:36,gs:2.5,g:13,z:1,ch:4,fi:1,ca:100,fe:2,mg:55,k2:580,na:720,zn:1.5,fo:15,se:80,col:60}},{id:"tpl_1166",nome:"Spigola in acqua pazza",nome_en:"Sea bass in crazy water",categoria:"Secondo piatto",porzioni:4,note:"Rosolare la spigola intera in olio con aglio e peperoncino. Aggiungere pomodorini, prezzemolo e acqua. Cuocere coperto 20 minuti. L'acqua di cottura si trasforma in un brodo aromatico delizioso.",note_en:"Brown whole sea bass in oil with garlic and chilli. Add cherry tomatoes, parsley and water. Cook covered 20 minutes. Cooking liquid transforms into a delicious aromatic broth.",ingredienti:[{nome:"Spigola intera",qt:"1kg"},{nome:"Pomodorini",qt:"250g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"25g"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Acqua",qt:"200ml"}],_dbEntry:{n:"Spigola in acqua pazza (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:30,gs:1.5,g:10,z:2,ch:3,fi:.8,ca:45,fe:1.5,mg:40,k2:600,na:250,zn:1.2,fo:20,se:38,col:78}},{id:"tpl_1167",nome:"Filetti di platessa alle erbe",nome_en:"Plaice fillets with herbs",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di platessa in teglia. Cospargere con pangrattato, prezzemolo, aglio, scorza di limone e olio. Cuocere in forno a 200 C per 15 minuti finche la superficie e dorata. Servire con verdure a vapore.",note_en:"Arrange plaice fillets in baking dish. Sprinkle with breadcrumbs, parsley, garlic, lemon zest and oil. Bake at 200 C for 15 minutes until surface is golden. Serve with steamed vegetables.",ingredienti:[{nome:"Filetti di platessa",qt:"700g"},{nome:"Pangrattato",qt:"50g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Filetti di platessa alle erbe (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:26,gs:1.5,g:8,z:1,ch:8,fi:.5,ca:40,fe:1,mg:32,k2:480,na:250,zn:1,fo:18,se:28,col:60}},{id:"tpl_1168",nome:"Seppie in umido con piselli",nome_en:"Cuttlefish stew with peas",categoria:"Secondo piatto",porzioni:4,note:"Pulire le seppie e tagliarle ad anelli. Soffriggere cipolla e aglio in olio. Aggiungere le seppie e sfumare con vino bianco. Unire i piselli e pomodori. Cuocere coperto 35 minuti. Aggiungere prezzemolo.",note_en:"Clean cuttlefish and cut into rings. Sauté onion and garlic in oil. Add cuttlefish and deglaze with white wine. Add peas and tomatoes. Cook covered 35 minutes. Add parsley.",ingredienti:[{nome:"Seppie",qt:"800g"},{nome:"Piselli",qt:"300g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"120ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Seppie in umido con piselli (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:1.5,g:8,z:5,ch:12,fi:4,ca:55,fe:2.5,mg:52,k2:580,na:380,zn:2,fo:50,se:40,col:180}},{id:"tpl_1169",nome:"Nasello al forno con patate",nome_en:"Baked hake with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Affettare le patate e disporle in teglia con olio. Adagiare i filetti di nasello sopra. Condire con aglio, prezzemolo, olio e vino bianco. Cuocere in forno a 190 C per 30 minuti.",note_en:"Slice potatoes and arrange in oiled baking dish. Place hake fillets on top. Season with garlic, parsley, oil and white wine. Bake at 190 C for 30 minutes.",ingredienti:[{nome:"Filetti di nasello",qt:"700g"},{nome:"Patate",qt:"500g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Nasello al forno con patate (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:28,gs:1.5,g:9,z:1,ch:22,fi:2,ca:45,fe:1.5,mg:42,k2:720,na:250,zn:1.2,fo:20,se:32,col:65}},{id:"tpl_1170",nome:"Sardine in saor veneziane",nome_en:"Venetian sweet-sour sardines",categoria:"Secondo piatto",porzioni:4,note:"Friggere le sardine infarinate. Stufare cipolle in olio finche morbide. Sfumare con aceto, aggiungere uvetta e pinoli. Alternare strati di sardine e cipolle in un contenitore. Lasciare marinare 24 ore in frigorifero.",note_en:"Fry floured sardines. Stew onions in oil until soft. Deglaze with vinegar, add raisins and pine nuts. Alternate layers of sardines and onions in a container. Marinate 24 hours in fridge.",ingredienti:[{nome:"Sardine fresche",qt:"600g"},{nome:"Cipolle",qt:"400g"},{nome:"Aceto di vino bianco",qt:"100ml"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Farina",qt:"60g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Sardine in saor veneziane (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:22,gs:3,g:16,z:8,ch:20,fi:2,ca:85,fe:2.5,mg:42,k2:480,na:280,zn:2,fo:18,se:38,col:72}},{id:"tpl_1171",nome:"Patate arrosto al rosmarino",nome_en:"Roast potatoes with rosemary",categoria:"Contorno",porzioni:4,note:"Tagliare le patate a spicchi. Bollire 10 minuti. Scolare e asciugare bene. Disporre in teglia con olio abbondante, rosmarino, aglio e sale. Cuocere in forno a 220 C per 35-40 minuti rigirando ogni 10 minuti.",note_en:"Cut potatoes into wedges. Boil 10 minutes. Drain and dry well. Arrange in baking dish with plenty of oil, rosemary, garlic and salt. Bake at 220 C for 35-40 minutes turning every 10 minutes.",ingredienti:[{nome:"Patate a pasta gialla",qt:"800g"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Sale grosso",qt:"q.b."}],_dbEntry:{n:"Patate arrosto al rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:3.5,gs:1.5,g:10,z:1,ch:28,fi:2.5,ca:15,fe:1,mg:28,k2:580,na:200,zn:.5,fo:22,se:2,col:0}},{id:"tpl_1172",nome:"Spinaci saltati con aglio e olio",nome_en:"Sautéed spinach with garlic and oil",categoria:"Contorno",porzioni:4,note:"Lavare gli spinaci. Soffriggere aglio e peperoncino in olio. Aggiungere gli spinaci freschi e cuocere a fuoco vivo 5 minuti mescolando. Salare e servire come contorno versatile.",note_en:"Wash spinach. Sauté garlic and chilli in oil. Add fresh spinach and cook on high heat 5 minutes stirring. Season with salt and serve as versatile side dish.",ingredienti:[{nome:"Spinaci freschi",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Spinaci saltati con aglio e olio (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:5,gs:1,g:7,z:1,ch:4,fi:4,ca:160,fe:3.5,mg:80,k2:680,na:180,zn:1,fo:180,se:2,col:0}},{id:"tpl_1173",nome:"Caponata siciliana",nome_en:"Sicilian caponata",categoria:"Contorno",porzioni:6,note:"Friggere le melanzane a cubetti. Soffriggere cipolla in olio. Aggiungere sedano, pomodori, olive, capperi. Sfumare con aceto e zucchero per il sapore agrodolce. Aggiungere le melanzane e cuocere 20 minuti. Ottima fredda.",note_en:"Fry diced aubergine. Sauté onion in oil. Add celery, tomatoes, olives, capers. Deglaze with vinegar and sugar for sweet-sour flavour. Add aubergine and cook 20 minutes. Excellent cold.",ingredienti:[{nome:"Melanzane",qt:"600g"},{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"3 coste"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Olive verdi",qt:"80g"},{nome:"Capperi",qt:"40g"},{nome:"Aceto di vino",qt:"50ml"},{nome:"Zucchero",qt:"20g"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Caponata siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:2,g:12,z:8,ch:14,fi:5,ca:45,fe:1.5,mg:35,k2:480,na:380,zn:.5,fo:28,se:2,col:0}},{id:"tpl_1174",nome:"Fagiolini verdi al vapore con mandorle",nome_en:"Steamed green beans with almonds",categoria:"Contorno",porzioni:4,note:"Cuocere i fagiolini a vapore 8 minuti: devono restare croccanti. Tostare le mandorle a lamelle in padella. Condire i fagiolini con olio, limone, sale e mandorle tostate.",note_en:"Steam green beans 8 minutes: they should remain crunchy. Toast flaked almonds in pan. Dress beans with oil, lemon, salt and toasted almonds.",ingredienti:[{nome:"Fagiolini verdi",qt:"600g"},{nome:"Mandorle a lamelle",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Fagiolini verdi al vapore con mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4.5,gs:1,g:7,z:3,ch:8,fi:4.5,ca:60,fe:1.5,mg:42,k2:340,na:10,zn:.8,fo:48,se:2,col:0}},{id:"tpl_1175",nome:"Zucchine trifolate",nome_en:"Sautéed courgettes with garlic",categoria:"Contorno",porzioni:4,note:"Tagliare le zucchine a rondelle o listarelle. Soffriggere aglio in olio. Aggiungere le zucchine e cuocere a fuoco vivo 8-10 minuti. Aggiungere prezzemolo e menta. Salare. Ottime calde o fredde.",note_en:"Cut courgettes into rounds or strips. Sauté garlic in oil. Add courgettes and cook on high heat 8-10 minutes. Add parsley and mint. Season with salt. Excellent hot or cold.",ingredienti:[{nome:"Zucchine",qt:"700g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Menta",qt:"5g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zucchine trifolate (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2.5,gs:1.2,g:7,z:3,ch:5,fi:2,ca:25,fe:.8,mg:22,k2:350,na:10,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1176",nome:"Broccoli al vapore con olio al limone",nome_en:"Steamed broccoli with lemon oil",categoria:"Contorno",porzioni:4,note:"Dividere i broccoli in cimette. Cuocere a vapore 8 minuti: devono restare al dente e di colore verde vivo. Condire con emulsione di olio extravergine, succo di limone, sale e pepe.",note_en:"Divide broccoli into florets. Steam 8 minutes: should remain al dente and bright green. Dress with emulsion of extra virgin oil, lemon juice, salt and pepper.",ingredienti:[{nome:"Broccoli",qt:"700g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Broccoli al vapore con olio al limone (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:5,gs:1.2,g:7,z:2,ch:6,fi:5,ca:65,fe:1,mg:25,k2:380,na:45,zn:.6,fo:100,se:3,col:0}},{id:"tpl_1177",nome:"Carote glassate al miele e timo",nome_en:"Honey-glazed carrots with thyme",categoria:"Contorno",porzioni:4,note:"Pelare le carote e tagliarle a bastoncini. Cuocere in padella con burro, acqua e miele coperto 10 minuti. Scoprire e alzare il fuoco per glassare. Aggiungere timo fresco e poco aceto balsamico.",note_en:"Peel carrots and cut into sticks. Cook in pan with butter, water and honey covered 10 minutes. Uncover and increase heat to glaze. Add fresh thyme and a little balsamic vinegar.",ingredienti:[{nome:"Carote",qt:"600g"},{nome:"Burro",qt:"25g"},{nome:"Miele",qt:"30ml"},{nome:"Timo",qt:"4 rametti"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Carote glassate al miele e timo (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1.5,gs:2,g:5,z:12,ch:16,fi:3.5,ca:42,fe:.7,mg:18,k2:420,na:90,zn:.3,fo:22,se:1,col:12}},{id:"tpl_1178",nome:"Peperoni arrostiti",nome_en:"Roasted peppers",categoria:"Contorno",porzioni:4,note:"Arrostire i peperoni interi direttamente sulla fiamma o in forno a 250 C finche la pelle e nera. Chiudere in sacchetto di plastica 15 minuti. Pelare, eliminare semi e filamenti. Condire con olio, aglio e basilico.",note_en:"Roast whole peppers directly on flame or in oven at 250 C until skin is black. Close in plastic bag 15 minutes. Peel, remove seeds and membranes. Dress with oil, garlic and basil.",ingredienti:[{nome:"Peperoni misti",qt:"800g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Peperoni arrostiti (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2,gs:1.2,g:7,z:6,ch:8,fi:3,ca:20,fe:.8,mg:18,k2:380,na:10,zn:.3,fo:35,se:1,col:0}},{id:"tpl_1179",nome:"Carciofi alla romana",nome_en:"Roman-style artichokes",categoria:"Contorno",porzioni:4,note:"Pulire i carciofi lasciando il gambo. Farcire con menta, prezzemolo e aglio. Disporli in casseruola con olio e acqua. Cuocere coperto a fuoco lento 35-40 minuti finche teneri. I gambi devono risultare morbidi.",note_en:"Clean artichokes keeping stems. Fill with mint, parsley and garlic. Arrange in pan with oil and water. Cook covered on low heat 35-40 minutes until tender. Stems should be soft.",ingredienti:[{nome:"Carciofi romaneschi",qt:"4"},{nome:"Menta",qt:"20g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Carciofi alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:4,gs:2,g:10,z:2,ch:10,fi:6,ca:45,fe:1.5,mg:35,k2:420,na:80,zn:.6,fo:68,se:1,col:0}},{id:"tpl_1180",nome:"Verdure grigliate miste",nome_en:"Mixed grilled vegetables",categoria:"Contorno",porzioni:4,note:"Affettare melanzane, zucchine, peperoni e cipolla rossa. Condire con olio e sale. Grigliare su piastra caldissima 3-4 minuti per lato. Condire con olio crudo, aglio, basilico e aceto balsamico.",note_en:"Slice aubergines, courgettes, peppers and red onion. Season with oil and salt. Grill on very hot griddle 3-4 minutes per side. Dress with raw oil, garlic, basil and balsamic vinegar.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Zucchine",qt:"300g"},{nome:"Peperoni",qt:"2"},{nome:"Cipolla rossa",qt:"2"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Aceto balsamico",qt:"20ml"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Verdure grigliate miste (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2.5,gs:1.5,g:8,z:6,ch:8,fi:4,ca:25,fe:.8,mg:25,k2:450,na:15,zn:.4,fo:35,se:1,col:0}},{id:"tpl_1181",nome:"Purè di patate classico",nome_en:"Classic mashed potatoes",categoria:"Contorno",porzioni:4,note:"Lessare le patate con la buccia. Pelare e passare allo schiacciapatate. Aggiungere burro, latte caldo e noce moscata. Mescolare energicamente finche il pure e liscio e cremoso. Regolare di sale.",note_en:"Boil potatoes in their skins. Peel and pass through potato ricer. Add butter, hot milk and nutmeg. Stir vigorously until mash is smooth and creamy. Season with salt.",ingredienti:[{nome:"Patate farinose",qt:"800g"},{nome:"Burro",qt:"60g"},{nome:"Latte intero",qt:"150ml"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Pure di patate classico (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:4,gs:4,g:8,z:3,ch:26,fi:2,ca:60,fe:.8,mg:22,k2:480,na:120,zn:.4,fo:15,se:2,col:22}},{id:"tpl_1182",nome:"Lenticchie in umido",nome_en:"Stewed lentils",categoria:"Contorno",porzioni:4,note:"Soffriggere cipolla, carota e sedano in olio. Aggiungere lenticchie lavate, pomodori e brodo. Cuocere 30 minuti. Aggiungere rosmarino. Le lenticchie devono essere morbide ma non sfatte. Ottimo con salsicce.",note_en:"Sauté onion, carrot and celery in oil. Add washed lentils, tomatoes and stock. Cook 30 minutes. Add rosemary. Lentils should be soft but not mushy. Excellent with sausages.",ingredienti:[{nome:"Lenticchie verdi",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Brodo",qt:"500ml"}],_dbEntry:{n:"Lenticchie in umido (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:.8,g:6,z:3,ch:30,fi:10,ca:45,fe:3.5,mg:55,k2:580,na:250,zn:2,fo:130,se:4,col:0}},{id:"tpl_1183",nome:"Fagioli all'uccelletto toscani",nome_en:"Tuscan cannellini beans",categoria:"Contorno",porzioni:4,note:"Soffriggere aglio e salvia in olio. Aggiungere i fagioli cannellini cotti. Unire poca passata di pomodoro e brodo. Cuocere 15 minuti a fuoco lento. Il sugo deve ristringere. Ottimi con salsicce o come contorno.",note_en:"Sauté garlic and sage in oil. Add cooked cannellini beans. Add a little tomato passata and stock. Cook 15 minutes on low heat. Sauce should thicken. Excellent with sausages or as side dish.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"600g"},{nome:"Passata di pomodoro",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Salvia",qt:"6 foglie"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Fagioli all uccelletto toscani (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:11,gs:1,g:7,z:3,ch:25,fi:8,ca:65,fe:2.5,mg:52,k2:620,na:200,zn:1.5,fo:90,se:3,col:0}},{id:"tpl_1184",nome:"Cime di rapa saltate",nome_en:"Sautéed turnip tops",categoria:"Contorno",porzioni:4,note:"Lessare le cime di rapa in acqua salata 5 minuti. Scolare. Saltare in padella con olio, aglio e peperoncino a fuoco vivo 5 minuti. Ottima con la pasta (orecchiette) o come contorno.",note_en:"Boil turnip tops in salted water 5 minutes. Drain. Sauté in pan with oil, garlic and chilli on high heat 5 minutes. Excellent with pasta (orecchiette) or as side dish.",ingredienti:[{nome:"Cime di rapa",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Acciughe",qt:"2"}],_dbEntry:{n:"Cime di rapa saltate (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:1.5,g:8,z:2,ch:4,fi:5.5,ca:110,fe:2.5,mg:38,k2:380,na:180,zn:.8,fo:120,se:2,col:3}},{id:"tpl_1185",nome:"Funghi trifolati",nome_en:"Sautéed mushrooms with garlic and parsley",categoria:"Contorno",porzioni:4,note:"Pulire i funghi e tagliarli a fette. Soffriggere aglio in olio a fuoco vivo. Aggiungere i funghi e cuocere senza mescolare per 5 minuti. Saltare e aggiungere prezzemolo e succo di limone. Salare a fine cottura.",note_en:"Clean mushrooms and slice. Sauté garlic in oil on high heat. Add mushrooms and cook without stirring for 5 minutes. Toss and add parsley and lemon juice. Season at end of cooking.",ingredienti:[{nome:"Funghi misti o porcini",qt:"600g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"0.5"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Funghi trifolati (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:1.5,g:8,z:1,ch:4,fi:3.5,ca:15,fe:1.5,mg:18,k2:480,na:15,zn:1,fo:22,se:6,col:0}},{id:"tpl_1186",nome:"Zucca al forno con cannella e cumino",nome_en:"Roasted pumpkin with cinnamon and cumin",categoria:"Contorno",porzioni:4,note:"Tagliare la zucca a spicchi lasciando la buccia. Condire con olio, cannella, cumino, sale e pepe. Cuocere in forno a 200 C per 30-35 minuti. La zucca deve caramellare ai bordi. Servire con yogurt al lime.",note_en:"Cut pumpkin into wedges leaving skin. Season with oil, cinnamon, cumin, salt and pepper. Bake at 200 C for 30-35 minutes. Pumpkin should caramelise at edges. Serve with lime yogurt.",ingredienti:[{nome:"Zucca",qt:"800g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Yogurt greco",qt:"100g"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Zucca al forno con cannella e cumino (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:4,gs:1.5,g:8,z:5,ch:12,fi:2.5,ca:55,fe:1,mg:22,k2:450,na:80,zn:.5,fo:25,se:2,col:2}},{id:"tpl_1187",nome:"Finocchi gratinati",nome_en:"Gratin fennel",categoria:"Contorno",porzioni:4,note:"Lessare i finocchi tagliati a meta in acqua salata 15 minuti. Scolare e disporre in teglia. Coprire con besciamella e parmigiano. Cuocere in forno a 200 C per 20 minuti fino a doratura.",note_en:"Boil halved fennel in salted water 15 minutes. Drain and arrange in baking dish. Cover with bechamel and parmesan. Bake at 200 C for 20 minutes until golden.",ingredienti:[{nome:"Finocchi",qt:"600g"},{nome:"Latte",qt:"300ml"},{nome:"Farina",qt:"25g"},{nome:"Burro",qt:"25g"},{nome:"Parmigiano",qt:"50g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Finocchi gratinati (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:7,gs:4,g:8,z:5,ch:12,fi:4,ca:200,fe:1,mg:25,k2:480,na:200,zn:1,fo:35,se:3,col:25}},{id:"tpl_1188",nome:"Melanzane alla parmigiana",nome_en:"Aubergine parmigiana",categoria:"Contorno",porzioni:6,note:"Friggere le melanzane a fette in olio abbondante. Scolare su carta. Alternare in teglia strati di melanzane, sugo di pomodoro, mozzarella e parmigiano. Cuocere in forno a 180 C per 40 minuti.",note_en:"Fry aubergine slices in plenty of oil. Drain on paper. Alternate in baking dish layers of aubergine, tomato sauce, mozzarella and parmesan. Bake at 180 C for 40 minutes.",ingredienti:[{nome:"Melanzane",qt:"1kg"},{nome:"Mozzarella",qt:"300g"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Parmigiano",qt:"80g"},{nome:"Basilico",qt:"15g"},{nome:"Olio per friggere",qt:"200ml"}],_dbEntry:{n:"Melanzane alla parmigiana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:5,g:22,z:6,ch:16,fi:5,ca:280,fe:1.5,mg:45,k2:520,na:420,zn:2,fo:45,se:5,col:30}},{id:"tpl_1189",nome:"Bruschetta al pomodoro e basilico",nome_en:"Bruschetta with tomato and basil",categoria:"Antipasto",porzioni:4,note:"Tostare le fette di pane casereccio sulla griglia. Strofinare con aglio. Condire con pomodori a dadini, basilico fresco, olio extravergine e sale grosso. Servire subito per mantenere il croccante.",note_en:"Toast slices of country bread on grill. Rub with garlic. Top with diced tomatoes, fresh basil, extra virgin oil and coarse salt. Serve immediately to keep crispness.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Pomodori maturi",qt:"400g"},{nome:"Basilico",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Sale grosso",qt:"q.b."}],_dbEntry:{n:"Bruschetta al pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1,g:7,z:4,ch:20,fi:2,ca:30,fe:1.2,mg:22,k2:320,na:200,zn:.5,fo:18,se:3,col:0}},{id:"tpl_1190",nome:"Carpaccio di manzo con rucola e parmigiano",nome_en:"Beef carpaccio with rocket and parmesan",categoria:"Antipasto",porzioni:4,note:"Affettare il filetto di manzo sottilissimo (oppure usare filetto gia affettato). Disporre su piatto. Condire con olio extravergine, succo di limone, sale e pepe. Coprire con rucola fresca e scaglie di parmigiano.",note_en:"Slice beef fillet very thin (or use pre-sliced fillet). Arrange on plate. Dress with extra virgin oil, lemon juice, salt and pepper. Cover with fresh rocket and parmesan shavings.",ingredienti:[{nome:"Filetto di manzo",qt:"400g"},{nome:"Rucola",qt:"100g"},{nome:"Parmigiano a scaglie",qt:"60g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Carpaccio di manzo con rucola e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:4,g:13,z:1,ch:2,fi:.5,ca:110,fe:2.5,mg:25,k2:420,na:280,zn:4,fo:28,se:18,col:55}},{id:"tpl_1191",nome:"Insalata caprese",nome_en:"Caprese salad",categoria:"Antipasto",porzioni:4,note:"Affettare i pomodori e la mozzarella di bufala. Alternare le fette su piatto da portata. Condire con olio extravergine di qualita, sale e foglie di basilico. Non aggiungere aceto. Servire a temperatura ambiente.",note_en:"Slice tomatoes and buffalo mozzarella. Alternate slices on serving plate. Dress with quality extra virgin oil, salt and basil leaves. Do not add vinegar. Serve at room temperature.",ingredienti:[{nome:"Pomodori cuore di bue",qt:"4"},{nome:"Mozzarella di bufala",qt:"250g"},{nome:"Basilico fresco",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata caprese (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:12,gs:5,g:16,z:4,ch:5,fi:1,ca:280,fe:.5,mg:18,k2:320,na:380,zn:1.5,fo:20,se:5,col:45}},{id:"tpl_1192",nome:"Tartare di tonno con avocado",nome_en:"Tuna tartare with avocado",categoria:"Antipasto",porzioni:4,note:"Tagliare il tonno fresco a cubetti piccoli. Condire con olio di sesamo, soia, zenzero grattugiato e cipollotto. Disporre su base di avocado schiacciato con lime. Guarnire con sesamo e microgreens.",note_en:"Cut fresh tuna into small cubes. Dress with sesame oil, soy, grated ginger and spring onion. Arrange on base of avocado mashed with lime. Garnish with sesame and microgreens.",ingredienti:[{nome:"Tonno fresco",qt:"400g"},{nome:"Avocado",qt:"2"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"15ml"},{nome:"Zenzero fresco",qt:"10g"},{nome:"Lime",qt:"1"},{nome:"Cipollotto",qt:"2"}],_dbEntry:{n:"Tartare di tonno con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:28,gs:3,g:16,z:1,ch:5,fi:4,ca:25,fe:1.5,mg:45,k2:680,na:580,zn:1.5,fo:38,se:55,col:48}},{id:"tpl_1193",nome:"Burrata con pomodori confit e pesto",nome_en:"Burrata with confit tomatoes and pesto",categoria:"Antipasto",porzioni:4,note:"Preparare i pomodorini confit in forno con olio, aglio e zucchero a 120 C per 2 ore. Disporre la burrata su piatto. Aggiungere i pomodori confit e cucchiaiate di pesto. Condire con olio e pane casereccio tostato.",note_en:"Prepare confit cherry tomatoes in oven with oil, garlic and sugar at 120 C for 2 hours. Place burrata on plate. Add confit tomatoes and spoonfuls of pesto. Dress with oil and toasted country bread.",ingredienti:[{nome:"Burrata",qt:"250g"},{nome:"Pomodorini",qt:"300g"},{nome:"Pesto al basilico",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Zucchero",qt:"10g"}],_dbEntry:{n:"Burrata con pomodori confit e pesto (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:9,g:24,z:5,ch:8,fi:1.5,ca:250,fe:.5,mg:20,k2:280,na:380,zn:1.2,fo:20,se:4,col:40}},{id:"tpl_1194",nome:"Tonno e fagioli",nome_en:"Tuna and bean salad",categoria:"Antipasto",porzioni:4,note:"Scolare il tonno e sminuzzarlo. Scolare i fagioli cannellini. Mescolare con cipolla rossa affettata sottile. Condire con olio extravergine, succo di limone, sale e pepe. Guarnire con prezzemolo.",note_en:"Drain and flake tuna. Drain cannellini beans. Mix with thinly sliced red onion. Dress with extra virgin oil, lemon juice, salt and pepper. Garnish with parsley.",ingredienti:[{nome:"Tonno sott olio",qt:"200g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Tonno e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:22,gs:1.5,g:10,z:2,ch:20,fi:7,ca:65,fe:3,mg:55,k2:700,na:480,zn:2,fo:88,se:38,col:35}},{id:"tpl_1195",nome:"Insalata russa",nome_en:"Russian salad",categoria:"Antipasto",porzioni:6,note:"Lessare separatamente patate, carote, fagiolini e piselli. Tagliare tutto a cubetti uniformi. Aggiungere cetriolini sott'aceto. Condire con maionese. Servire fredda decorata con uova sode e verdure.",note_en:"Boil separately potatoes, carrots, green beans and peas. Cut everything into uniform cubes. Add pickled gherkins. Dress with mayonnaise. Serve cold decorated with hard-boiled eggs and vegetables.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Carote",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Piselli",qt:"150g"},{nome:"Cetriolini",qt:"80g"},{nome:"Maionese",qt:"150g"},{nome:"Uova sode",qt:"2"}],_dbEntry:{n:"Insalata russa (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:6,gs:4,g:16,z:4,ch:18,fi:4,ca:40,fe:1.2,mg:30,k2:450,na:480,zn:.8,fo:45,se:5,col:75}},{id:"tpl_1196",nome:"Insalata greca",nome_en:"Greek salad",categoria:"Insalata",porzioni:4,note:"Tagliare pomodori, cetrioli e cipolla rossa. Aggiungere olive Kalamata e feta sbriciolata. Condire con olio extravergine, origano, sale e pepe. Non aggiungere aceto. La semplicita e il segreto.",note_en:"Cut tomatoes, cucumbers and red onion. Add Kalamata olives and crumbled feta. Dress with extra virgin oil, oregano, salt and pepper. Do not add vinegar. Simplicity is the secret.",ingredienti:[{nome:"Pomodori maturi",qt:"400g"},{nome:"Cetriolo",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Olive Kalamata",qt:"80g"},{nome:"Feta",qt:"150g"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata greca (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:5,g:16,z:5,ch:8,fi:3,ca:200,fe:1,mg:28,k2:420,na:680,zn:1.5,fo:30,se:5,col:30}},{id:"tpl_1197",nome:"Bowl di quinoa con verdure e ceci",nome_en:"Quinoa bowl with vegetables and chickpeas",categoria:"Insalata",porzioni:4,note:"Cuocere la quinoa in brodo vegetale. Arrostire i ceci con cumino e paprika. Preparare verdure arrostite. Comporre le bowl con quinoa, ceci, verdure, avocado e salsa tahini al limone.",note_en:"Cook quinoa in vegetable stock. Roast chickpeas with cumin and paprika. Prepare roasted vegetables. Compose bowls with quinoa, chickpeas, vegetables, avocado and lemon tahini sauce.",ingredienti:[{nome:"Quinoa",qt:"200g"},{nome:"Ceci cotti",qt:"300g"},{nome:"Avocado",qt:"2"},{nome:"Zucchine grigliate",qt:"200g"},{nome:"Tahini",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Cumino",qt:"1 cucchiaino"}],_dbEntry:{n:"Bowl di quinoa con verdure e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:2,g:18,z:3,ch:50,fi:12,ca:80,fe:4.5,mg:90,k2:750,na:280,zn:3,fo:160,se:6,col:0}},{id:"tpl_1198",nome:"Insalata di farro con pomodorini e mozzarella",nome_en:"Farro salad with cherry tomatoes and mozzarella",categoria:"Insalata",porzioni:4,note:"Cuocere il farro perlato in acqua salata 25 minuti. Scolare e raffreddare. Mescolare con pomodorini, mozzarella, rucola, basilico e olio. Aggiustare di sale e servire a temperatura ambiente.",note_en:"Cook pearl farro in salted water 25 minutes. Drain and cool. Mix with cherry tomatoes, mozzarella, rocket, basil and oil. Season with salt and serve at room temperature.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Pomodorini",qt:"250g"},{nome:"Mozzarella",qt:"200g"},{nome:"Rucola",qt:"60g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata di farro con pomodorini e mozzarella (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:4,g:14,z:4,ch:48,fi:4,ca:220,fe:2,mg:55,k2:420,na:320,zn:2,fo:40,se:8,col:25}},{id:"tpl_1199",nome:"Panzanella toscana",nome_en:"Tuscan bread salad",categoria:"Insalata",porzioni:4,note:"Bagnare il pane raffermo con acqua e aceto. Strizzare bene. Mescolare con pomodori maturi, cetriolo, cipolla rossa, basilico e olio extravergine. Lasciare riposare 30 minuti prima di servire.",note_en:"Soak stale bread with water and vinegar. Squeeze well. Mix with ripe tomatoes, cucumber, red onion, basil and extra virgin oil. Rest 30 minutes before serving.",ingredienti:[{nome:"Pane sciocco toscano raffermo",qt:"300g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Cetriolo",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Basilico",qt:"20g"},{nome:"Aceto di vino",qt:"30ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Panzanella toscana (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:5,gs:1.5,g:12,z:5,ch:30,fi:3,ca:55,fe:1.5,mg:28,k2:420,na:300,zn:.5,fo:25,se:4,col:0}},{id:"tpl_1200",nome:"Insalata di polpo e patate",nome_en:"Octopus and potato salad",categoria:"Insalata",porzioni:4,note:"Cuocere il polpo in acqua con aglio, alloro e limone per 50 minuti. Lasciare raffreddare nel brodo. Tagliare a pezzi. Lessare le patate e tagliarle a cubetti. Condire con olio, limone, prezzemolo, sedano e olive.",note_en:"Cook octopus in water with garlic, bay leaf and lemon for 50 minutes. Let cool in broth. Cut into pieces. Boil potatoes and dice. Dress with oil, lemon, parsley, celery and olives.",ingredienti:[{nome:"Polpo",qt:"800g"},{nome:"Patate",qt:"400g"},{nome:"Sedano",qt:"2 coste"},{nome:"Olive nere",qt:"60g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"2"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Insalata di polpo e patate (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:26,gs:1.5,g:10,z:2,ch:20,fi:3,ca:60,fe:2.5,mg:50,k2:680,na:380,zn:2,fo:28,se:45,col:80}},{id:"tpl_1201",nome:"Tabouleh libanese",nome_en:"Lebanese tabbouleh",categoria:"Insalata",porzioni:4,note:"Idratare il bulgur in acqua calda 20 minuti. Scolare e raffreddare. Tritare abbondante prezzemolo e menta. Tagliare pomodori e cetriolo. Condire con olio extravergine e succo di limone abbondante.",note_en:"Hydrate bulgur in hot water 20 minutes. Drain and cool. Finely chop plenty of parsley and mint. Dice tomatoes and cucumber. Dress with extra virgin oil and plenty of lemon juice.",ingredienti:[{nome:"Bulgur",qt:"200g"},{nome:"Prezzemolo",qt:"100g"},{nome:"Menta fresca",qt:"30g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Cetriolo",qt:"1"},{nome:"Limone",qt:"2"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Tabouleh libanese (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:6,gs:1.5,g:12,z:4,ch:32,fi:5,ca:55,fe:3.5,mg:55,k2:520,na:30,zn:1,fo:120,se:3,col:0}},{id:"tpl_1202",nome:"Insalata di lenticchie e spinaci baby",nome_en:"Lentil and baby spinach salad",categoria:"Insalata",porzioni:4,note:"Cuocere le lenticchie verdi al dente. Raffreddare. Mescolare con spinaci baby, pomodorini, cipolla rossa, cetriolo. Condire con vinaigrette al limone (olio, limone, senape, miele). Aggiungere semi di girasole tostati.",note_en:"Cook green lentils al dente. Cool. Mix with baby spinach, cherry tomatoes, red onion, cucumber. Dress with lemon vinaigrette (oil, lemon, mustard, honey). Add toasted sunflower seeds.",ingredienti:[{nome:"Lenticchie verdi",qt:"200g"},{nome:"Spinaci baby",qt:"120g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Semi di girasole",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Limone",qt:"1"},{nome:"Senape",qt:"10g"}],_dbEntry:{n:"Insalata di lenticchie e spinaci baby (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:14,gs:1.5,g:12,z:4,ch:30,fi:10,ca:70,fe:4.5,mg:75,k2:680,na:120,zn:2.5,fo:160,se:8,col:0}},{id:"tpl_1203",nome:"Wrap integrale con pollo e avocado",nome_en:"Whole wheat wrap with chicken and avocado",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e affettarlo. Schiacciare l'avocado con limone e sale. Spalmare sulla piadina integrale. Aggiungere pollo, lattuga, pomodoro, cipolla rossa e yogurt greco. Arrotolare e tagliare a meta.",note_en:"Grill chicken breast and slice. Mash avocado with lemon and salt. Spread on whole wheat flatbread. Add chicken, lettuce, tomato, red onion and Greek yogurt. Roll up and cut in half.",ingredienti:[{nome:"Piadina integrale",qt:"2"},{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"60g"},{nome:"Pomodoro",qt:"1"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Yogurt greco",qt:"60g"}],_dbEntry:{n:"Wrap integrale con pollo e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:34,gs:3,g:14,z:4,ch:42,fi:8,ca:80,fe:2.5,mg:55,k2:680,na:420,zn:2.5,fo:55,se:22,col:75}},{id:"tpl_1204",nome:"Insalata di barbabietole e formaggio di capra",nome_en:"Beetroot and goat cheese salad",categoria:"Insalata",porzioni:4,note:"Arrostire le barbabietole in forno a 200 C per 45 minuti. Pelare e tagliare a spicchi. Disporre su letto di insalata mista con noci tostate e formaggio di capra sbriciolato. Condire con vinaigrette all'arancia.",note_en:"Roast beetroots in oven at 200 C for 45 minutes. Peel and cut into wedges. Arrange on mixed salad with toasted walnuts and crumbled goat cheese. Dress with orange vinaigrette.",ingredienti:[{nome:"Barbabietole",qt:"400g"},{nome:"Formaggio di capra",qt:"120g"},{nome:"Gherigli di noce",qt:"60g"},{nome:"Insalata mista",qt:"100g"},{nome:"Arancia",qt:"1"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Insalata di barbabietole e formaggio di capra (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:5,g:18,z:10,ch:18,fi:4.5,ca:130,fe:2,mg:35,k2:520,na:280,zn:1.5,fo:50,se:4,col:20}},{id:"tpl_1205",nome:"Tiramisù classico",nome_en:"Classic tiramisù",categoria:"Dolce",porzioni:8,note:"Montare i tuorli con lo zucchero. Aggiungere il mascarpone. Montare gli albumi a neve e incorporare. Inzuppare i savoiardi nel caffe. Alternare strati di crema e biscotti. Spolverare con cacao. Raffreddare 4 ore.",note_en:"Whisk egg yolks with sugar. Add mascarpone. Whisk egg whites stiff and fold in. Soak ladyfingers in coffee. Alternate layers of cream and biscuits. Dust with cocoa. Refrigerate 4 hours.",ingredienti:[{nome:"Mascarpone",qt:"500g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"100g"},{nome:"Savoiardi",qt:"300g"},{nome:"Caffe espresso",qt:"300ml"},{nome:"Cacao amaro",qt:"30g"}],_dbEntry:{n:"Tiramisu classico (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:10,gs:14,g:24,z:28,ch:40,fi:.5,ca:100,fe:1,mg:20,k2:150,na:120,zn:1,fo:20,se:8,col:185}},{id:"tpl_1206",nome:"Panna cotta alla vaniglia con coulis di fragole",nome_en:"Vanilla panna cotta with strawberry coulis",categoria:"Dolce",porzioni:6,note:"Scaldare panna con zucchero e vaniglia. Ammorbidire la gelatina in acqua fredda. Sciogliere nella panna calda. Versare negli stampini e raffreddare 4 ore. Preparare coulis di fragole con fragole frullate e zucchero a velo.",note_en:"Heat cream with sugar and vanilla. Soften gelatine in cold water. Dissolve in hot cream. Pour into moulds and refrigerate 4 hours. Prepare strawberry coulis with blended strawberries and icing sugar.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Zucchero",qt:"80g"},{nome:"Gelatina in fogli",qt:"10g"},{nome:"Baccello di vaniglia",qt:"1"},{nome:"Fragole",qt:"200g"},{nome:"Zucchero a velo",qt:"30g"}],_dbEntry:{n:"Panna cotta alla vaniglia con coulis di fragole (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:3,gs:12,g:18,z:22,ch:25,fi:.5,ca:80,fe:.2,mg:8,k2:120,na:30,zn:.3,fo:8,se:2,col:60}},{id:"tpl_1207",nome:"Crostata di marmellata",nome_en:"Jam tart",categoria:"Dolce",porzioni:8,note:"Impastare farina, burro freddo, zucchero, uova e scorza di limone fino a ottenere pasta frolla. Riposare 30 minuti. Stendere nella teglia imburrata. Farcire con marmellata. Decorare con strisce di pasta. Cuocere a 180 C per 35 minuti.",note_en:"Mix flour, cold butter, sugar, eggs and lemon zest to make shortcrust pastry. Rest 30 minutes. Roll into buttered tin. Fill with jam. Decorate with pastry strips. Bake at 180 C for 35 minutes.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Burro",qt:"150g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Marmellata",qt:"300g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Crostata di marmellata (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:4.5,gs:7,g:13,z:28,ch:50,fi:1,ca:30,fe:1,mg:15,k2:120,na:80,zn:.5,fo:12,se:4,col:70}},{id:"tpl_1208",nome:"Mousse al cioccolato fondente",nome_en:"Dark chocolate mousse",categoria:"Dolce",porzioni:6,note:"Sciogliere il cioccolato fondente a bagno maria. Montare gli albumi a neve. Montare la panna. Amalgamare il cioccolato tiepido con la panna montata. Incorporare gli albumi con movimenti dal basso. Raffreddare 2 ore.",note_en:"Melt dark chocolate over double boiler. Whisk egg whites stiff. Whip cream. Fold tepid chocolate into whipped cream. Fold in egg whites with bottom-to-top movements. Refrigerate 2 hours.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"200g"},{nome:"Panna fresca",qt:"250ml"},{nome:"Albumi",qt:"3"},{nome:"Zucchero",qt:"30g"}],_dbEntry:{n:"Mousse al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:5,gs:11,g:22,z:20,ch:28,fi:3,ca:40,fe:3,mg:60,k2:280,na:40,zn:1.5,fo:8,se:4,col:35}},{id:"tpl_1209",nome:"Torta di mele e cannella",nome_en:"Apple and cinnamon cake",categoria:"Dolce",porzioni:8,note:"Sbattere uova, zucchero e olio. Aggiungere farina, lievito, cannella e mele a cubetti. Versare in teglia imburrata. Cuocere in forno a 180 C per 40 minuti. Controllare con lo stecchino. Spolverare con zucchero a velo.",note_en:"Beat eggs, sugar and oil. Add flour, baking powder, cinnamon and diced apples. Pour into buttered tin. Bake at 180 C for 40 minutes. Check with toothpick. Dust with icing sugar.",ingredienti:[{nome:"Mele",qt:"4"},{nome:"Farina",qt:"250g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"100ml"},{nome:"Lievito",qt:"16g"},{nome:"Cannella",qt:"2 cucchiaini"}],_dbEntry:{n:"Torta di mele e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:4.5,gs:1.5,g:10,z:24,ch:42,fi:2,ca:30,fe:1,mg:18,k2:180,na:80,zn:.5,fo:15,se:5,col:70}},{id:"tpl_1210",nome:"Torta al cioccolato fondente",nome_en:"Dark chocolate cake",categoria:"Dolce",porzioni:8,note:"Sciogliere burro e cioccolato. Aggiungere uova, zucchero, farina e lievito. Versare in teglia. Cuocere a 180 C per 30-35 minuti. L'interno deve restare leggermente umido. Servire con ganache o zucchero a velo.",note_en:"Melt butter and chocolate. Add eggs, sugar, flour and baking powder. Pour into tin. Bake at 180 C for 30-35 minutes. Inside should remain slightly moist. Serve with ganache or icing sugar.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"200g"},{nome:"Burro",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Farina",qt:"100g"},{nome:"Lievito",qt:"8g"}],_dbEntry:{n:"Torta al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:6,gs:14,g:22,z:28,ch:42,fi:2.5,ca:40,fe:3.5,mg:55,k2:250,na:120,zn:1.5,fo:15,se:5,col:130}},{id:"tpl_1211",nome:"Cheesecake ai frutti di bosco",nome_en:"Berry cheesecake",categoria:"Dolce",porzioni:8,note:"Tritare i biscotti e mescolare con burro fuso. Pressare nella teglia. Montare formaggio spalmabile con zucchero, panna e limone. Versare sulla base. Raffreddare 6 ore. Decorare con coulis di frutti di bosco.",note_en:"Crush biscuits and mix with melted butter. Press into tin. Whip cream cheese with sugar, cream and lemon. Pour over base. Refrigerate 6 hours. Decorate with berry coulis.",ingredienti:[{nome:"Formaggio spalmabile",qt:"400g"},{nome:"Biscotti secchi",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Panna fresca",qt:"150ml"},{nome:"Zucchero",qt:"100g"},{nome:"Frutti di bosco misti",qt:"200g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Cheesecake ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:6,gs:15,g:24,z:24,ch:34,fi:1,ca:80,fe:.5,mg:12,k2:150,na:280,zn:.5,fo:10,se:3,col:75}},{id:"tpl_1212",nome:"Cannoli siciliani",nome_en:"Sicilian cannoli",categoria:"Dolce",porzioni:8,note:"Preparare la sfoglia con farina, strutto, zucchero, vino bianco e cacao. Avvolgere su cannolicchi e friggere. Mescolare ricotta setacciata con zucchero a velo, gocce di cioccolato e scorza d'arancia candita. Farcire i cannoli al momento.",note_en:"Make pastry with flour, lard, sugar, white wine and cocoa. Wrap around cannoli moulds and fry. Mix sieved ricotta with icing sugar, chocolate chips and candied orange peel. Fill cannoli at time of serving.",ingredienti:[{nome:"Ricotta di pecora",qt:"500g"},{nome:"Zucchero a velo",qt:"120g"},{nome:"Gocce di cioccolato",qt:"60g"},{nome:"Farina",qt:"300g"},{nome:"Strutto",qt:"30g"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Cannoli siciliani (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:10,gs:8,g:14,z:22,ch:48,fi:1,ca:150,fe:1,mg:25,k2:150,na:80,zn:1,fo:12,se:6,col:45}},{id:"tpl_1213",nome:"Semifreddo al pistacchio",nome_en:"Pistachio semifreddo",categoria:"Dolce",porzioni:8,note:"Montare tuorli con zucchero. Montare panna. Tritare i pistacchi finemente. Amalgamare tutto delicatamente. Versare in stampo foderato con pellicola. Congelare almeno 6 ore. Servire con salsa di cioccolato bianco.",note_en:"Whisk egg yolks with sugar. Whip cream. Finely chop pistachios. Fold everything together gently. Pour into cling-film-lined mould. Freeze at least 6 hours. Serve with white chocolate sauce.",ingredienti:[{nome:"Pistacchi non salati",qt:"100g"},{nome:"Tuorli",qt:"4"},{nome:"Zucchero",qt:"100g"},{nome:"Panna fresca",qt:"300ml"},{nome:"Cioccolato bianco",qt:"80g"}],_dbEntry:{n:"Semifreddo al pistacchio (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:8,gs:14,g:28,z:28,ch:32,fi:1.5,ca:90,fe:1.5,mg:40,k2:320,na:40,zn:1.5,fo:12,se:4,col:180}},{id:"tpl_1214",nome:"Torta di carote e mandorle",nome_en:"Carrot and almond cake",categoria:"Dolce",porzioni:8,note:"Mescolare carote grattugiate, farina di mandorle, uova, zucchero, olio e lievito. Versare in teglia. Cuocere a 180 C per 35 minuti. Naturalmente umida e ricca di fibre. Spolverare con zucchero a velo e decorare con mandorle.",note_en:"Mix grated carrots, almond flour, eggs, sugar, oil and baking powder. Pour into tin. Bake at 180 C for 35 minutes. Naturally moist and fibre-rich. Dust with icing sugar and decorate with almonds.",ingredienti:[{nome:"Carote",qt:"300g"},{nome:"Farina di mandorle",qt:"200g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"120g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito",qt:"10g"},{nome:"Mandorle intere",qt:"40g"}],_dbEntry:{n:"Torta di carote e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:2.5,g:18,z:20,ch:30,fi:4,ca:80,fe:2,mg:55,k2:320,na:60,zn:1.2,fo:18,se:5,col:70}},{id:"tpl_1215",nome:"Granita al limone siciliana",nome_en:"Sicilian lemon granita",categoria:"Dolce",porzioni:6,note:"Sciogliere lo zucchero in acqua calda. Raffreddare. Aggiungere succo e scorza di limoni non trattati. Versare in contenitore basso e congelare. Ogni 30 minuti grattare con forchetta per formare i cristalli. Servire con brioche.",note_en:"Dissolve sugar in hot water. Cool. Add juice and zest of untreated lemons. Pour into shallow container and freeze. Every 30 minutes scrape with fork to form crystals. Serve with brioche.",ingredienti:[{nome:"Limoni non trattati",qt:"6"},{nome:"Zucchero",qt:"150g"},{nome:"Acqua",qt:"500ml"}],_dbEntry:{n:"Granita al limone siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:.2,gs:0,g:0,z:22,ch:28,fi:.5,ca:8,fe:.1,mg:5,k2:55,na:2,zn:.05,fo:5,se:0,col:0}},{id:"tpl_1216",nome:"Porridge di avena con frutti di bosco",nome_en:"Oat porridge with berries",categoria:"Colazione",porzioni:2,note:"Cuocere i fiocchi di avena con latte o acqua per 5-7 minuti mescolando. Aggiustare la consistenza con altro liquido. Servire in ciotola con frutti di bosco freschi, miele, semi di chia e noci. Proteico e nutriente.",note_en:"Cook oats with milk or water for 5-7 minutes stirring. Adjust consistency with more liquid. Serve in bowl with fresh berries, honey, chia seeds and walnuts. Protein-rich and nutritious.",ingredienti:[{nome:"Fiocchi di avena",qt:"80g"},{nome:"Latte",qt:"300ml"},{nome:"Frutti di bosco misti",qt:"100g"},{nome:"Miele",qt:"20ml"},{nome:"Semi di chia",qt:"10g"},{nome:"Noci",qt:"20g"}],_dbEntry:{n:"Porridge di avena con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:2.5,g:11,z:18,ch:54,fi:7,ca:220,fe:3,mg:75,k2:480,na:80,zn:2,fo:32,se:8,col:12}},{id:"tpl_1217",nome:"Toast con avocado e uova in camicia",nome_en:"Avocado toast with poached eggs",categoria:"Colazione",porzioni:2,note:"Tostare il pane integrale. Schiacciare l'avocado maturo con limone, sale e pepe. Cuocere le uova in camicia in acqua con aceto. Spalmare l'avocado sul pane. Adagiare le uova in camicia. Condire con peperoncino e semi di sesamo.",note_en:"Toast wholegrain bread. Mash ripe avocado with lemon, salt and pepper. Poach eggs in water with vinegar. Spread avocado on bread. Place poached eggs on top. Season with chilli and sesame seeds.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Limone",qt:"0.5"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Aceto di vino",qt:"20ml"}],_dbEntry:{n:"Toast con avocado e uova in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:4,g:22,z:2,ch:30,fi:9,ca:80,fe:3.5,mg:55,k2:620,na:280,zn:2,fo:120,se:20,col:185}},{id:"tpl_1218",nome:"Yogurt greco con granola e frutta fresca",nome_en:"Greek yogurt with granola and fresh fruit",categoria:"Colazione",porzioni:2,note:"Tostare fiocchi di avena con miele, noci e semi in forno a 160 C per 20 minuti. Raffreddare. Servire con yogurt greco, granola croccante e frutta fresca di stagione. Ricco di proteine e probiotici.",note_en:"Toast oats with honey, nuts and seeds in oven at 160 C for 20 minutes. Cool. Serve with Greek yogurt, crunchy granola and fresh seasonal fruit. Rich in protein and probiotics.",ingredienti:[{nome:"Yogurt greco intero",qt:"300g"},{nome:"Fiocchi di avena",qt:"60g"},{nome:"Miele",qt:"25ml"},{nome:"Noci miste",qt:"30g"},{nome:"Frutta fresca di stagione",qt:"200g"}],_dbEntry:{n:"Yogurt greco con granola e frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:18,gs:3,g:12,z:22,ch:48,fi:4,ca:200,fe:2,mg:55,k2:520,na:80,zn:2,fo:28,se:8,col:15}},{id:"tpl_1219",nome:"Frittata alle erbe e verdure",nome_en:"Herb and vegetable frittata",categoria:"Colazione",porzioni:4,note:"Sbattere le uova con sale, pepe e erbe aromatiche. Soffriggere cipolla e verdure a dadini. Versare le uova sulle verdure. Cuocere coperto a fuoco lento 8 minuti. Gratinare sotto il grill 3 minuti. Ottima calda o fredda.",note_en:"Beat eggs with salt, pepper and herbs. Sauté onion and diced vegetables. Pour eggs over vegetables. Cook covered on low heat 8 minutes. Grill under broiler 3 minutes. Excellent hot or cold.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Prezzemolo",qt:"15g"},{nome:"Basilico",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Frittata alle erbe e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:14,gs:3.5,g:13,z:3,ch:6,fi:2,ca:80,fe:2.5,mg:28,k2:350,na:200,zn:1.5,fo:55,se:22,col:280}},{id:"tpl_1220",nome:"Chia pudding alla vaniglia",nome_en:"Vanilla chia pudding",categoria:"Colazione",porzioni:2,note:"Mescolare semi di chia con latte vegetale, miele e vaniglia. Lasciare riposare in frigorifero tutta la notte mescolando dopo 30 minuti. Al mattino il pudding e pronto. Servire con frutta fresca e sciroppo d'acero.",note_en:"Mix chia seeds with plant milk, honey and vanilla. Rest in fridge overnight stirring after 30 minutes. In the morning pudding is ready. Serve with fresh fruit and maple syrup.",ingredienti:[{nome:"Semi di chia",qt:"50g"},{nome:"Latte di mandorla",qt:"300ml"},{nome:"Miele",qt:"20ml"},{nome:"Vaniglia",qt:"0.5 cucchiaino"},{nome:"Frutta mista",qt:"100g"}],_dbEntry:{n:"Chia pudding alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:1.5,g:12,z:14,ch:32,fi:12,ca:280,fe:4,mg:90,k2:320,na:60,zn:2,fo:22,se:15,col:0}},{id:"tpl_1221",nome:"Banana bread integrale con noci",nome_en:"Wholegrain banana bread with walnuts",categoria:"Colazione",porzioni:8,note:"Schiacciare le banane mature. Mescolare con uova, olio, miele e vaniglia. Aggiungere farina integrale, lievito e bicarbonato. Incorporare le noci tritate. Cuocere in stampo da plum cake a 175 C per 60 minuti.",note_en:"Mash ripe bananas. Mix with eggs, oil, honey and vanilla. Add wholemeal flour, baking powder and bicarbonate. Fold in chopped walnuts. Bake in loaf tin at 175 C for 60 minutes.",ingredienti:[{nome:"Banane mature",qt:"3"},{nome:"Farina integrale",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60ml"},{nome:"Noci",qt:"60g"},{nome:"Lievito",qt:"10g"}],_dbEntry:{n:"Banana bread integrale con noci (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:1.5,g:11,z:16,ch:40,fi:4,ca:30,fe:1.5,mg:38,k2:320,na:80,zn:1,fo:20,se:8,col:45}},{id:"tpl_1222",nome:"Energy balls con datteri e cacao",nome_en:"Energy balls with dates and cocoa",categoria:"Spuntino",porzioni:4,note:"Frullare datteri denocciolati con mandorle, cacao, cocco rapato e un pizzico di sale. L'impasto deve essere appiccicoso. Formare palline. Rotolare nel cocco rapato. Conservare in frigorifero.",note_en:"Blend pitted dates with almonds, cocoa, desiccated coconut and pinch of salt. Mixture should be sticky. Shape into balls. Roll in desiccated coconut. Store in fridge.",ingredienti:[{nome:"Datteri Medjool",qt:"200g"},{nome:"Mandorle",qt:"100g"},{nome:"Cacao amaro",qt:"30g"},{nome:"Cocco rapato",qt:"40g"}],_dbEntry:{n:"Energy balls con datteri e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4.5,gs:3,g:8,z:20,ch:24,fi:4,ca:40,fe:1.5,mg:42,k2:280,na:5,zn:.8,fo:8,se:2,col:0}},{id:"tpl_1223",nome:"Hummus classico con crudité",nome_en:"Classic hummus with crudités",categoria:"Spuntino",porzioni:6,note:"Frullare ceci cotti con tahini, aglio, succo di limone, olio e sale fino a crema liscia. Aggiungere acqua fredda per ammorbidire. Servire con bastoncini di carota, sedano, cetriolo e peperoni.",note_en:"Blend cooked chickpeas with tahini, garlic, lemon juice, oil and salt until smooth cream. Add cold water to soften. Serve with sticks of carrot, celery, cucumber and peppers.",ingredienti:[{nome:"Ceci cotti",qt:"400g"},{nome:"Tahini",qt:"60g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Carote",qt:"2"},{nome:"Cetriolo",qt:"1"},{nome:"Peperoni",qt:"1"}],_dbEntry:{n:"Hummus classico con crudite (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:8,gs:1.5,g:10,z:3,ch:20,fi:7,ca:65,fe:2.5,mg:55,k2:480,na:180,zn:1.5,fo:100,se:5,col:0}},{id:"tpl_1224",nome:"Smoothie bowl verde con banana e spinaci",nome_en:"Green smoothie bowl with banana and spinach",categoria:"Colazione",porzioni:2,note:"Frullare spinaci baby, banana congelata, latte di cocco e proteine in polvere. Versare in ciotola. Decorare con fette di banana fresca, mirtilli, semi di canapa, granola e filo di miele. Consumare subito.",note_en:"Blend baby spinach, frozen banana, coconut milk and protein powder. Pour into bowl. Decorate with fresh banana slices, blueberries, hemp seeds, granola and drizzle of honey. Consume immediately.",ingredienti:[{nome:"Spinaci baby",qt:"60g"},{nome:"Banana congelata",qt:"2"},{nome:"Latte di cocco",qt:"100ml"},{nome:"Mirtilli",qt:"80g"},{nome:"Granola",qt:"30g"},{nome:"Semi di canapa",qt:"15g"},{nome:"Miele",qt:"15ml"}],_dbEntry:{n:"Smoothie bowl verde con banana e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:8,gs:5,g:10,z:28,ch:52,fi:7,ca:80,fe:2.5,mg:62,k2:680,na:60,zn:1.5,fo:80,se:4,col:0}},{id:"tpl_1225",nome:"Crema di zucca e zenzero",nome_en:"Pumpkin and ginger cream soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere zucca a cubetti, zenzero grattugiato e brodo vegetale. Cuocere 25 minuti. Frullare fino a crema liscia. Aggiustare di sale. Servire con panna acida, semi di zucca tostati e olio al peperoncino.",note_en:"Sauté onion in oil. Add diced pumpkin, grated ginger and vegetable stock. Cook 25 minutes. Blend until smooth cream. Season with salt. Serve with sour cream, toasted pumpkin seeds and chilli oil.",ingredienti:[{nome:"Zucca",qt:"800g"},{nome:"Zenzero fresco",qt:"25g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Panna acida",qt:"60g"},{nome:"Semi di zucca",qt:"20g"}],_dbEntry:{n:"Crema di zucca e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4.5,gs:3,g:9,z:6,ch:20,fi:3,ca:60,fe:1.5,mg:35,k2:580,na:280,zn:.8,fo:35,se:3,col:10}},{id:"tpl_1226",nome:"Zuppa di patate e porro",nome_en:"Potato and leek soup",categoria:"Zuppa",porzioni:4,note:"Stufare i porri affettati in burro. Aggiungere patate a cubetti e brodo. Cuocere 25 minuti. Frullare meta della zuppa per darle cremosita mantenendo pezzi. Aggiungere panna e servire con crostini e erba cipollina.",note_en:"Stew sliced leeks in butter. Add diced potatoes and stock. Cook 25 minutes. Blend half the soup for creaminess while keeping chunks. Add cream and serve with croutons and chives.",ingredienti:[{nome:"Porri",qt:"400g"},{nome:"Patate",qt:"500g"},{nome:"Burro",qt:"30g"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Zuppa di patate e porro (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4.5,gs:4,g:8,z:4,ch:32,fi:4,ca:70,fe:1.5,mg:35,k2:620,na:280,zn:.8,fo:45,se:3,col:25}},{id:"tpl_1227",nome:"Acquacotta maremmana",nome_en:"Maremma acquacotta",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, sedano, pomodori e peperoncino in olio. Aggiungere acqua e cuocere 30 minuti. Versare sulla zuppa due uova per persona: si cuociono direttamente nella zuppa calda. Servire su pane tostato sfregato con aglio.",note_en:"Sauté onion, celery, tomatoes and chilli in oil. Add water and cook 30 minutes. Break two eggs per person directly into hot soup to cook. Serve on toasted bread rubbed with garlic.",ingredienti:[{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"3 coste"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Uova",qt:"4"},{nome:"Pane casereccio",qt:"4 fette"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Acquacotta maremmana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:12,gs:3,g:14,z:5,ch:24,fi:3,ca:65,fe:2.5,mg:30,k2:420,na:320,zn:1.2,fo:45,se:15,col:185}},{id:"tpl_1228",nome:"Zuppa di cipolla alla francese",nome_en:"French onion soup",categoria:"Zuppa",porzioni:4,note:"Caramellare lentamente le cipolle affettate in burro per 45 minuti. Sfumare con vino bianco e brandy. Aggiungere brodo di carne. Cuocere 20 minuti. Versare in ciotole da forno. Coprire con pane tostato e gruviera. Gratinare.",note_en:"Slowly caramelise sliced onions in butter for 45 minutes. Deglaze with white wine and brandy. Add beef stock. Cook 20 minutes. Pour into oven bowls. Cover with toasted bread and gruyère. Gratinate.",ingredienti:[{nome:"Cipolle",qt:"1kg"},{nome:"Burro",qt:"50g"},{nome:"Brodo di carne",qt:"1L"},{nome:"Vino bianco",qt:"150ml"},{nome:"Pane baguette",qt:"4 fette"},{nome:"Gruviera",qt:"120g"}],_dbEntry:{n:"Zuppa di cipolla alla francese (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:7,g:14,z:8,ch:30,fi:3,ca:280,fe:1.5,mg:30,k2:380,na:480,zn:2,fo:22,se:8,col:45}},{id:"tpl_1229",nome:"Crema di piselli alla menta",nome_en:"Pea cream with mint",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere piselli surgelati e brodo. Cuocere 10 minuti. Frullare con foglie di menta fresca, succo di limone e olio. Servire calda o fredda con uno spoon di panna acida e menta.",note_en:"Sauté onion in oil. Add frozen peas and stock. Cook 10 minutes. Blend with fresh mint leaves, lemon juice and oil. Serve hot or cold with a spoonful of sour cream and mint.",ingredienti:[{nome:"Piselli surgelati",qt:"500g"},{nome:"Cipolla",qt:"1"},{nome:"Menta fresca",qt:"20g"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"},{nome:"Panna acida",qt:"60g"}],_dbEntry:{n:"Crema di piselli alla menta (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:10,gs:2,g:7,z:6,ch:22,fi:8,ca:45,fe:2.5,mg:42,k2:480,na:220,zn:1.2,fo:80,se:3,col:10}},{id:"tpl_1230",nome:"Jota triestina con crauti e fagioli",nome_en:"Triestine jota with sauerkraut and beans",categoria:"Zuppa",porzioni:6,note:"Soffriggere lardo e aglio. Aggiungere fagioli borlotti, crauti, patate e brodo. Cuocere 45 minuti. Aggiustare con un cucchiaio di farina per addensare. La jota deve risultare densa e saporita. Servire calda con pancetta croccante.",note_en:"Sauté lard and garlic. Add borlotti beans, sauerkraut, potatoes and stock. Cook 45 minutes. Adjust with a spoonful of flour to thicken. Jota should be thick and flavourful. Serve hot with crispy bacon.",ingredienti:[{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Crauti",qt:"300g"},{nome:"Patate",qt:"200g"},{nome:"Lardo",qt:"60g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Brodo",qt:"800ml"},{nome:"Farina",qt:"20g"}],_dbEntry:{n:"Jota triestina con crauti e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:14,gs:4,g:10,z:3,ch:36,fi:10,ca:65,fe:3,mg:55,k2:680,na:620,zn:2,fo:100,se:5,col:18}},{id:"tpl_1231",nome:"Crema di carote allo zenzero e arancia",nome_en:"Carrot cream with ginger and orange",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere carote a rondelle, zenzero grattugiato e succo di arancia. Versare brodo e cuocere 25 minuti. Frullare. Regolare di sale. Guarnire con creme fraiche e semi di sesamo tostati.",note_en:"Sauté onion in oil. Add sliced carrots, grated ginger and orange juice. Pour in stock and cook 25 minutes. Blend. Season with salt. Garnish with crème fraîche and toasted sesame seeds.",ingredienti:[{nome:"Carote",qt:"700g"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Arancia",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Creme fraiche",qt:"40g"}],_dbEntry:{n:"Crema di carote allo zenzero e arancia (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:3,gs:2,g:7,z:10,ch:20,fi:4.5,ca:55,fe:1,mg:20,k2:520,na:220,zn:.5,fo:30,se:2,col:8}},{id:"tpl_1232",nome:"Stracciatella romana",nome_en:"Roman egg-drop soup",categoria:"Zuppa",porzioni:4,note:"Portare a bollore il brodo di carne. Sbattere uova con parmigiano, sale e noce moscata. Versare il composto a filo nel brodo bollente mescolando. Le uova si raggrinziscono formando i caratteristici fiocchi. Servire con parmigiano.",note_en:"Bring meat stock to boil. Beat eggs with parmesan, salt and nutmeg. Pour mixture in a thin stream into boiling stock while stirring. Eggs curdle forming characteristic flakes. Serve with parmesan.",ingredienti:[{nome:"Brodo di carne",qt:"1L"},{nome:"Uova",qt:"3"},{nome:"Parmigiano",qt:"60g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Stracciatella romana (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:14,gs:4,g:10,z:.5,ch:4,fi:0,ca:180,fe:1.5,mg:18,k2:220,na:380,zn:1.5,fo:15,se:15,col:185}},{id:"tpl_1233",nome:"Minestrone estivo di verdure fresche",nome_en:"Summer fresh vegetable minestrone",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla e aglio in olio. Aggiungere zucchine, fagiolini, pomodori, mais e brodo. Cuocere 20 minuti. Aggiungere pasta corta o riso. Servire tiepido con abbondante basilico e parmigiano.",note_en:"Sauté onion and garlic in oil. Add courgettes, green beans, tomatoes, corn and stock. Cook 20 minutes. Add short pasta or rice. Serve warm with plenty of basil and parmesan.",ingredienti:[{nome:"Zucchine",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Mais",qt:"100g"},{nome:"Pasta corta",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Basilico",qt:"20g"}],_dbEntry:{n:"Minestrone estivo di verdure fresche (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:7,gs:1,g:5,z:5,ch:32,fi:5.5,ca:50,fe:1.5,mg:40,k2:520,na:280,zn:.8,fo:50,se:4,col:0}},{id:"tpl_1234",nome:"Brodetto di pesce marchigiano",nome_en:"Marche-style fish brodetto",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e aglio in olio. Aggiungere passata di pomodoro e aceto bianco. Cuocere 10 minuti. Aggiungere pesce misto a pezzi nell'ordine di cottura: prima i molluschi, poi il pesce. Cuocere 20 minuti. Servire su pane abbrustolito.",note_en:"Sauté onion and garlic in oil. Add tomato passata and white vinegar. Cook 10 minutes. Add mixed fish pieces in order of cooking: molluscs first, then fish. Cook 20 minutes. Serve on toasted bread.",ingredienti:[{nome:"Pesce misto da zuppa",qt:"1kg"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Aceto bianco",qt:"30ml"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Pane casereccio",qt:"4 fette"}],_dbEntry:{n:"Brodetto di pesce marchigiano (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:30,gs:2.5,g:10,z:5,ch:18,fi:2,ca:80,fe:2.5,mg:55,k2:620,na:480,zn:2,fo:28,se:45,col:95}},{id:"tpl_1235",nome:"Zuppa di miso con tofu e wakame",nome_en:"Miso soup with tofu and wakame",categoria:"Zuppa",porzioni:4,note:"Preparare il dashi con kombu e katsuobushi. Filtrare. Sciogliere il miso nel dashi tiepido (non bollire il miso). Aggiungere tofu a cubetti, alghe wakame reidratate e cipollotto affettato. Servire subito.",note_en:"Prepare dashi with kombu and bonito flakes. Strain. Dissolve miso in warm dashi (do not boil miso). Add diced tofu, rehydrated wakame seaweed and sliced spring onion. Serve immediately.",ingredienti:[{nome:"Miso bianco",qt:"60g"},{nome:"Tofu sodo",qt:"200g"},{nome:"Alghe wakame secche",qt:"10g"},{nome:"Cipollotto",qt:"3"},{nome:"Kombu",qt:"10g"},{nome:"Katsuobushi",qt:"15g"}],_dbEntry:{n:"Zuppa di miso con tofu e wakame (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:8,gs:.5,g:3,z:2,ch:10,fi:2,ca:80,fe:2,mg:45,k2:320,na:780,zn:1.2,fo:25,se:5,col:0}},{id:"tpl_1236",nome:"Crema di asparagi con uovo in camicia",nome_en:"Asparagus cream with poached egg",categoria:"Zuppa",porzioni:4,note:"Lessare gli asparagi 10 minuti tenendo le punte. Frullare i gambi con brodo, scalogno stufato e panna. Setacciare. Aggiustare di sale. Servire la crema con una punta di asparago e un uovo in camicia al centro.",note_en:"Boil asparagus 10 minutes keeping tips. Blend stems with stock, stewed shallot and cream. Strain. Season with salt. Serve cream with an asparagus tip and a poached egg in the centre.",ingredienti:[{nome:"Asparagi",qt:"700g"},{nome:"Scalogno",qt:"2"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Uova",qt:"4"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Crema di asparagi con uovo in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:12,gs:4,g:12,z:4,ch:12,fi:4,ca:70,fe:3.5,mg:30,k2:450,na:250,zn:1.5,fo:150,se:18,col:185}},{id:"tpl_1237",nome:"Lombata di maiale alla griglia con salsa verde",nome_en:"Grilled pork loin with green sauce",categoria:"Secondo piatto",porzioni:4,note:"Condire le fettine di lombata con olio, aglio, timo e pepe. Grigliare su piastra caldissima 3-4 minuti per lato. Preparare salsa verde con prezzemolo, acciughe, capperi, aglio, olio e aceto. Servire la carne nappata di salsa.",note_en:"Season pork loin slices with oil, garlic, thyme and pepper. Grill on very hot griddle 3-4 minutes per side. Make green sauce with parsley, anchovies, capers, garlic, oil and vinegar. Serve meat topped with sauce.",ingredienti:[{nome:"Lombata di maiale",qt:"600g"},{nome:"Prezzemolo",qt:"50g"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Aceto di vino",qt:"20ml"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Lombata di maiale alla griglia con salsa verde (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:30,gs:4,g:18,z:.5,ch:2,fi:.5,ca:35,fe:1.8,mg:32,k2:480,na:380,zn:3,fo:15,se:22,col:85}},{id:"tpl_1238",nome:"Spiedini di pollo e verdure",nome_en:"Chicken and vegetable skewers",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il petto di pollo a cubetti. Alternare su spiedini con peperone, zucchine, cipolla e pomodorini. Marinare con olio, limone, aglio e origano 1 ora. Cuocere su griglia o in forno 20 minuti rigirando.",note_en:"Cut chicken breast into cubes. Alternate on skewers with pepper, courgettes, onion and cherry tomatoes. Marinate with oil, lemon, garlic and oregano 1 hour. Cook on grill or in oven 20 minutes turning.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Peperone",qt:"2"},{nome:"Zucchine",qt:"2"},{nome:"Cipolla rossa",qt:"2"},{nome:"Pomodorini",qt:"12"},{nome:"Limone",qt:"1"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Spiedini di pollo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:30,gs:1.5,g:9,z:5,ch:10,fi:3,ca:35,fe:1.5,mg:40,k2:620,na:180,zn:2,fo:35,se:22,col:80}},{id:"tpl_1239",nome:"Hamburger di manzo artigianale",nome_en:"Artisan beef burger",categoria:"Secondo piatto",porzioni:4,note:"Mescolare manzo macinato con sale e pepe. Formare 4 hamburger da 150g. Cuocere su piastra caldissima 4 minuti per lato. Servire su panino con lattuga, pomodoro, cipolla rossa, cetrioli e salse a scelta.",note_en:"Mix minced beef with salt and pepper. Shape 4 burgers of 150g each. Cook on very hot griddle 4 minutes per side. Serve in bun with lettuce, tomato, red onion, gherkins and chosen sauces.",ingredienti:[{nome:"Macinato di manzo (20% grasso)",qt:"600g"},{nome:"Panini per hamburger",qt:"4"},{nome:"Lattuga",qt:"80g"},{nome:"Pomodoro",qt:"2"},{nome:"Cipolla rossa",qt:"1"},{nome:"Cetriolini",qt:"4"},{nome:"Cheddar",qt:"4 fette"}],_dbEntry:{n:"Hamburger di manzo artigianale (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:36,gs:10,g:28,z:6,ch:44,fi:2,ca:180,fe:4,mg:40,k2:500,na:720,zn:6,fo:30,se:22,col:110}},{id:"tpl_1240",nome:"Coscia di pollo ripiena al forno",nome_en:"Stuffed chicken leg baked",categoria:"Secondo piatto",porzioni:4,note:"Disossare le cosce di pollo. Farcire con spinaci saltati, ricotta, parmigiano e noce moscata. Richiudere e legare. Cuocere in forno a 190 C per 35-40 minuti. Servire con sugo del fondo di cottura.",note_en:"Debone chicken legs. Fill with sautéed spinach, ricotta, parmesan and nutmeg. Close and tie. Bake at 190 C for 35-40 minutes. Serve with cooking juice sauce.",ingredienti:[{nome:"Cosce di pollo disossate",qt:"4"},{nome:"Spinaci",qt:"200g"},{nome:"Ricotta",qt:"150g"},{nome:"Parmigiano",qt:"40g"},{nome:"Noce moscata",qt:"q.b."},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Coscia di pollo ripiena al forno (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:34,gs:6,g:18,z:2,ch:3,fi:1.5,ca:130,fe:2,mg:35,k2:480,na:280,zn:3,fo:30,se:28,col:120}},{id:"tpl_1241",nome:"Coda alla vaccinara",nome_en:"Roman oxtail in tomato sauce",categoria:"Secondo piatto",porzioni:6,note:"Rosolare i pezzi di coda con soffritto di cipolla, carota, sedano. Sfumare con vino bianco. Aggiungere pomodori, uvetta, pinoli, cacao e cannella. Cuocere 3 ore a fuoco lentissimo. Piatto della tradizione romana.",note_en:"Brown oxtail pieces with onion, carrot, celery soffritto. Deglaze with white wine. Add tomatoes, raisins, pine nuts, cocoa and cinnamon. Cook 3 hours on very low heat. Traditional Roman dish.",ingredienti:[{nome:"Coda di bue",qt:"1.5kg"},{nome:"Pomodori pelati",qt:"500g"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Cacao amaro",qt:"20g"},{nome:"Cannella",qt:"0.5 cucchiaino"},{nome:"Sedano",qt:"3 coste"},{nome:"Vino bianco",qt:"150ml"}],_dbEntry:{n:"Coda alla vaccinara (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:40,gs:5,g:18,z:7,ch:12,fi:3,ca:50,fe:4,mg:45,k2:650,na:420,zn:7,fo:22,se:28,col:115}},{id:"tpl_1242",nome:"Trippa alla romana",nome_en:"Roman-style tripe",categoria:"Secondo piatto",porzioni:4,note:"Lessare la trippa precotta 30 minuti. Soffriggere cipolla, aglio e peperoncino. Aggiungere trippa tagliata, pomodori e menta. Cuocere 30 minuti. Spolverare con pecorino romano abbondante. Piatto tipico della tradizione romanesca.",note_en:"Boil pre-cooked tripe 30 minutes. Sauté onion, garlic and chilli. Add sliced tripe, tomatoes and mint. Cook 30 minutes. Generously sprinkle with pecorino romano. Typical Roman tradition dish.",ingredienti:[{nome:"Trippa precotta",qt:"800g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Pecorino romano",qt:"80g"},{nome:"Menta",qt:"15g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Trippa alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:28,gs:5,g:14,z:5,ch:10,fi:2,ca:160,fe:2,mg:22,k2:380,na:520,zn:3.5,fo:12,se:20,col:130}},{id:"tpl_1243",nome:"Arista di maiale in porchetta",nome_en:"Pork loin in porchetta style",categoria:"Secondo piatto",porzioni:6,note:"Aprire la lonza a libro. Cospargere internamente con aglio, rosmarino, finocchietto selvatico, sale e pepe. Arrotolare e legare. Cuocere in forno a 160 C per 2 ore. La cotenna deve risultare croccante.",note_en:"Open pork loin like a book. Sprinkle inside with garlic, rosemary, wild fennel, salt and pepper. Roll and tie. Bake at 160 C for 2 hours. Skin should be crispy.",ingredienti:[{nome:"Lonza di maiale con cotenna",qt:"1.2kg"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Rosmarino",qt:"4 rametti"},{nome:"Finocchietto selvatico",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Arista di maiale in porchetta (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:35,gs:5,g:18,z:0,ch:1,fi:.3,ca:22,fe:1.5,mg:32,k2:500,na:300,zn:3.5,fo:8,se:28,col:100}},{id:"tpl_1244",nome:"Baccalà fritto in pastella alla birra",nome_en:"Beer-battered salt cod",categoria:"Secondo piatto",porzioni:4,note:"Dissalare il baccalà. Preparare pastella con farina, birra fredda, sale e pepe fino a consistenza cremosa. Passare il baccalà nella pastella. Friggere in olio a 180 C finche dorato e croccante. Servire con maionese e limone.",note_en:"Desalt cod. Make batter with flour, cold beer, salt and pepper to creamy consistency. Coat cod in batter. Fry in oil at 180 C until golden and crispy. Serve with mayonnaise and lemon.",ingredienti:[{nome:"Baccalà ammollato",qt:"600g"},{nome:"Farina 00",qt:"150g"},{nome:"Birra chiara",qt:"200ml"},{nome:"Olio per friggere",qt:"500ml"},{nome:"Limone",qt:"2"},{nome:"Maionese",qt:"80g"}],_dbEntry:{n:"Baccalà fritto in pastella alla birra (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:26,gs:4,g:20,z:1,ch:22,fi:.5,ca:40,fe:1.2,mg:38,k2:480,na:580,zn:1.2,fo:12,se:35,col:75}},{id:"tpl_1245",nome:"Cernia al forno con verdure mediterranee",nome_en:"Grouper baked with Mediterranean vegetables",categoria:"Secondo piatto",porzioni:4,note:"Disporre filetti di cernia in teglia con zucchine, pomodorini, olive e capperi. Condire con olio, aglio, origano e vino bianco. Cuocere in forno a 190 C per 25 minuti. Piatto completo e leggero.",note_en:"Arrange grouper fillets in baking dish with courgettes, cherry tomatoes, olives and capers. Season with oil, garlic, oregano and white wine. Bake at 190 C for 25 minutes. Complete and light dish.",ingredienti:[{nome:"Filetti di cernia",qt:"700g"},{nome:"Zucchine",qt:"200g"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cernia al forno con verdure mediterranee (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:30,gs:1.5,g:10,z:4,ch:8,fi:3,ca:50,fe:1.5,mg:45,k2:680,na:380,zn:1.5,fo:22,se:42,col:70}},{id:"tpl_1246",nome:"Scampi alla busara",nome_en:"Scampi alla busara",categoria:"Secondo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in olio. Aggiungere passata di pomodoro e vino bianco. Cuocere 10 minuti. Aggiungere gli scampi. Cuocere 8 minuti. Gli scampi devono risultare rossi e succulenti. Servire con polenta bianca o pane.",note_en:"Sauté garlic and chilli in oil. Add tomato passata and white wine. Cook 10 minutes. Add scampi. Cook 8 minutes. Scampi should be red and succulent. Serve with white polenta or bread.",ingredienti:[{nome:"Scampi",qt:"1kg"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Scampi alla busara (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:24,gs:1.5,g:9,z:4,ch:8,fi:1.5,ca:80,fe:2.5,mg:50,k2:550,na:580,zn:2,fo:18,se:40,col:145}},{id:"tpl_1247",nome:"Capesante gratinate con pancetta",nome_en:"Scallops gratin with bacon",categoria:"Secondo piatto",porzioni:4,note:"Disporre le capesante nelle mezze valve. Cospargere con pangrattato, prezzemolo, aglio e olio. Aggiungere una fettina di pancetta su ogni capasanta. Gratinare sotto il grill 5-6 minuti finche dorato.",note_en:"Place scallops in half shells. Sprinkle with breadcrumbs, parsley, garlic and oil. Add a slice of bacon on each scallop. Gratinate under grill 5-6 minutes until golden.",ingredienti:[{nome:"Capesante",qt:"12"},{nome:"Pancetta affumicata",qt:"80g"},{nome:"Pangrattato",qt:"40g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Capesante gratinate con pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:3,g:10,z:1,ch:8,fi:.5,ca:30,fe:1,mg:42,k2:420,na:480,zn:2.5,fo:15,se:25,col:55}},{id:"tpl_1248",nome:"Asparagi alla piastra con uova e parmigiano",nome_en:"Griddled asparagus with eggs and parmesan",categoria:"Contorno",porzioni:4,note:"Pulire gli asparagi e togliere la parte dura. Condire con olio e sale. Cuocere su piastra calda 8-10 minuti rigirando. Disporre su piatto con uova sode affettate, scaglie di parmigiano e vinaigrette al limone.",note_en:"Clean asparagus and remove tough ends. Season with oil and salt. Cook on hot griddle 8-10 minutes turning. Arrange on plate with sliced hard-boiled eggs, parmesan shavings and lemon vinaigrette.",ingredienti:[{nome:"Asparagi verdi",qt:"600g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano a scaglie",qt:"50g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Asparagi alla piastra con uova e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:12,gs:3,g:10,z:2,ch:5,fi:4,ca:120,fe:3.5,mg:32,k2:400,na:200,zn:1.5,fo:130,se:15,col:95}},{id:"tpl_1249",nome:"Topinambur arrosto con rosmarino",nome_en:"Roasted Jerusalem artichoke with rosemary",categoria:"Contorno",porzioni:4,note:"Lavare e tagliare i topinambur a spicchi senza sbucciarli. Condire con olio, rosmarino, aglio e sale. Cuocere in forno a 200 C per 30-35 minuti finche dorati e caramellati.",note_en:"Wash and cut Jerusalem artichokes into wedges without peeling. Season with oil, rosemary, garlic and salt. Bake at 200 C for 30-35 minutes until golden and caramelised.",ingredienti:[{nome:"Topinambur",qt:"700g"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"35ml"}],_dbEntry:{n:"Topinambur arrosto con rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:3,gs:1.5,g:8,z:3,ch:16,fi:3,ca:20,fe:3,mg:20,k2:440,na:8,zn:.5,fo:15,se:1,col:0}},{id:"tpl_1250",nome:"Piselli alla menta e pancetta",nome_en:"Peas with mint and bacon",categoria:"Contorno",porzioni:4,note:"Rosolare la pancetta a cubetti in padella. Aggiungere i piselli freschi o surgelati con un mestolo di brodo. Cuocere 8 minuti. Aggiungere menta fresca e un filo di olio crudo. Semplice e gustoso.",note_en:"Brown diced bacon in pan. Add fresh or frozen peas with a ladle of stock. Cook 8 minutes. Add fresh mint and a drizzle of raw oil. Simple and tasty.",ingredienti:[{nome:"Piselli",qt:"500g"},{nome:"Pancetta",qt:"80g"},{nome:"Menta fresca",qt:"10g"},{nome:"Brodo",qt:"100ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Piselli alla menta e pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:10,gs:2.5,g:8,z:5,ch:16,fi:5,ca:30,fe:1.5,mg:30,k2:350,na:320,zn:1,fo:55,se:3,col:18}},{id:"tpl_1251",nome:"Bietole con pinoli e uvetta",nome_en:"Swiss chard with pine nuts and raisins",categoria:"Contorno",porzioni:4,note:"Lessare le bietole con gambi 5 minuti. Soffriggere aglio in olio. Aggiungere le bietole strizzate, uvetta e pinoli. Saltare a fuoco vivo 5 minuti. Condire con olio crudo e poco aceto balsamico.",note_en:"Boil Swiss chard with stems 5 minutes. Sauté garlic in oil. Add squeezed chard, raisins and pine nuts. Sauté on high heat 5 minutes. Dress with raw oil and a little balsamic vinegar.",ingredienti:[{nome:"Bietole",qt:"800g"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Aceto balsamico",qt:"15ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Bietole con pinoli e uvetta (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:5,gs:1.5,g:9,z:8,ch:12,fi:5,ca:120,fe:3.5,mg:75,k2:680,na:250,zn:.8,fo:45,se:2,col:0}},{id:"tpl_1252",nome:"Cavolo rosso in umido alla tedesca",nome_en:"German-style braised red cabbage",categoria:"Contorno",porzioni:6,note:"Affettare il cavolo rosso. Soffriggere cipolla in strutto o burro. Aggiungere cavolo, mela a pezzi, aceto, zucchero e chiodi di garofano. Cuocere coperto 45 minuti. Il sapore deve essere agrodolce. Ottimo con maiale.",note_en:"Slice red cabbage. Sauté onion in lard or butter. Add cabbage, apple pieces, vinegar, sugar and cloves. Cook covered 45 minutes. Flavour should be sweet-sour. Excellent with pork.",ingredienti:[{nome:"Cavolo rosso",qt:"800g"},{nome:"Mela",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Aceto di vino",qt:"50ml"},{nome:"Zucchero",qt:"30g"},{nome:"Chiodi di garofano",qt:"3"},{nome:"Burro",qt:"30g"}],_dbEntry:{n:"Cavolo rosso in umido alla tedesca (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:2,gs:2,g:4,z:12,ch:18,fi:5,ca:65,fe:1,mg:22,k2:380,na:60,zn:.3,fo:25,se:1,col:10}},{id:"tpl_1253",nome:"Barbabietole al forno con balsamico",nome_en:"Oven-roasted beetroot with balsamic",categoria:"Contorno",porzioni:4,note:"Avvolgere le barbabietole intere in carta stagnola con timo e olio. Cuocere in forno a 200 C per 60 minuti. Pelare mentre ancora calde. Tagliare a spicchi. Condire con aceto balsamico, olio e semi di finocchio.",note_en:"Wrap whole beetroots in foil with thyme and oil. Bake at 200 C for 60 minutes. Peel while still hot. Cut into wedges. Dress with balsamic vinegar, oil and fennel seeds.",ingredienti:[{nome:"Barbabietole",qt:"600g"},{nome:"Timo",qt:"3 rametti"},{nome:"Aceto balsamico",qt:"25ml"},{nome:"Semi di finocchio",qt:"5g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Barbabietole al forno con balsamico (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:1,g:5,z:8,ch:14,fi:3.5,ca:25,fe:1,mg:22,k2:380,na:80,zn:.5,fo:95,se:1,col:0}},{id:"tpl_1254",nome:"Crocchette di patate al forno",nome_en:"Baked potato croquettes",categoria:"Contorno",porzioni:4,note:"Preparare pure di patate denso con burro, parmigiano e tuorlo. Formare le crocchette. Passare in uovo sbattuto e pangrattato. Cuocere in forno a 200 C per 20-25 minuti fino a doratura. Piu leggere delle versioni fritte.",note_en:"Make thick mash with butter, parmesan and egg yolk. Shape croquettes. Coat in beaten egg and breadcrumbs. Bake at 200 C for 20-25 minutes until golden. Lighter than fried versions.",ingredienti:[{nome:"Patate",qt:"700g"},{nome:"Parmigiano",qt:"60g"},{nome:"Burro",qt:"30g"},{nome:"Tuorli",qt:"2"},{nome:"Uovo intero",qt:"1"},{nome:"Pangrattato",qt:"80g"}],_dbEntry:{n:"Crocchette di patate al forno (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:8,gs:4,g:9,z:2,ch:32,fi:2.5,ca:110,fe:1.2,mg:22,k2:420,na:220,zn:1,fo:18,se:5,col:90}},{id:"tpl_1255",nome:"Ratatouille provenzale",nome_en:"Provençal ratatouille",categoria:"Contorno",porzioni:6,note:"Soffriggere cipolla e aglio. Aggiungere a strati zucchine, melanzane e peperoni a cubetti. Aggiungere pomodori, timo, origano e basilico. Cuocere coperto 30 minuti poi scoperto 15. Ottima calda o fredda.",note_en:"Sauté onion and garlic. Add diced courgettes, aubergines and peppers in layers. Add tomatoes, thyme, oregano and basil. Cook covered 30 minutes then uncovered 15. Excellent hot or cold.",ingredienti:[{nome:"Zucchine",qt:"300g"},{nome:"Melanzane",qt:"300g"},{nome:"Peperoni",qt:"2"},{nome:"Pomodori maturi",qt:"400g"},{nome:"Cipolla",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Timo",qt:"3 rametti"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Ratatouille provenzale (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:1.5,g:8,z:7,ch:8,fi:4.5,ca:30,fe:1,mg:28,k2:480,na:15,zn:.4,fo:38,se:1.5,col:0}},{id:"tpl_1256",nome:"Purè di cavolfiore",nome_en:"Cauliflower mash",categoria:"Contorno",porzioni:4,note:"Lessare il cavolfiore a cimette finche tenerissimo. Frullare con burro, latte caldo, parmigiano e noce moscata. Il risultato e simile al pure di patate ma piu leggero. Servire con erba cipollina e olio crudo.",note_en:"Boil cauliflower florets until very tender. Blend with butter, hot milk, parmesan and nutmeg. Result is similar to mashed potato but lighter. Serve with chives and raw oil.",ingredienti:[{nome:"Cavolfiore",qt:"800g"},{nome:"Burro",qt:"30g"},{nome:"Latte",qt:"80ml"},{nome:"Parmigiano",qt:"40g"},{nome:"Noce moscata",qt:"q.b."},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Pure di cavolfiore (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:6,gs:3,g:6,z:4,ch:8,fi:4,ca:100,fe:.8,mg:22,k2:380,na:150,zn:.8,fo:60,se:3,col:18}},{id:"tpl_1257",nome:"Edamame al sale e sesamo",nome_en:"Edamame with salt and sesame",categoria:"Contorno",porzioni:4,note:"Cuocere gli edamame in acqua salata 5 minuti. Scolare. Cospargere con sale marino in fiocchi, semi di sesamo tostati e poche gocce di olio di sesamo. Mangiare direttamente dal baccello. Snack proteico ottimale.",note_en:"Cook edamame in salted water 5 minutes. Drain. Sprinkle with sea salt flakes, toasted sesame seeds and a few drops of sesame oil. Eat directly from pod. Optimal protein snack.",ingredienti:[{nome:"Edamame surgelati",qt:"400g"},{nome:"Sale marino in fiocchi",qt:"q.b."},{nome:"Semi di sesamo tostati",qt:"20g"},{nome:"Olio di sesamo",qt:"10ml"}],_dbEntry:{n:"Edamame al sale e sesamo (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:12,gs:1,g:6,z:2,ch:10,fi:6,ca:55,fe:2.5,mg:55,k2:380,na:200,zn:1.5,fo:180,se:3,col:0}},{id:"tpl_1258",nome:"Cavolfiore arrosto con curcuma e ceci",nome_en:"Roasted cauliflower with turmeric and chickpeas",categoria:"Contorno",porzioni:4,note:"Tagliare il cavolfiore a fette spesse. Mescolare con ceci lessati, curcuma, paprika, olio e sale. Cuocere in forno a 220 C per 30 minuti. Servire con yogurt al limone e coriandolo fresco.",note_en:"Cut cauliflower into thick slices. Mix with boiled chickpeas, turmeric, paprika, oil and salt. Bake at 220 C for 30 minutes. Serve with lemon yogurt and fresh coriander.",ingredienti:[{nome:"Cavolfiore",qt:"600g"},{nome:"Ceci cotti",qt:"200g"},{nome:"Curcuma",qt:"1.5 cucchiaini"},{nome:"Paprika",qt:"1 cucchiaino"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cavolfiore arrosto con curcuma e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:9,gs:1.5,g:9,z:4,ch:22,fi:7.5,ca:70,fe:2.5,mg:45,k2:580,na:200,zn:1.5,fo:110,se:4,col:2}},{id:"tpl_1259",nome:"Polenta taragna con funghi",nome_en:"Taragna polenta with mushrooms",categoria:"Contorno",porzioni:4,note:"Preparare la polenta taragna (mix farina gialla e grano saraceno) in acqua salata 40 minuti mescolando continuamente. Aggiungere burro e taleggio. Servire con funghi porcini trifolati in aglio e prezzemolo.",note_en:"Prepare taragna polenta (yellow flour and buckwheat mix) in salted water 40 minutes stirring continuously. Add butter and taleggio. Serve with porcini mushrooms sautéed with garlic and parsley.",ingredienti:[{nome:"Farina per polenta taragna",qt:"250g"},{nome:"Funghi porcini",qt:"300g"},{nome:"Taleggio",qt:"100g"},{nome:"Burro",qt:"50g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Polenta taragna con funghi (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:10,gs:7,g:14,z:1,ch:40,fi:3,ca:120,fe:2,mg:35,k2:380,na:320,zn:1.5,fo:18,se:5,col:35}},{id:"tpl_1260",nome:"Scarola saltata all'aglio e acciughe",nome_en:"Sautéed escarole with garlic and anchovies",categoria:"Contorno",porzioni:4,note:"Lessare la scarola tagliata in acqua salata 5 minuti. Soffriggere aglio, acciughe e peperoncino in olio finche le acciughe si sciolgono. Aggiungere la scarola strizzata. Saltare 5 minuti. Aggiustare di sale.",note_en:"Boil chopped escarole in salted water 5 minutes. Sauté garlic, anchovies and chilli in oil until anchovies dissolve. Add squeezed escarole. Sauté 5 minutes. Season with salt.",ingredienti:[{nome:"Scarola",qt:"800g"},{nome:"Acciughe sott olio",qt:"5"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olive nere",qt:"40g"},{nome:"Capperi",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Scarola saltata all aglio e acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:4.5,gs:1.5,g:8,z:1,ch:4,fi:5,ca:90,fe:2,mg:35,k2:380,na:420,zn:.8,fo:58,se:5,col:8}},{id:"tpl_1261",nome:"Crostini con fegatini di pollo",nome_en:"Chicken liver crostini",categoria:"Antipasto",porzioni:6,note:"Rosolare cipolla e salvia in burro. Aggiungere i fegatini puliti. Sfumare con Marsala. Cuocere 10 minuti. Frullare grossolanamente aggiungendo burro. Tostare il pane toscano e spalmare il paté. Tipico antipasto toscano.",note_en:"Sauté onion and sage in butter. Add cleaned chicken livers. Deglaze with Marsala. Cook 10 minutes. Blend roughly adding butter. Toast Tuscan bread and spread pâté. Typical Tuscan starter.",ingredienti:[{nome:"Fegatini di pollo",qt:"300g"},{nome:"Pane toscano sciocco",qt:"8 fette"},{nome:"Cipolla",qt:"1"},{nome:"Salvia",qt:"6 foglie"},{nome:"Marsala",qt:"80ml"},{nome:"Burro",qt:"60g"}],_dbEntry:{n:"Crostini con fegatini di pollo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:5,g:10,z:3,ch:20,fi:1,ca:40,fe:8,mg:22,k2:280,na:220,zn:2.5,fo:220,se:30,col:230}},{id:"tpl_1262",nome:"Arancini di riso siciliani",nome_en:"Sicilian rice arancini",categoria:"Antipasto",porzioni:8,note:"Preparare riso con zafferano. Raffreddare. Formare palline con al centro ragu e piselli. Passare in uovo e pangrattato. Friggere in olio profondo a 180 C fino a doratura. Scolare e servire caldi.",note_en:"Cook rice with saffron. Cool. Shape balls with ragu and peas inside. Coat with egg and breadcrumbs. Deep-fry in oil at 180 C until golden. Drain and serve hot.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Macinato di manzo",qt:"150g"},{nome:"Piselli",qt:"100g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Parmigiano",qt:"60g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Olio per friggere",qt:"500ml"}],_dbEntry:{n:"Arancini di riso siciliani (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:5,g:16,z:2,ch:48,fi:2,ca:80,fe:2,mg:28,k2:250,na:320,zn:2,fo:28,se:12,col:75}},{id:"tpl_1263",nome:"Frittelle di baccalà",nome_en:"Salt cod fritters",categoria:"Antipasto",porzioni:6,note:"Dissalare il baccalà. Lessare e sminuzzare. Mescolare con pastella di farina, acqua, prezzemolo, aglio e pepe. Friggere cucchiaiate in olio a 170 C finche dorate. Servire con salsa aioli o maionese al limone.",note_en:"Desalt cod. Boil and flake. Mix with batter of flour, water, parsley, garlic and pepper. Fry spoonfuls in oil at 170 C until golden. Serve with aioli or lemon mayonnaise.",ingredienti:[{nome:"Baccalà ammollato",qt:"400g"},{nome:"Farina",qt:"100g"},{nome:"Acqua",qt:"120ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio per friggere",qt:"400ml"}],_dbEntry:{n:"Frittelle di baccala (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:16,gs:2,g:10,z:.5,ch:16,fi:.5,ca:30,fe:.8,mg:28,k2:320,na:380,zn:.8,fo:10,se:28,col:45}},{id:"tpl_1264",nome:"Prosciutto crudo con fichi freschi",nome_en:"Cured ham with fresh figs",categoria:"Antipasto",porzioni:4,note:"Disporre le fette di prosciutto crudo DOP su piatto da portata. Accompagnare con fichi freschi tagliati a meta. Il contrasto dolce-salato e perfetto. Completare con rucola, grana a scaglie e olio extravergine.",note_en:"Arrange DOP cured ham slices on serving plate. Accompany with halved fresh figs. Sweet-salt contrast is perfect. Complete with rocket, grana shavings and extra virgin oil.",ingredienti:[{nome:"Prosciutto crudo DOP",qt:"200g"},{nome:"Fichi freschi",qt:"8"},{nome:"Rucola",qt:"60g"},{nome:"Grana Padano a scaglie",qt:"40g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Prosciutto crudo con fichi freschi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:16,gs:3,g:9,z:12,ch:18,fi:2.5,ca:80,fe:1,mg:20,k2:320,na:780,zn:1.5,fo:12,se:12,col:40}},{id:"tpl_1265",nome:"Bruschetta con porcini e tartufo nero",nome_en:"Bruschetta with porcini and black truffle",categoria:"Antipasto",porzioni:4,note:"Trifolite i porcini freschi con aglio e prezzemolo. Tostare il pane casereccio. Strofinare con aglio. Disporre i funghi sul pane. Aggiungere scaglie di tartufo nero o poco olio al tartufo. Piatto nobile e aromatico.",note_en:"Sauté fresh porcini with garlic and parsley. Toast country bread. Rub with garlic. Place mushrooms on bread. Add black truffle shavings or a little truffle oil. Noble and aromatic dish.",ingredienti:[{nome:"Funghi porcini freschi",qt:"300g"},{nome:"Pane casereccio",qt:"4 fette"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio al tartufo nero",qt:"20ml"},{nome:"Tartufo nero",qt:"20g"}],_dbEntry:{n:"Bruschetta con porcini e tartufo nero (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:6,gs:1.5,g:8,z:2,ch:25,fi:3,ca:25,fe:2,mg:22,k2:380,na:180,zn:1,fo:22,se:6,col:0}},{id:"tpl_1266",nome:"Torta della nonna",nome_en:"Grandmother's cream pie",categoria:"Dolce",porzioni:8,note:"Preparare pasta frolla e crema pasticciera. Foderare una teglia con meta della frolla. Versare la crema. Coprire con la restante frolla. Cospargere con pinoli. Cuocere a 180 C per 35 minuti. Spolverare con zucchero a velo.",note_en:"Make shortcrust pastry and custard cream. Line baking tin with half the pastry. Pour in cream. Cover with remaining pastry. Sprinkle with pine nuts. Bake at 180 C for 35 minutes. Dust with icing sugar.",ingredienti:[{nome:"Farina",qt:"300g"},{nome:"Burro",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Latte",qt:"300ml"},{nome:"Amido di mais",qt:"40g"},{nome:"Pinoli",qt:"50g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Torta della nonna (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:8,gs:8,g:16,z:26,ch:50,fi:1,ca:90,fe:1.2,mg:20,k2:160,na:120,zn:.8,fo:20,se:5,col:130}},{id:"tpl_1267",nome:"Zabaione caldo con savoiardi",nome_en:"Warm zabaglione with ladyfingers",categoria:"Dolce",porzioni:4,note:"Sbattere i tuorli con lo zucchero finche chiari. Aggiungere il Marsala. Cuocere a bagno maria montando continuamente fino a raddoppio del volume. Servire subito in coppa con savoiardi per intingere.",note_en:"Whisk egg yolks with sugar until pale. Add Marsala. Cook over double boiler whisking continuously until doubled in volume. Serve immediately in glass with ladyfingers for dipping.",ingredienti:[{nome:"Tuorli",qt:"4"},{nome:"Zucchero",qt:"60g"},{nome:"Marsala secco",qt:"80ml"},{nome:"Savoiardi",qt:"100g"}],_dbEntry:{n:"Zabaione caldo con savoiardi (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:2.5,g:7,z:25,ch:38,fi:.2,ca:35,fe:1.2,mg:12,k2:120,na:50,zn:.8,fo:25,se:10,col:205}},{id:"tpl_1268",nome:"Creme brulée alla vaniglia",nome_en:"Vanilla crème brûlée",categoria:"Dolce",porzioni:6,note:"Scaldare panna con vaniglia. Sbattere tuorli con zucchero. Temperare con la panna calda. Versare nei ramequin. Cuocere a bagno maria in forno a 150 C per 40 minuti. Raffreddare. Cospargere con zucchero e caramellare con cannello.",note_en:"Heat cream with vanilla. Whisk egg yolks with sugar. Temper with hot cream. Pour into ramekins. Bake in water bath at 150 C for 40 minutes. Cool. Sprinkle with sugar and caramelise with blowtorch.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Tuorli",qt:"5"},{nome:"Zucchero",qt:"80g"},{nome:"Zucchero di canna (per caramellare)",qt:"60g"},{nome:"Baccello di vaniglia",qt:"2"}],_dbEntry:{n:"Creme brulee alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:4.5,gs:14,g:22,z:22,ch:25,fi:0,ca:70,fe:.5,mg:8,k2:100,na:30,zn:.5,fo:12,se:3,col:220}},{id:"tpl_1269",nome:"Budino di riso al forno",nome_en:"Baked rice pudding",categoria:"Dolce",porzioni:6,note:"Cuocere il riso nel latte con zucchero, scorza di limone e cannella 20 minuti. Aggiungere uova sbattute. Versare in stampo imburrato. Cuocere in forno a 180 C per 30 minuti finche dorato. Ottimo tiepido.",note_en:"Cook rice in milk with sugar, lemon zest and cinnamon 20 minutes. Add beaten eggs. Pour into buttered mould. Bake at 180 C for 30 minutes until golden. Excellent warm.",ingredienti:[{nome:"Riso",qt:"150g"},{nome:"Latte intero",qt:"700ml"},{nome:"Zucchero",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Burro",qt:"20g"},{nome:"Limone",qt:"1"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Budino di riso al forno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:8,gs:4,g:7,z:18,ch:40,fi:.3,ca:150,fe:.8,mg:20,k2:280,na:90,zn:.8,fo:20,se:6,col:80}},{id:"tpl_1270",nome:"Macedonia di frutta con menta e limone",nome_en:"Fruit salad with mint and lemon",categoria:"Dolce",porzioni:6,note:"Tagliare la frutta di stagione a pezzi uniformi. Condire con succo di limone, zucchero a velo e foglioline di menta fresca. Mescolare delicatamente. Lasciare riposare 15 minuti. Servire fredda. Leggera e vitaminica.",note_en:"Cut seasonal fruit into uniform pieces. Dress with lemon juice, icing sugar and fresh mint leaves. Mix gently. Rest 15 minutes. Serve cold. Light and vitamin-rich.",ingredienti:[{nome:"Frutta mista di stagione",qt:"1kg"},{nome:"Limone",qt:"1"},{nome:"Zucchero a velo",qt:"20g"},{nome:"Menta fresca",qt:"10g"}],_dbEntry:{n:"Macedonia di frutta con menta e limone (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1,gs:0,g:.3,z:16,ch:20,fi:3,ca:25,fe:.5,mg:15,k2:320,na:5,zn:.2,fo:22,se:1,col:0}},{id:"tpl_1271",nome:"Muffin ai mirtilli e fiocchi d'avena",nome_en:"Blueberry and oat muffins",categoria:"Colazione",porzioni:12,note:"Mescolare farina integrale, fiocchi di avena, lievito e sale. A parte sbattere uova, olio, miele e yogurt. Unire liquidi ai solidi. Incorporare i mirtilli. Versare nei pirottini. Cuocere a 180 C per 20-22 minuti.",note_en:"Mix wholemeal flour, oats, baking powder and salt. Separately beat eggs, oil, honey and yogurt. Combine wet and dry ingredients. Fold in blueberries. Pour into cases. Bake at 180 C for 20-22 minutes.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Fiocchi di avena",qt:"60g"},{nome:"Mirtilli",qt:"150g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60ml"},{nome:"Lievito",qt:"10g"}],_dbEntry:{n:"Muffin ai mirtilli e fiocchi d avena (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:5,gs:1,g:6,z:10,ch:26,fi:3,ca:40,fe:1.2,mg:25,k2:150,na:80,zn:.8,fo:15,se:5,col:30}},{id:"tpl_1272",nome:"Pancakes integrali con frutti di bosco",nome_en:"Wholegrain pancakes with berries",categoria:"Colazione",porzioni:4,note:"Mescolare farina integrale, farina di avena, lievito, bicarbonato e sale. Sbattere uova, latte, yogurt e olio. Unire. Cuocere in padella antiaderente calda, 2 minuti per lato. Servire con frutti di bosco freschi e sciroppo d'acero.",note_en:"Mix wholemeal flour, oat flour, baking powder, bicarbonate and salt. Beat eggs, milk, yogurt and oil. Combine. Cook in hot non-stick pan, 2 minutes per side. Serve with fresh berries and maple syrup.",ingredienti:[{nome:"Farina integrale",qt:"100g"},{nome:"Farina di avena",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"200ml"},{nome:"Yogurt",qt:"80g"},{nome:"Frutti di bosco",qt:"150g"},{nome:"Sciroppo d acero",qt:"30ml"}],_dbEntry:{n:"Pancakes integrali con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:2,g:7,z:14,ch:42,fi:5,ca:120,fe:2.5,mg:40,k2:320,na:200,zn:1.5,fo:35,se:8,col:90}},{id:"tpl_1273",nome:"Barrette di cereali e frutta secca fatte in casa",nome_en:"Homemade cereal and nut bars",categoria:"Spuntino",porzioni:12,note:"Scaldare miele con burro di arachidi. Mescolare con fiocchi di avena, riso soffiato, frutta secca tritata e semi. Versare in teglia rivestita di carta forno. Compattare bene. Congelare 1 ora. Tagliare a barrette.",note_en:"Heat honey with peanut butter. Mix with oats, puffed rice, chopped nuts and seeds. Pour into parchment-lined tin. Press down firmly. Freeze 1 hour. Cut into bars.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Riso soffiato",qt:"60g"},{nome:"Frutta secca mista",qt:"100g"},{nome:"Semi misti",qt:"50g"},{nome:"Miele",qt:"80ml"},{nome:"Burro di arachidi",qt:"80g"}],_dbEntry:{n:"Barrette di cereali e frutta secca fatte in casa (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5.5,gs:2,g:9,z:12,ch:26,fi:3,ca:35,fe:1.5,mg:42,k2:200,na:20,zn:1,fo:12,se:4,col:0}},{id:"tpl_1274",nome:"Kefir con semi di chia e frutta secca",nome_en:"Kefir with chia seeds and dried fruit",categoria:"Colazione",porzioni:2,note:"Versare il kefir in ciotola. Aggiungere semi di chia e lasciare riposare 10 minuti. Aggiungere frutta secca ammollata, granola e cannella. Il kefir apporta probiotici, i semi omega-3. Colazione completa e funzionale.",note_en:"Pour kefir into bowl. Add chia seeds and rest 10 minutes. Add soaked dried fruit, granola and cinnamon. Kefir provides probiotics, seeds provide omega-3. Complete functional breakfast.",ingredienti:[{nome:"Kefir intero",qt:"300ml"},{nome:"Semi di chia",qt:"20g"},{nome:"Albicocche secche",qt:"40g"},{nome:"Prugne secche",qt:"30g"},{nome:"Granola",qt:"30g"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Kefir con semi di chia e frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:12,gs:2,g:7,z:22,ch:44,fi:8,ca:280,fe:2.5,mg:55,k2:580,na:100,zn:1.5,fo:18,se:5,col:12}},{id:"tpl_1275",nome:"Mini frittate al forno in stampini muffin",nome_en:"Mini baked frittatas in muffin tin",categoria:"Spuntino",porzioni:12,note:"Sbattere le uova con latte, sale e pepe. Aggiungere verdure a dadini (peperoni, spinaci, pomodorini) e formaggio. Versare nei stampini muffin oliati. Cuocere a 180 C per 18-20 minuti. Si conservano in frigorifero 3 giorni.",note_en:"Beat eggs with milk, salt and pepper. Add diced vegetables (peppers, spinach, cherry tomatoes) and cheese. Pour into oiled muffin tin. Bake at 180 C for 18-20 minutes. Store in fridge 3 days.",ingredienti:[{nome:"Uova",qt:"8"},{nome:"Latte",qt:"80ml"},{nome:"Peperoni",qt:"1"},{nome:"Spinaci",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Feta o ricotta",qt:"80g"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Mini frittate al forno in stampini muffin (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:8.5,gs:2.5,g:6.5,z:2,ch:3,fi:1,ca:80,fe:1.5,mg:18,k2:200,na:200,zn:1,fo:28,se:15,col:190}},{id:"tpl_1276",nome:"Coniglio alla cacciatora",nome_en:"Hunter-style rabbit",categoria:"Secondo piatto",porzioni:4,note:"Rosolare il coniglio a pezzi in olio. Aggiungere cipolla, aglio, pomodori pelati, vino rosso, rosmarino e timo. Cuocere coperto 50 minuti. Scoprire e restringere il sugo 10 minuti. Servire con polenta o patate.",note_en:"Brown rabbit pieces in oil. Add onion, garlic, peeled tomatoes, red wine, rosemary and thyme. Cook covered 50 minutes. Uncover and reduce sauce 10 minutes. Serve with polenta or potatoes.",ingredienti:[{nome:"Coniglio",qt:"1.2kg"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino rosso",qt:"150ml"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Timo",qt:"3 rametti"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Coniglio alla cacciatora (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:34,gs:3,g:12,z:4,ch:6,fi:2,ca:35,fe:2.5,mg:40,k2:580,na:350,zn:3.5,fo:20,se:22,col:90}},{id:"tpl_1277",nome:"Petto d'anatra con salsa al mirtillo",nome_en:"Duck breast with blueberry sauce",categoria:"Secondo piatto",porzioni:4,note:"Incidere la pelle dell'anatra a rombi. Cuocere dalla parte della pelle in padella a fuoco medio 8 minuti, poi girare 5 minuti. Lasciare riposare. In una casseruola cuocere mirtilli, porto, miele e brodo per la salsa.",note_en:"Score duck skin in diamonds. Cook skin-side down in pan on medium heat 8 minutes, then turn 5 minutes. Rest. In saucepan cook blueberries, port, honey and stock for sauce.",ingredienti:[{nome:"Petto d anatra",qt:"600g"},{nome:"Mirtilli",qt:"150g"},{nome:"Vino Porto",qt:"80ml"},{nome:"Miele",qt:"20ml"},{nome:"Brodo di pollo",qt:"100ml"}],_dbEntry:{n:"Petto d anatra con salsa al mirtillo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:32,gs:6,g:20,z:10,ch:12,fi:1.5,ca:25,fe:3,mg:35,k2:480,na:200,zn:3.5,fo:15,se:22,col:130}},{id:"tpl_1278",nome:"Quaglie al forno con uva e vin santo",nome_en:"Baked quail with grapes and Vin Santo",categoria:"Secondo piatto",porzioni:4,note:"Farcire le quaglie con spicchi d'aglio e salvia. Rosolare in burro e olio. Aggiungere uva nera intera e Vin Santo. Cuocere in forno a 190 C per 25 minuti. Ottimo con polenta morbida.",note_en:"Fill quails with garlic cloves and sage. Brown in butter and oil. Add whole black grapes and Vin Santo. Bake at 190 C for 25 minutes. Excellent with soft polenta.",ingredienti:[{nome:"Quaglie",qt:"4"},{nome:"Uva nera",qt:"200g"},{nome:"Vin Santo",qt:"100ml"},{nome:"Burro",qt:"30g"},{nome:"Salvia",qt:"8 foglie"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Quaglie al forno con uva e vin santo (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:30,gs:5,g:16,z:10,ch:10,fi:.8,ca:35,fe:3.5,mg:28,k2:450,na:200,zn:3,fo:12,se:18,col:115}},{id:"tpl_1279",nome:"Lonza di maiale con finocchio e arance",nome_en:"Pork loin with fennel and oranges",categoria:"Secondo piatto",porzioni:4,note:"Marinare la lonza con succo d'arancia, scorza, finocchietto, aglio e olio per 2 ore. Rosolare in padella. Aggiungere finocchio a spicchi e la marinatura. Cuocere coperto 40 minuti. Fresco e profumato.",note_en:"Marinate pork loin with orange juice, zest, fennel fronds, garlic and oil for 2 hours. Brown in pan. Add fennel wedges and marinade. Cook covered 40 minutes. Fresh and fragrant.",ingredienti:[{nome:"Lonza di maiale",qt:"700g"},{nome:"Finocchio",qt:"2"},{nome:"Arance",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Finocchietto",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Lonza di maiale con finocchio e arance (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:3,g:12,z:6,ch:10,fi:3.5,ca:55,fe:1.5,mg:35,k2:620,na:180,zn:3,fo:30,se:28,col:90}},{id:"tpl_1280",nome:"Petto di pollo con crosta di pistacchi",nome_en:"Chicken breast with pistachio crust",categoria:"Secondo piatto",porzioni:4,note:"Tritare i pistacchi con pangrattato, prezzemolo e scorza di limone. Spalmare senape sui petti di pollo. Impanare con il composto ai pistacchi. Cuocere in forno a 200 C per 20 minuti. Elegante e nutriente.",note_en:"Chop pistachios with breadcrumbs, parsley and lemon zest. Spread mustard on chicken breasts. Coat with pistachio mix. Bake at 200 C for 20 minutes. Elegant and nutritious.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Pistacchi non salati",qt:"80g"},{nome:"Pangrattato",qt:"40g"},{nome:"Senape di Digione",qt:"30g"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Petto di pollo con crosta di pistacchi (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:36,gs:2.5,g:13,z:2,ch:10,fi:2,ca:40,fe:2,mg:55,k2:580,na:320,zn:2.5,fo:22,se:28,col:85}},{id:"tpl_1281",nome:"Zuppa di vongole alla napoletana",nome_en:"Neapolitan clam soup",categoria:"Secondo piatto",porzioni:4,note:"Lasciare spurgare le vongole in acqua salata 2 ore. Soffriggere aglio in olio. Aggiungere le vongole con vino bianco. Cuocere coperto 5 minuti. Aggiungere pomodorini e prezzemolo. Servire con pane tostato.",note_en:"Soak clams in salted water 2 hours to purge. Sauté garlic in oil. Add clams with white wine. Cook covered 5 minutes. Add cherry tomatoes and parsley. Serve with toasted bread.",ingredienti:[{nome:"Vongole",qt:"1.5kg"},{nome:"Pomodorini",qt:"200g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"30g"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Pane tostato",qt:"4 fette"}],_dbEntry:{n:"Zuppa di vongole alla napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1.5,g:10,z:3,ch:10,fi:1.5,ca:80,fe:12,mg:55,k2:500,na:580,zn:2.5,fo:22,se:30,col:50}},{id:"tpl_1282",nome:"Salmone al cartoccio con limone e aneto",nome_en:"Salmon en papillote with lemon and dill",categoria:"Secondo piatto",porzioni:4,note:"Posizionare il filetto di salmone su carta da forno. Condire con olio, succo di limone, scorza, aneto e fettine di cipolla. Chiudere il cartoccio ermeticamente. Cuocere in forno a 190 C per 18 minuti.",note_en:"Place salmon fillet on parchment paper. Season with oil, lemon juice, zest, dill and onion slices. Seal parcel tightly. Bake at 190 C for 18 minutes.",ingredienti:[{nome:"Filetto di salmone",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aneto fresco",qt:"25g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Salmone al cartoccio con limone e aneto (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:32,gs:3.5,g:15,z:2,ch:3,fi:.5,ca:30,fe:1,mg:42,k2:600,na:180,zn:1,fo:22,se:48,col:90}},{id:"tpl_1283",nome:"Alici fritte dorate",nome_en:"Golden fried anchovies",categoria:"Secondo piatto",porzioni:4,note:"Pulire le alici togliendo testa e lisca. Infarinare e scrollare la farina in eccesso. Friggere in olio a 180 C per 2-3 minuti finche dorate. Scolare su carta assorbente. Salare e servire con limone.",note_en:"Clean anchovies removing head and backbone. Flour and shake off excess. Fry in oil at 180 C for 2-3 minutes until golden. Drain on paper. Salt and serve with lemon.",ingredienti:[{nome:"Alici fresche",qt:"600g"},{nome:"Farina",qt:"80g"},{nome:"Olio per friggere",qt:"400ml"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Alici fritte dorate (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:24,gs:3,g:14,z:.5,ch:10,fi:.3,ca:180,fe:3,mg:38,k2:380,na:200,zn:1.5,fo:10,se:38,col:90}},{id:"tpl_1284",nome:"Rana pescatrice in salsa verde",nome_en:"Monkfish in green sauce",categoria:"Secondo piatto",porzioni:4,note:"Tagliare la rana pescatrice a tranci. Infarinare e rosolare in olio. Preparare salsa verde con prezzemolo, aglio, acciughe, capperi, cetriolini e olio. Nappare il pesce con la salsa e cuocere 10 minuti.",note_en:"Cut monkfish into steaks. Flour and brown in oil. Make green sauce with parsley, garlic, anchovies, capers, gherkins and oil. Coat fish with sauce and cook 10 minutes.",ingredienti:[{nome:"Rana pescatrice",qt:"800g"},{nome:"Prezzemolo",qt:"50g"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"30g"},{nome:"Cetriolini",qt:"30g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Rana pescatrice in salsa verde (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:30,gs:2,g:12,z:1,ch:6,fi:.8,ca:40,fe:1.5,mg:45,k2:600,na:480,zn:1.5,fo:18,se:38,col:55}},{id:"tpl_1285",nome:"Fritto misto di paranza",nome_en:"Mixed small fish fry",categoria:"Secondo piatto",porzioni:4,note:"Pulire alici, gamberi piccoli, calamari e totanetti. Asciugare bene. Infarinare con semola di grano duro. Friggere in abbondante olio a 180-190 C pochi pezzi alla volta. Scolare e salare. Servire con limone.",note_en:"Clean anchovies, small prawns, squid and baby cuttlefish. Dry well. Coat with semolina flour. Fry in plenty of oil at 180-190 C in small batches. Drain and salt. Serve with lemon.",ingredienti:[{nome:"Alici fresche",qt:"200g"},{nome:"Gamberi piccoli",qt:"200g"},{nome:"Calamari piccoli",qt:"200g"},{nome:"Semola di grano duro",qt:"120g"},{nome:"Olio per friggere",qt:"600ml"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Fritto misto di paranza (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:28,gs:4,g:18,z:.5,ch:22,fi:.5,ca:120,fe:3,mg:42,k2:420,na:300,zn:2,fo:18,se:40,col:180}},{id:"tpl_1286",nome:"Fave fresche con pecorino e menta",nome_en:"Fresh broad beans with pecorino and mint",categoria:"Contorno",porzioni:4,note:"Sgranare le fave fresche. Sbollentare 2 minuti e pelare. Mescolare con pecorino a scaglie, foglie di menta fresca e olio extravergine. Condire con sale e pepe. Antipasto o contorno primaverile per eccellenza.",note_en:"Shell fresh broad beans. Blanch 2 minutes and peel. Mix with pecorino shavings, fresh mint leaves and extra virgin oil. Season with salt and pepper. The quintessential spring starter or side.",ingredienti:[{nome:"Fave fresche sgranate",qt:"500g"},{nome:"Pecorino a scaglie",qt:"80g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Fave fresche con pecorino e menta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:12,gs:3,g:9,z:2,ch:14,fi:7,ca:160,fe:2,mg:42,k2:420,na:320,zn:1.5,fo:100,se:3,col:15}},{id:"tpl_1287",nome:"Cous cous di verdure arrostite",nome_en:"Roasted vegetable couscous",categoria:"Contorno",porzioni:4,note:"Arrostire zucchine, peperoni, melanzane e cipolla in forno. Preparare il cous cous con brodo bollente e olio. Mescolare con le verdure arrostite, uvetta, mandorle tostate, prezzemolo e cumino.",note_en:"Roast courgettes, peppers, aubergines and onion in oven. Prepare couscous with boiling stock and oil. Mix with roasted vegetables, raisins, toasted almonds, parsley and cumin.",ingredienti:[{nome:"Cous cous",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"2"},{nome:"Melanzane",qt:"150g"},{nome:"Uvetta",qt:"30g"},{nome:"Mandorle tostate",qt:"40g"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cous cous di verdure arrostite (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:9,gs:1.5,g:12,z:8,ch:46,fi:6,ca:50,fe:2,mg:55,k2:480,na:180,zn:1,fo:45,se:5,col:0}},{id:"tpl_1288",nome:"Puntarelle alla romana con acciughe",nome_en:"Roman puntarelle with anchovies",categoria:"Contorno",porzioni:4,note:"Tagliare le puntarelle a listarelle e immergerle in acqua fredda con ghiaccio 30 minuti finche si arricciassero. Pestare acciughe con aglio e olio. Scolare le puntarelle e condire con la salsa di acciughe e aceto.",note_en:"Cut puntarelle into strips and soak in cold iced water 30 minutes until they curl. Pound anchovies with garlic and oil. Drain puntarelle and dress with anchovy sauce and vinegar.",ingredienti:[{nome:"Puntarelle",qt:"500g"},{nome:"Acciughe sott olio",qt:"6"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Aceto di vino",qt:"25ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Puntarelle alla romana con acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4.5,gs:1.5,g:8,z:1,ch:4,fi:5,ca:55,fe:2,mg:25,k2:350,na:350,zn:.5,fo:45,se:5,col:8}},{id:"tpl_1289",nome:"Patate al cartoccio con panna acida",nome_en:"Jacket potatoes with sour cream",categoria:"Contorno",porzioni:4,note:"Lavare bene le patate. Strofinarle con olio e sale grosso. Avvolgerle in carta stagnola. Cuocere in forno a 220 C per 60 minuti. Aprire e farcire con panna acida, erba cipollina e bacon croccante.",note_en:"Wash potatoes well. Rub with oil and coarse salt. Wrap in foil. Bake at 220 C for 60 minutes. Open and fill with sour cream, chives and crispy bacon.",ingredienti:[{nome:"Patate grandi",qt:"4"},{nome:"Panna acida",qt:"120g"},{nome:"Erba cipollina",qt:"15g"},{nome:"Bacon",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Patate al cartoccio con panna acida (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:8,gs:4,g:12,z:2,ch:40,fi:3.5,ca:55,fe:1.5,mg:38,k2:800,na:280,zn:.8,fo:30,se:3,col:25}},{id:"tpl_1290",nome:"Porri in padella con aceto balsamico",nome_en:"Leeks with balsamic vinegar",categoria:"Contorno",porzioni:4,note:"Tagliare i porri a rondelle spesse. Soffriggere in olio a fuoco medio 10 minuti finche morbidi. Sfumare con aceto balsamico. Aggiungere miele. Cuocere altri 5 minuti. Guarnire con timo e noci tritate.",note_en:"Cut leeks into thick rounds. Sauté in oil over medium heat 10 minutes until soft. Deglaze with balsamic vinegar. Add honey. Cook 5 more minutes. Garnish with thyme and chopped walnuts.",ingredienti:[{nome:"Porri",qt:"600g"},{nome:"Aceto balsamico",qt:"30ml"},{nome:"Miele",qt:"15ml"},{nome:"Timo",qt:"3 rametti"},{nome:"Noci",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Porri in padella con aceto balsamico (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3,gs:1.5,g:8,z:7,ch:12,fi:3.5,ca:60,fe:1.5,mg:22,k2:350,na:15,zn:.5,fo:45,se:2,col:0}},{id:"tpl_1291",nome:"Supplì romani al telefono",nome_en:"Roman suppli",categoria:"Antipasto",porzioni:8,note:"Preparare riso cotto nel sugo di carne con parmigiano. Raffreddare. Formare le palline con un pezzo di mozzarella al centro. Passare in uovo sbattuto e pangrattato. Friggere in olio a 180 C finche dorati.",note_en:"Make rice cooked in meat sauce with parmesan. Cool. Shape balls with a piece of mozzarella in centre. Coat in beaten egg and breadcrumbs. Fry in oil at 180 C until golden.",ingredienti:[{nome:"Riso",qt:"250g"},{nome:"Mozzarella",qt:"150g"},{nome:"Sugo di carne",qt:"200ml"},{nome:"Parmigiano",qt:"50g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Olio per friggere",qt:"500ml"}],_dbEntry:{n:"Suppli romani al telefono (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:11,gs:4,g:13,z:2,ch:36,fi:1,ca:120,fe:1.5,mg:22,k2:200,na:360,zn:1.5,fo:18,se:10,col:65}},{id:"tpl_1292",nome:"Bagna cauda piemontese",nome_en:"Piedmontese bagna cauda",categoria:"Antipasto",porzioni:6,note:"Sciogliere le acciughe in aglio e olio a fuoco bassissimo 15 minuti. Aggiungere burro a pezzetti e mescolare fino a crema. Mantenere calda. Servire con verdure crude e cotte: peperoni, sedano, cavolo, topinambur, cipolle.",note_en:"Melt anchovies in garlic and oil on very low heat 15 minutes. Add butter pieces and stir to cream. Keep warm. Serve with raw and cooked vegetables: peppers, celery, cabbage, Jerusalem artichoke, onions.",ingredienti:[{nome:"Acciughe sotto sale",qt:"150g"},{nome:"Aglio",qt:"8 spicchi"},{nome:"Olio extravergine",qt:"150ml"},{nome:"Burro",qt:"80g"},{nome:"Verdure miste per intingere",qt:"800g"}],_dbEntry:{n:"Bagna cauda piemontese (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:8,gs:6,g:20,z:5,ch:8,fi:4,ca:80,fe:1.5,mg:30,k2:450,na:600,zn:.8,fo:40,se:15,col:45}},{id:"tpl_1293",nome:"Gazpacho andaluso",nome_en:"Andalusian gazpacho",categoria:"Antipasto",porzioni:6,note:"Frullare pomodori maturi, cetriolo, peperone rosso, aglio, cipolla e pane raffermo imbevuto. Aggiungere olio, aceto e sale. Setacciare. Raffreddare almeno 2 ore. Servire con guarnizione di dadini di verdure e crostini.",note_en:"Blend ripe tomatoes, cucumber, red pepper, garlic, onion and soaked stale bread. Add oil, vinegar and salt. Strain. Refrigerate at least 2 hours. Serve garnished with diced vegetables and croutons.",ingredienti:[{nome:"Pomodori maturi",qt:"700g"},{nome:"Cetriolo",qt:"1"},{nome:"Peperone rosso",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pane raffermo",qt:"60g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Aceto di vino bianco",qt:"30ml"}],_dbEntry:{n:"Gazpacho andaluso (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:2.5,gs:1.5,g:10,z:6,ch:8,fi:3,ca:25,fe:1,mg:22,k2:480,na:180,zn:.4,fo:30,se:2,col:0}},{id:"tpl_1294",nome:"Carpaccio di salmone con lime e zenzero",nome_en:"Salmon carpaccio with lime and ginger",categoria:"Antipasto",porzioni:4,note:"Affettare il salmone freschissimo sottilissimo. Disporre su piatto freddo. Marinare 5 minuti con succo di lime, scorza, zenzero grattugiato, olio di sesamo e cipollotto. Guarnire con sesamo e microgreens.",note_en:"Slice very fresh salmon paper-thin. Arrange on cold plate. Marinate 5 minutes with lime juice, zest, grated ginger, sesame oil and spring onion. Garnish with sesame and microgreens.",ingredienti:[{nome:"Salmone fresco filetto",qt:"400g"},{nome:"Lime",qt:"2"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Olio di sesamo",qt:"20ml"},{nome:"Cipollotto",qt:"2"},{nome:"Semi di sesamo",qt:"15g"}],_dbEntry:{n:"Carpaccio di salmone con lime e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:3,g:12,z:1,ch:2,fi:.3,ca:25,fe:.8,mg:38,k2:520,na:180,zn:.8,fo:20,se:42,col:70}},{id:"tpl_1295",nome:"Focaccia genovese all'olio",nome_en:"Genoese olive oil focaccia",categoria:"Antipasto",porzioni:8,note:"Impastare farina, acqua, lievito, olio e sale. Far lievitare 2 ore. Stendere nella teglia oleata. Fare le tipiche fossette con le dita. Spennellare con salamoia (acqua e sale). Aggiungere olio abbondante. Lievitare 30 min. Cuocere a 220 C per 20 min.",note_en:"Mix flour, water, yeast, oil and salt. Rise 2 hours. Spread in oiled tin. Make typical dimples with fingers. Brush with brine (water and salt). Add plenty of oil. Rise 30 min. Bake at 220 C for 20 min.",ingredienti:[{nome:"Farina 0",qt:"500g"},{nome:"Acqua",qt:"350ml"},{nome:"Lievito di birra",qt:"7g"},{nome:"Olio extravergine",qt:"80ml"},{nome:"Sale",qt:"12g"}],_dbEntry:{n:"Focaccia genovese all olio (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:6.5,gs:1.5,g:8,z:.5,ch:40,fi:1.5,ca:15,fe:1.5,mg:18,k2:120,na:380,zn:.6,fo:30,se:15,col:0}},{id:"tpl_1296",nome:"Insalata nizzarda",nome_en:"Niçoise salad",categoria:"Insalata",porzioni:4,note:"Comporre su piatto grande: lattuga, pomodori, uova sode, fagiolini lessati al dente, patate lesse, tonno, olive nere, acciughe e cetriolini. Condire con vinaigrette alla senape. Non mescolare: ogni elemento deve essere visibile.",note_en:"Compose on large plate: lettuce, tomatoes, hard-boiled eggs, al dente boiled green beans, boiled potatoes, tuna, black olives, anchovies and gherkins. Dress with mustard vinaigrette. Do not mix: each element must be visible.",ingredienti:[{nome:"Lattuga",qt:"1"},{nome:"Tonno sott olio",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Fagiolini",qt:"150g"},{nome:"Patate novelle",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Acciughe",qt:"6"},{nome:"Senape",qt:"10g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata nizzarda (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:20,gs:3,g:16,z:3,ch:16,fi:4,ca:75,fe:3,mg:45,k2:620,na:680,zn:2,fo:60,se:28,col:165}},{id:"tpl_1297",nome:"Bowl di orzo con salmone affumicato",nome_en:"Barley bowl with smoked salmon",categoria:"Insalata",porzioni:4,note:"Cuocere l'orzo perlato. Raffreddare. Comporre le bowl con orzo, salmone affumicato a strisce, avocado a fette, cetriolo, ravanelli e rucola. Condire con crema di yogurt, aneto e limone.",note_en:"Cook pearl barley. Cool. Compose bowls with barley, smoked salmon strips, sliced avocado, cucumber, radishes and rocket. Dress with yogurt cream, dill and lemon.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Salmone affumicato",qt:"200g"},{nome:"Avocado",qt:"2"},{nome:"Cetriolo",qt:"1"},{nome:"Ravanelli",qt:"8"},{nome:"Yogurt greco",qt:"100g"},{nome:"Aneto",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Bowl di orzo con salmone affumicato (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:22,gs:3.5,g:16,z:3,ch:48,fi:6.5,ca:80,fe:2,mg:58,k2:680,na:680,zn:2,fo:55,se:30,col:30}},{id:"tpl_1298",nome:"Insalata di mare classica",nome_en:"Classic seafood salad",categoria:"Insalata",porzioni:6,note:"Lessare separatamente calamari, gamberi, cozze e vongole. Tagliare i calamari ad anelli. Condire tutto con olio extravergine, succo di limone, aglio, prezzemolo, sedano e peperoncino. Lasciare marinare 1 ora.",note_en:"Boil separately squid, prawns, mussels and clams. Cut squid into rings. Dress everything with extra virgin oil, lemon juice, garlic, parsley, celery and chilli. Marinate 1 hour.",ingredienti:[{nome:"Calamari",qt:"300g"},{nome:"Gamberi",qt:"300g"},{nome:"Cozze",qt:"400g"},{nome:"Vongole",qt:"300g"},{nome:"Sedano",qt:"2 coste"},{nome:"Limone",qt:"2"},{nome:"Prezzemolo",qt:"25g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Insalata di mare classica (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:26,gs:1.5,g:9,z:2,ch:6,fi:1,ca:100,fe:4,mg:55,k2:550,na:480,zn:3,fo:28,se:42,col:170}},{id:"tpl_1299",nome:"Poke bowl hawaiiano con tonno",nome_en:"Hawaiian tuna poke bowl",categoria:"Insalata",porzioni:2,note:"Tagliare il tonno freschissimo a cubetti. Marinare con soia, olio di sesamo, cipollotto e zenzero. Cuocere il riso per sushi. Comporre le bowl con riso, tonno marinato, avocado, edamame, cetriolo e alghe.",note_en:"Cut very fresh tuna into cubes. Marinate with soy, sesame oil, spring onion and ginger. Cook sushi rice. Compose bowls with rice, marinated tuna, avocado, edamame, cucumber and seaweed.",ingredienti:[{nome:"Tonno fresco",qt:"250g"},{nome:"Riso per sushi",qt:"200g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"80g"},{nome:"Cetriolo",qt:"0.5"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"15ml"},{nome:"Alghe nori",qt:"2 fogli"}],_dbEntry:{n:"Poke bowl hawaiiano con tonno (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:34,gs:3,g:16,z:3,ch:52,fi:7,ca:40,fe:2.5,mg:65,k2:750,na:720,zn:2,fo:55,se:72,col:48}},{id:"tpl_1300",nome:"Insalata tiepida di lenticchie e salsiccia",nome_en:"Warm lentil and sausage salad",categoria:"Insalata",porzioni:4,note:"Cuocere le lenticchie con alloro. Rosolare la salsiccia sbriciolata. Mescolare lenticchie calde con salsiccia, sedano, carota, cipolla rossa e senape. Condire con aceto di mele e olio. Servire tiepida.",note_en:"Cook lentils with bay leaf. Brown crumbled sausage. Mix warm lentils with sausage, celery, carrot, red onion and mustard. Dress with apple cider vinegar and oil. Serve warm.",ingredienti:[{nome:"Lenticchie verdi",qt:"250g"},{nome:"Salsiccia di maiale",qt:"200g"},{nome:"Sedano",qt:"2 coste"},{nome:"Carota",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Senape",qt:"15g"},{nome:"Aceto di mele",qt:"20ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata tiepida di lenticchie e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:22,gs:5,g:16,z:3,ch:32,fi:9,ca:55,fe:5,mg:62,k2:720,na:520,zn:3,fo:150,se:12,col:45}},{id:"tpl_1301",nome:"Ricotta al forno con miele e limone",nome_en:"Baked ricotta with honey and lemon",categoria:"Dolce",porzioni:6,note:"Mescolare ricotta con uova, zucchero, scorza di limone e vaniglia. Versare in teglia imburrata. Cuocere a 170 C per 35-40 minuti. Raffreddare e servire con miele, fichi freschi o frutti di bosco.",note_en:"Mix ricotta with eggs, sugar, lemon zest and vanilla. Pour into buttered tin. Bake at 170 C for 35-40 minutes. Cool and serve with honey, fresh figs or berries.",ingredienti:[{nome:"Ricotta fresca",qt:"500g"},{nome:"Uova",qt:"2"},{nome:"Zucchero",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Vaniglia",qt:"1 cucchiaino"},{nome:"Miele",qt:"40ml"},{nome:"Frutti di bosco",qt:"100g"}],_dbEntry:{n:"Ricotta al forno con miele e limone (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:11,gs:5,g:10,z:20,ch:26,fi:.3,ca:200,fe:.5,mg:18,k2:180,na:120,zn:1,fo:15,se:8,col:90}},{id:"tpl_1302",nome:"Ciambella allo yogurt",nome_en:"Yogurt ring cake",categoria:"Dolce",porzioni:8,note:"Usare il vasetto di yogurt come unità di misura. Mescolare yogurt, olio, uova, zucchero, farina, lievito e scorza di limone. Versare nello stampo a ciambella. Cuocere a 180 C per 35 minuti. La ciambella della tradizione italiana.",note_en:"Use yogurt pot as unit of measure. Mix yogurt, oil, eggs, sugar, flour, baking powder and lemon zest. Pour into ring mould. Bake at 180 C for 35 minutes. Italian tradition ring cake.",ingredienti:[{nome:"Yogurt intero",qt:"125g"},{nome:"Farina",qt:"250g"},{nome:"Zucchero",qt:"200g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito",qt:"16g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Ciambella allo yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5.5,gs:1.5,g:9,z:24,ch:44,fi:.8,ca:40,fe:1,mg:15,k2:120,na:80,zn:.5,fo:12,se:5,col:70}},{id:"tpl_1303",nome:"Cantuccini alle mandorle",nome_en:"Almond cantuccini biscotti",categoria:"Dolce",porzioni:20,note:"Impastare farina, zucchero, uova, mandorle intere non pelate, lievito e scorza d'arancia. Formare filoncini. Cuocere a 180 C per 25 minuti. Tagliare in diagonale e biscottare in forno a 150 C per 15 minuti. Ottimi inzuppati nel Vin Santo.",note_en:"Mix flour, sugar, eggs, whole unpeeled almonds, baking powder and orange zest. Shape into logs. Bake at 180 C for 25 minutes. Cut diagonally and dry in oven at 150 C for 15 minutes. Excellent dunked in Vin Santo.",ingredienti:[{nome:"Farina",qt:"300g"},{nome:"Zucchero",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Mandorle intere",qt:"200g"},{nome:"Lievito",qt:"8g"},{nome:"Arancia",qt:"1"}],_dbEntry:{n:"Cantuccini alle mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3.5,gs:.5,g:4.5,z:12,ch:18,fi:1,ca:25,fe:.8,mg:22,k2:100,na:30,zn:.5,fo:8,se:3,col:18}},{id:"tpl_1304",nome:"Panna cotta al caffè",nome_en:"Coffee panna cotta",categoria:"Dolce",porzioni:6,note:"Scaldare panna con zucchero e caffè espresso ristretto. Ammorbidire gelatina in acqua fredda. Sciogliere nella panna calda. Versare in bicchieri o stampini. Raffreddare 4 ore. Servire con salsa al cioccolato fondente.",note_en:"Heat cream with sugar and strong espresso. Soften gelatine in cold water. Dissolve in hot cream. Pour into glasses or moulds. Refrigerate 4 hours. Serve with dark chocolate sauce.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Caffe espresso",qt:"80ml"},{nome:"Zucchero",qt:"70g"},{nome:"Gelatina in fogli",qt:"10g"},{nome:"Cioccolato fondente",qt:"60g"}],_dbEntry:{n:"Panna cotta al caffe (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:3,gs:13,g:20,z:16,ch:20,fi:.3,ca:75,fe:.5,mg:10,k2:120,na:30,zn:.3,fo:5,se:2,col:65}},{id:"tpl_1305",nome:"Frutta di stagione al forno con cannella",nome_en:"Seasonal baked fruit with cinnamon",categoria:"Dolce",porzioni:4,note:"Tagliare pesche, albicocche, fichi o mele a meta. Disporre in teglia. Cospargere con cannella, zucchero di canna, poche gocce di succo d'arancia. Cuocere a 180 C per 20-25 minuti. Servire con gelato alla vaniglia o yogurt.",note_en:"Halve peaches, apricots, figs or apples. Arrange in baking dish. Sprinkle with cinnamon, brown sugar, a few drops of orange juice. Bake at 180 C for 20-25 minutes. Serve with vanilla ice cream or yogurt.",ingredienti:[{nome:"Frutta mista di stagione",qt:"800g"},{nome:"Zucchero di canna",qt:"40g"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Arancia (succo)",qt:"0.5"},{nome:"Yogurt o gelato",qt:"150g"}],_dbEntry:{n:"Frutta di stagione al forno con cannella (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:.5,g:1.5,z:22,ch:30,fi:4,ca:35,fe:.5,mg:18,k2:350,na:20,zn:.3,fo:15,se:2,col:5}},{id:"tpl_1306",nome:"Golden milk latte con curcuma e zenzero",nome_en:"Turmeric and ginger golden milk latte",categoria:"Colazione",porzioni:2,note:"Scaldare il latte con curcuma, zenzero in polvere, cannella, pepe nero e miele. Non portare a ebollizione. Montare il latte con frullino. Versare in tazza. Il pepe nero esalta l'assorbimento della curcumina.",note_en:"Heat milk with turmeric, ground ginger, cinnamon, black pepper and honey. Do not boil. Froth milk with whisk. Pour into cup. Black pepper enhances curcumin absorption.",ingredienti:[{nome:"Latte di mandorla o vaccino",qt:"400ml"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Zenzero in polvere",qt:"0.5 cucchiaino"},{nome:"Cannella",qt:"0.5 cucchiaino"},{nome:"Pepe nero",qt:"1 pizzico"},{nome:"Miele",qt:"20ml"}],_dbEntry:{n:"Golden milk latte con curcuma e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:3,gs:1,g:3,z:12,ch:18,fi:.5,ca:200,fe:.5,mg:20,k2:200,na:80,zn:.3,fo:5,se:2,col:5}},{id:"tpl_1307",nome:"Pane tostato con ricotta e miele",nome_en:"Toast with ricotta and honey",categoria:"Colazione",porzioni:2,note:"Tostare due fette di pane integrale. Spalmare abbondante ricotta fresca. Condire con miele, noci tritate e cannella. Aggiungere fettine di banana o mirtilli. Colazione proteica e naturalmente dolce.",note_en:"Toast two slices of wholegrain bread. Spread plenty of fresh ricotta. Top with honey, chopped walnuts and cinnamon. Add banana slices or blueberries. Naturally sweet protein breakfast.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Ricotta fresca",qt:"120g"},{nome:"Miele",qt:"20ml"},{nome:"Noci",qt:"20g"},{nome:"Banana",qt:"1"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Pane tostato con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:12,gs:2.5,g:8,z:18,ch:46,fi:5,ca:140,fe:1.8,mg:35,k2:380,na:180,zn:1.2,fo:22,se:8,col:22}},{id:"tpl_1308",nome:"Frullato proteico post-allenamento",nome_en:"Post-workout protein shake",categoria:"Spuntino",porzioni:1,note:"Frullare banana congelata, latte, proteine in polvere (vaniglia o cioccolato), burro di mandorle e semi di chia. Se troppo denso aggiungere latte. Consumare entro 30 minuti dall'allenamento per massimizzare la sintesi proteica.",note_en:"Blend frozen banana, milk, protein powder (vanilla or chocolate), almond butter and chia seeds. If too thick add more milk. Consume within 30 minutes of training to maximise protein synthesis.",ingredienti:[{nome:"Banana congelata",qt:"1"},{nome:"Latte",qt:"250ml"},{nome:"Proteine in polvere",qt:"30g"},{nome:"Burro di mandorle",qt:"20g"},{nome:"Semi di chia",qt:"10g"}],_dbEntry:{n:"Frullato proteico post-allenamento (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:30,gs:2,g:10,z:16,ch:40,fi:4.5,ca:280,fe:1.5,mg:65,k2:580,na:120,zn:1.5,fo:18,se:5,col:15}},{id:"tpl_1309",nome:"Crackers di segale con avocado e cetriolo",nome_en:"Rye crackers with avocado and cucumber",categoria:"Spuntino",porzioni:2,note:"Spalmare l'avocado schiacciato con limone e sale sui crackers di segale. Aggiungere fettine sottili di cetriolo, semi di sesamo e pepe. Snack veloce, ricco di grassi buoni e fibre. Ottimo a meta mattina.",note_en:"Spread avocado mashed with lemon and salt on rye crackers. Add thin cucumber slices, sesame seeds and pepper. Quick snack, rich in healthy fats and fibre. Excellent mid-morning.",ingredienti:[{nome:"Crackers di segale",qt:"4"},{nome:"Avocado",qt:"0.5"},{nome:"Cetriolo",qt:"0.5"},{nome:"Limone",qt:"0.5"},{nome:"Semi di sesamo",qt:"5g"}],_dbEntry:{n:"Crackers di segale con avocado e cetriolo (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:1.5,g:8,z:1,ch:22,fi:7,ca:20,fe:1.2,mg:28,k2:280,na:180,zn:.8,fo:45,se:3,col:0}},{id:"tpl_1310",nome:"Uova in cocotte con prosciutto e parmigiano",nome_en:"Eggs en cocotte with ham and parmesan",categoria:"Colazione",porzioni:4,note:"Imburrare 4 cocotte. Adagiare una fetta di prosciutto cotto in ciascuna. Rompere un uovo dentro. Aggiungere un cucchiaio di panna, parmigiano grattugiato e pepe. Cuocere a bagno maria in forno a 180 C per 12 minuti.",note_en:"Butter 4 ramekins. Place a slice of cooked ham in each. Break an egg inside. Add a spoonful of cream, grated parmesan and pepper. Bake in water bath at 180 C for 12 minutes.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Prosciutto cotto",qt:"4 fette"},{nome:"Panna da cucina",qt:"40ml"},{nome:"Parmigiano",qt:"30g"},{nome:"Burro",qt:"15g"}],_dbEntry:{n:"Uova in cocotte con prosciutto e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:14,gs:5.5,g:14,z:1,ch:1.5,fi:0,ca:90,fe:1.2,mg:12,k2:160,na:480,zn:1.2,fo:22,se:18,col:230}},{id:"tpl_1311",nome:"Zuppa toscana con cavolo nero e fagioli",nome_en:"Tuscan soup with cavolo nero and beans",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, carota e sedano in olio. Aggiungere fagioli cannellini, cavolo nero a strisce e pomodori. Versare brodo e cuocere 35 minuti. Aggiustare di sale. Servire su fette di pane tostato con olio crudo.",note_en:"Sauté onion, carrot and celery in oil. Add cannellini beans, sliced cavolo nero and tomatoes. Pour in stock and cook 35 minutes. Season with salt. Serve on toasted bread slices with raw oil.",ingredienti:[{nome:"Cavolo nero",qt:"400g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Pane toscano",qt:"4 fette"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Zuppa toscana con cavolo nero e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:11,gs:1,g:7,z:4,ch:35,fi:10,ca:100,fe:3.5,mg:60,k2:680,na:320,zn:1.5,fo:110,se:4,col:0}},{id:"tpl_1312",nome:"Borscht di barbabietole con panna acida",nome_en:"Beetroot borscht with sour cream",categoria:"Zuppa",porzioni:6,note:"Rosolare cipolla, carota e sedano in olio. Aggiungere barbabietole grattugiate, cavolo, pomodori e brodo. Cuocere 40 minuti. Aggiungere aceto e zucchero. Servire calda o fredda con panna acida e aneto.",note_en:"Brown onion, carrot and celery in oil. Add grated beetroot, cabbage, tomatoes and stock. Cook 40 minutes. Add vinegar and sugar. Serve hot or cold with sour cream and dill.",ingredienti:[{nome:"Barbabietole",qt:"400g"},{nome:"Cavolo bianco",qt:"200g"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Brodo di carne",qt:"1L"},{nome:"Aceto di vino",qt:"30ml"},{nome:"Panna acida",qt:"100g"},{nome:"Aneto",qt:"15g"}],_dbEntry:{n:"Borscht di barbabietole con panna acida (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4.5,gs:3,g:6,z:10,ch:20,fi:5,ca:65,fe:1.5,mg:30,k2:550,na:320,zn:.5,fo:55,se:3,col:15}},{id:"tpl_1313",nome:"Crema di pomodoro fresco con basilico",nome_en:"Fresh tomato cream with basil",categoria:"Zuppa",porzioni:4,note:"Rosolare cipolla e aglio in olio. Aggiungere pomodori maturi pelati e a pezzi. Cuocere 20 minuti. Frullare con basilico fresco e olio extravergine. Setacciare. Regolare di sale. Servire calda o fredda con crostini.",note_en:"Sauté onion and garlic in oil. Add peeled and chopped ripe tomatoes. Cook 20 minutes. Blend with fresh basil and extra virgin oil. Strain. Season. Serve hot or cold with croutons.",ingredienti:[{nome:"Pomodori maturi",qt:"1kg"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"25g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Crema di pomodoro fresco con basilico (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:3,gs:1.5,g:9,z:7,ch:10,fi:3,ca:25,fe:1,mg:22,k2:480,na:150,zn:.4,fo:30,se:2,col:0}},{id:"tpl_1314",nome:"Minestra di orzo e fagioli borlotti",nome_en:"Barley and borlotti bean soup",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, carota, sedano, lardo o pancetta. Aggiungere fagioli borlotti e orzo perlato. Versare brodo abbondante. Cuocere 40 minuti finche l'orzo e cotto. La zuppa si addensa raffreddando. Servire con olio crudo.",note_en:"Sauté onion, carrot, celery, lard or pancetta. Add borlotti beans and pearl barley. Pour in plenty of stock. Cook 40 minutes until barley is cooked. Soup thickens as it cools. Serve with raw oil.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Brodo vegetale",qt:"1.5L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Minestra di orzo e fagioli borlotti (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:2,g:8,z:3,ch:44,fi:10,ca:70,fe:3,mg:55,k2:600,na:380,zn:2,fo:110,se:5,col:10}},{id:"tpl_1315",nome:"Zuppa di ceci e baccalà",nome_en:"Chickpea and salt cod soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e rosmarino in olio. Aggiungere ceci lessati e pomodori. Cuocere 15 minuti. Aggiungere il baccalà dissalato a bocconcini. Cuocere 15 minuti. Aggiustare di sale. Guarnire con olio e peperoncino.",note_en:"Sauté garlic and rosemary in oil. Add cooked chickpeas and tomatoes. Cook 15 minutes. Add desalted cod pieces. Cook 15 minutes. Season with salt. Garnish with oil and chilli.",ingredienti:[{nome:"Ceci cotti",qt:"400g"},{nome:"Baccalà ammollato",qt:"400g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Zuppa di ceci e baccala (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:26,gs:1.5,g:8,z:3,ch:28,fi:8,ca:80,fe:3.5,mg:65,k2:700,na:450,zn:2,fo:130,se:35,col:55}},{id:"tpl_1316",nome:"Passato di verdure invernale",nome_en:"Winter vegetable passato",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla in olio. Aggiungere patate, carote, sedano rapa, zucca e brodo. Cuocere 30 minuti. Frullare fino a crema liscia. Regolare la consistenza con brodo. Servire con un filo di olio crudo, semi di zucca e pane tostato.",note_en:"Sauté onion in oil. Add potatoes, carrots, celeriac, pumpkin and stock. Cook 30 minutes. Blend until smooth cream. Adjust consistency with stock. Serve with raw oil drizzle, pumpkin seeds and toast.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Carote",qt:"200g"},{nome:"Sedano rapa",qt:"200g"},{nome:"Zucca",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Semi di zucca",qt:"20g"}],_dbEntry:{n:"Passato di verdure invernale (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:3.5,gs:1,g:6,z:5,ch:22,fi:4.5,ca:45,fe:1.2,mg:28,k2:560,na:220,zn:.6,fo:30,se:2,col:0}},{id:"tpl_1317",nome:"Zuppa di pesce mediterranea",nome_en:"Mediterranean fish soup",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, aglio e finocchio in olio. Aggiungere passata di pomodoro, vino bianco e zafferano. Cuocere 10 minuti. Aggiungere pesce misto a pezzi, crostacei e molluschi. Cuocere 20 minuti. Servire con croutons.",note_en:"Sauté onion, garlic and fennel in oil. Add tomato passata, white wine and saffron. Cook 10 minutes. Add mixed fish pieces, shellfish and molluscs. Cook 20 minutes. Serve with croutons.",ingredienti:[{nome:"Pesce misto da zuppa",qt:"1kg"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Finocchio",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Zuppa di pesce mediterranea (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:30,gs:2,g:10,z:5,ch:12,fi:2,ca:80,fe:3,mg:58,k2:700,na:480,zn:2.5,fo:30,se:48,col:100}},{id:"tpl_1318",nome:"Zuppa di porcini e castagne",nome_en:"Porcini and chestnut soup",categoria:"Zuppa",porzioni:4,note:"Ammollare i porcini secchi 30 minuti. Soffriggere scalogno in burro. Aggiungere porcini scolati e castagne lesse. Versare brodo e il liquido di ammollo filtrato. Cuocere 25 minuti. Frullare meta zuppa. Guarnire con porcini trifolati.",note_en:"Soak dried porcini 30 minutes. Sauté shallot in butter. Add drained porcini and boiled chestnuts. Pour in stock and strained soaking liquid. Cook 25 minutes. Blend half soup. Garnish with sautéed porcini.",ingredienti:[{nome:"Porcini secchi",qt:"30g"},{nome:"Castagne lessate",qt:"250g"},{nome:"Scalogno",qt:"3"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Burro",qt:"30g"},{nome:"Timo",qt:"3 rametti"}],_dbEntry:{n:"Zuppa di porcini e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:3,g:7,z:5,ch:34,fi:5.5,ca:30,fe:2.5,mg:38,k2:480,na:180,zn:1,fo:35,se:8,col:18}},{id:"tpl_1319",nome:"Crema di topinambur e tartufo",nome_en:"Jerusalem artichoke and truffle cream",categoria:"Zuppa",porzioni:4,note:"Lessare il topinambur con scalogno. Frullare con brodo, panna e olio. Setacciare per ottenere una crema vellutata. Regolare di sale. Servire con julienne di topinambur croccante, olio al tartufo e chips di prosciutto.",note_en:"Boil Jerusalem artichoke with shallot. Blend with stock, cream and oil. Strain to obtain velvet cream. Season. Serve with crispy Jerusalem artichoke julienne, truffle oil and crispy ham chips.",ingredienti:[{nome:"Topinambur",qt:"600g"},{nome:"Scalogno",qt:"2"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Olio al tartufo",qt:"15ml"},{nome:"Prosciutto crudo",qt:"40g"}],_dbEntry:{n:"Crema di topinambur e tartufo (ricetta)",c:"Ricette",src:"RICETTE",k:195,p:6,gs:4,g:11,z:4,ch:18,fi:3.5,ca:25,fe:3.5,mg:22,k2:480,na:320,zn:.5,fo:18,se:3,col:28}},{id:"tpl_1320",nome:"Zuppa di fagioli neri alla messicana",nome_en:"Mexican black bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, aglio, peperone e jalapeño in olio. Aggiungere fagioli neri, cumino, coriandolo e brodo. Cuocere 20 minuti. Frullare meta. Servire con tortilla chips, avocado, panna acida e lime.",note_en:"Sauté onion, garlic, pepper and jalapeño in oil. Add black beans, cumin, coriander and stock. Cook 20 minutes. Blend half. Serve with tortilla chips, avocado, sour cream and lime.",ingredienti:[{nome:"Fagioli neri cotti",qt:"500g"},{nome:"Peperone",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Cumino",qt:"2 cucchiaini"},{nome:"Coriandolo",qt:"20g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Avocado",qt:"1"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Zuppa di fagioli neri alla messicana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:13,gs:1,g:7,z:3,ch:38,fi:12,ca:65,fe:4,mg:75,k2:700,na:320,zn:2.5,fo:150,se:4,col:5}},{id:"tpl_1321",nome:"Cassoeula lombarda",nome_en:"Lombard cassoeula pork and cabbage",categoria:"Secondo piatto",porzioni:6,note:"Rosolare verze tagliate con cipolla in olio. Aggiungere costine, salsiccia, cotechino e verzini a pezzi. Versare poco vino bianco e brodo. Cuocere coperto 2 ore. Piatto invernale lombardo per eccellenza da gustare con polenta.",note_en:"Sauté sliced savoy cabbage with onion in oil. Add ribs, sausage, cotechino and small sausages. Pour in a little white wine and stock. Cook covered 2 hours. Quintessential Lombard winter dish, best with polenta.",ingredienti:[{nome:"Verza",qt:"1kg"},{nome:"Costine di maiale",qt:"500g"},{nome:"Salsiccia",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Brodo",qt:"300ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Cassoeula lombarda (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:30,gs:9,g:26,z:4,ch:12,fi:6,ca:80,fe:3,mg:50,k2:650,na:680,zn:5,fo:55,se:22,col:85}},{id:"tpl_1322",nome:"Porceddu sardo al forno",nome_en:"Sardinian roast suckling pig",categoria:"Secondo piatto",porzioni:8,note:"Massaggiare il maialino con lardo, aglio, mirto, sale e pepe. Cuocere lentamente al forno a 140 C per 3-4 ore bagnando con vino bianco. Alzare a 220 C per gli ultimi 20 minuti per croccantare la cotenna.",note_en:"Rub suckling pig with lard, garlic, myrtle, salt and pepper. Roast slowly at 140 C for 3-4 hours basting with white wine. Raise to 220 C for last 20 minutes to crisp the skin.",ingredienti:[{nome:"Maialino da latte",qt:"3kg"},{nome:"Lardo",qt:"80g"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Mirto",qt:"4 rametti"},{nome:"Vino bianco",qt:"300ml"},{nome:"Rosmarino",qt:"4 rametti"}],_dbEntry:{n:"Porceddu sardo al forno (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:42,gs:9,g:26,z:0,ch:0,fi:0,ca:25,fe:1.8,mg:35,k2:520,na:380,zn:4.5,fo:10,se:30,col:120}},{id:"tpl_1323",nome:"Tegame di pesce alla pugliese",nome_en:"Apulian fish tray bake",categoria:"Secondo piatto",porzioni:4,note:"Disporre in teglia strati di patate, cipolla, pomodorini, riso crudo e cozze aperte. Condire ogni strato con olio, aglio, prezzemolo e pecorino. Coprire con acqua. Cuocere in forno a 180 C per 45 minuti.",note_en:"Layer in baking dish potatoes, onion, cherry tomatoes, raw rice and opened mussels. Season each layer with oil, garlic, parsley and pecorino. Cover with water. Bake at 180 C for 45 minutes.",ingredienti:[{nome:"Cozze",qt:"1kg"},{nome:"Patate",qt:"400g"},{nome:"Riso",qt:"150g"},{nome:"Pomodorini",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Tegame di pesce alla pugliese (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:22,gs:2.5,g:12,z:4,ch:42,fi:3.5,ca:110,fe:5,mg:60,k2:620,na:520,zn:2.5,fo:42,se:40,col:60}},{id:"tpl_1324",nome:"Timballo di riso al forno",nome_en:"Baked rice timbale",categoria:"Primo piatto",porzioni:6,note:"Cuocere il riso al dente. Mescolare con sugo di carne, piselli, mozzarella e parmigiano. Rivestire lo stampo con pangrattato imburrato. Versare il riso. Cuocere in forno a 180 C per 30 minuti. Sformare e servire.",note_en:"Cook rice al dente. Mix with meat sauce, peas, mozzarella and parmesan. Line mould with buttered breadcrumbs. Pour in rice. Bake at 180 C for 30 minutes. Unmould and serve.",ingredienti:[{nome:"Riso",qt:"400g"},{nome:"Sugo di carne",qt:"300ml"},{nome:"Piselli",qt:"150g"},{nome:"Mozzarella",qt:"150g"},{nome:"Parmigiano",qt:"80g"},{nome:"Burro",qt:"40g"},{nome:"Pangrattato",qt:"60g"}],_dbEntry:{n:"Timballo di riso al forno (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:17,gs:5.5,g:14,z:3,ch:55,fi:2,ca:180,fe:2,mg:38,k2:350,na:420,zn:2.5,fo:35,se:15,col:55}},{id:"tpl_1325",nome:"Pasta alla carbonara con guanciale DOP",nome_en:"Carbonara pasta with DOP guanciale",categoria:"Primo piatto",porzioni:4,note:"Rosolare il guanciale tagliato a listarelle senza aggiunta di olio. Sbattere tuorli con pecorino romano DOP e abbondante pepe nero. Cuocere gli spaghetti al dente. Fuori dal fuoco amalgamare uova, guanciale e poca acqua di cottura.",note_en:"Brown guanciale strips without adding oil. Beat egg yolks with DOP pecorino romano and plenty of black pepper. Cook spaghetti al dente. Off heat combine eggs, guanciale and a little cooking water.",ingredienti:[{nome:"Spaghetti di semola",qt:"320g"},{nome:"Guanciale",qt:"180g"},{nome:"Tuorli",qt:"5"},{nome:"Pecorino romano DOP",qt:"100g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla carbonara con guanciale DOP (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:24,gs:10,g:22,z:1,ch:57,fi:1,ca:220,fe:2,mg:35,k2:250,na:720,zn:3,fo:55,se:22,col:360}},{id:"tpl_1326",nome:"Risotto alla crema di scampi",nome_en:"Scampi cream risotto",categoria:"Primo piatto",porzioni:4,note:"Sgusciare gli scampi tenendo teste e carapaci per il fumetto. Preparare fumetto con teste, cipolla e vino. Tostare il riso in scalogno e burro. Aggiungere il fumetto a mestoli. Aggiungere gli scampi negli ultimi 5 minuti. Mantecare con burro.",note_en:"Shell scampi keeping heads and shells for bisque. Make bisque with heads, onion and wine. Toast rice in shallot and butter. Add bisque ladle by ladle. Add scampi in last 5 minutes. Finish with butter.",ingredienti:[{nome:"Scampi",qt:"600g"},{nome:"Riso Carnaroli",qt:"320g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Burro",qt:"50g"},{nome:"Panna",qt:"60ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Risotto alla crema di scampi (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:22,gs:8,g:16,z:2,ch:55,fi:.5,ca:60,fe:1.5,mg:42,k2:380,na:420,zn:2,fo:18,se:38,col:145}},{id:"tpl_1327",nome:"Gnudi di ricotta e spinaci",nome_en:"Ricotta and spinach gnudi",categoria:"Primo piatto",porzioni:4,note:"Strizzare benissimo gli spinaci lessati. Tritare finemente. Mescolare con ricotta, uovo, parmigiano, noce moscata e poca farina. Formare palline. Tuffare in acqua bollente salata. Scolare quando vengono a galla. Condire con burro e salvia.",note_en:"Squeeze boiled spinach very well. Chop finely. Mix with ricotta, egg, parmesan, nutmeg and a little flour. Shape into balls. Drop into salted boiling water. Drain when they float. Dress with butter and sage.",ingredienti:[{nome:"Spinaci",qt:"400g"},{nome:"Ricotta",qt:"300g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano",qt:"60g"},{nome:"Farina",qt:"40g"},{nome:"Burro",qt:"50g"},{nome:"Salvia",qt:"8 foglie"}],_dbEntry:{n:"Gnudi di ricotta e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:16,gs:9,g:18,z:2,ch:20,fi:3,ca:300,fe:3.5,mg:55,k2:450,na:280,zn:2,fo:160,se:12,col:110}},{id:"tpl_1328",nome:"Tortelli di zucca mantovani",nome_en:"Mantua pumpkin tortelli",categoria:"Primo piatto",porzioni:6,note:"Preparare ripieno con zucca al forno, amaretti sbriciolati, mostarda di Mantova, parmigiano e noce moscata. Preparare la sfoglia all'uovo. Formare i tortelli. Cuocere in acqua salata. Condire con burro fuso, salvia e parmigiano abbondante.",note_en:"Make filling with oven-roasted pumpkin, crumbled amaretti, Mantua mostarda, parmesan and nutmeg. Make egg pasta dough. Form tortelli. Cook in salted water. Dress with melted butter, sage and plenty of parmesan.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Zucca",qt:"500g"},{nome:"Amaretti",qt:"40g"},{nome:"Mostarda di Mantova",qt:"40g"},{nome:"Parmigiano",qt:"80g"},{nome:"Burro",qt:"80g"},{nome:"Salvia",qt:"12 foglie"}],_dbEntry:{n:"Tortelli di zucca mantovani (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:15,gs:8,g:16,z:6,ch:58,fi:2.5,ca:180,fe:2.5,mg:42,k2:380,na:320,zn:2,fo:35,se:12,col:150}},{id:"tpl_1329",nome:"Vincisgrassi marchigiani",nome_en:"Marche-style baked pasta vincisgrassi",categoria:"Primo piatto",porzioni:8,note:"Preparare ragu ricco con rigaglie di pollo, vitello, prosciutto e funghi porcini. Preparare besciamella. Foderare teglia con sfoglia all'uovo. Alternare strati con ragu e besciamella. Spolverare con parmigiano. Cuocere a 180 C per 40 minuti.",note_en:"Make rich ragu with chicken giblets, veal, ham and porcini mushrooms. Make bechamel. Line tin with egg pasta. Alternate layers with ragu and bechamel. Sprinkle parmesan. Bake at 180 C for 40 minutes.",ingredienti:[{nome:"Sfoglia all uovo",qt:"400g"},{nome:"Rigaglie di pollo",qt:"200g"},{nome:"Macinato di vitello",qt:"200g"},{nome:"Porcini secchi",qt:"20g"},{nome:"Latte",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"80g"},{nome:"Parmigiano",qt:"100g"}],_dbEntry:{n:"Vincisgrassi marchigiani (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:24,gs:9,g:20,z:4,ch:50,fi:2,ca:250,fe:3,mg:42,k2:380,na:560,zn:3.5,fo:45,se:20,col:160}},{id:"tpl_1330",nome:"Polenta taragna con spezzatino",nome_en:"Taragna polenta with stew",categoria:"Piatto unico",porzioni:6,note:"Cuocere la polenta taragna 45 minuti. Preparare uno spezzatino di manzo con verdure e vino rosso. Servire la polenta morbida con lo spezzatino sopra. Piatto montano completo e sostanzioso della tradizione lombarda.",note_en:"Cook taragna polenta 45 minutes. Prepare beef stew with vegetables and red wine. Serve soft polenta topped with stew. Complete and hearty mountain dish from Lombard tradition.",ingredienti:[{nome:"Farina per polenta taragna",qt:"300g"},{nome:"Manzo per spezzatino",qt:"600g"},{nome:"Vino rosso",qt:"150ml"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Burro",qt:"50g"},{nome:"Taleggio",qt:"80g"}],_dbEntry:{n:"Polenta taragna con spezzatino (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:32,gs:8,g:20,z:4,ch:52,fi:4,ca:150,fe:4,mg:50,k2:650,na:420,zn:6,fo:28,se:28,col:95}},{id:"tpl_1331",nome:"Cous cous con verdure e ceci",nome_en:"Couscous with vegetables and chickpeas",categoria:"Piatto unico",porzioni:4,note:"Cuocere il cous cous con acqua bollente salata e olio, sgranare con una forchetta. Saltare in padella zucchine, carote e peperoni a cubetti con cipolla. Unire i ceci lessati e le verdure al cous cous. Condire con olio, menta e limone.",note_en:"Cook couscous with boiling salted water and oil, fluff with a fork. Sauté diced courgettes, carrots and peppers with onion. Add boiled chickpeas and vegetables to couscous. Dress with oil, mint and lemon.",ingredienti:[{nome:"Cous cous",qt:"280g"},{nome:"Ceci lessati",qt:"300g"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Peperoni",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Menta",qt:"10g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Cous cous con verdure e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:410,p:14,gs:1.5,g:9,z:6,ch:68,fi:8,ca:70,fe:3,mg:60,k2:520,na:280,zn:2,fo:90,se:8,col:0}},{id:"tpl_1332",nome:"Poke bowl di salmone e riso",nome_en:"Salmon poke bowl",categoria:"Piatto unico",porzioni:2,note:"Cuocere il riso e condirlo con aceto di riso. Tagliare il salmone crudo a cubetti e marinare con salsa di soia e sesamo. Comporre la bowl con riso, salmone, avocado, edamame, cetriolo e alga nori a listarelle.",note_en:"Cook rice and dress with rice vinegar. Cut raw salmon into cubes and marinate with soy sauce and sesame. Assemble bowl with rice, salmon, avocado, edamame, cucumber and nori strips.",ingredienti:[{nome:"Salmone fresco",qt:"250g"},{nome:"Riso",qt:"160g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"100g"},{nome:"Cetriolo",qt:"100g"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Alga nori",qt:"2 fogli"}],_dbEntry:{n:"Poke bowl di salmone e riso (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:28,gs:4,g:22,z:3,ch:55,fi:6,ca:60,fe:2,mg:70,k2:750,na:680,zn:2,fo:60,se:35,col:45}},{id:"tpl_1333",nome:"Paella di pesce",nome_en:"Seafood paella",categoria:"Piatto unico",porzioni:6,note:"Preparare un soffritto di cipolla, aglio e peperone. Aggiungere il riso e tostarlo con lo zafferano. Bagnare gradualmente con brodo di pesce. Unire cozze, gamberi, calamari e vongole. Cuocere senza mescolare fino ad asciugare il brodo.",note_en:"Prepare a sofrito of onion, garlic and pepper. Add rice and toast with saffron. Gradually add fish stock. Add mussels, prawns, squid and clams. Cook without stirring until stock is absorbed.",ingredienti:[{nome:"Riso",qt:"400g"},{nome:"Cozze",qt:"300g"},{nome:"Gamberi",qt:"250g"},{nome:"Calamari",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Peperone",qt:"1"},{nome:"Brodo di pesce",qt:"900ml"}],_dbEntry:{n:"Paella di pesce (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:26,gs:1.5,g:6,z:2,ch:60,fi:2,ca:80,fe:2.5,mg:55,k2:480,na:580,zn:2,fo:35,se:40,col:110}},{id:"tpl_1334",nome:"Burrito bowl con pollo e fagioli neri",nome_en:"Chicken and black bean burrito bowl",categoria:"Piatto unico",porzioni:4,note:"Cuocere il pollo a cubetti con paprika e cumino. Preparare riso, fagioli neri, mais, pomodorini e avocado a dadini. Comporre la bowl con tutti gli ingredienti e guarnire con lime e coriandolo fresco.",note_en:"Cook diced chicken with paprika and cumin. Prepare rice, black beans, corn, cherry tomatoes and diced avocado. Assemble bowl with all ingredients and garnish with lime and fresh coriander.",ingredienti:[{nome:"Petto di pollo",qt:"400g"},{nome:"Riso",qt:"200g"},{nome:"Fagioli neri",qt:"250g"},{nome:"Mais",qt:"100g"},{nome:"Avocado",qt:"1"},{nome:"Pomodorini",qt:"150g"},{nome:"Lime",qt:"1"},{nome:"Coriandolo",qt:"10g"}],_dbEntry:{n:"Burrito bowl con pollo e fagioli neri (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:32,gs:2,g:12,z:3,ch:60,fi:9,ca:60,fe:3,mg:70,k2:800,na:320,zn:2.5,fo:80,se:26,col:65}},{id:"tpl_1335",nome:"Riso alla cantonese con gamberi e verdure",nome_en:"Cantonese-style rice with prawns and vegetables",categoria:"Piatto unico",porzioni:4,note:"Cuocere il riso e raffreddarlo. Saltare in wok uova strapazzate, piselli, carote e gamberi. Aggiungere il riso freddo e la salsa di soia. Saltare a fuoco vivo qualche minuto mescolando bene.",note_en:"Cook rice and let it cool. Stir-fry scrambled eggs, peas, carrots and prawns in wok. Add cold rice and soy sauce. Stir-fry over high heat a few minutes, mixing well.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Gamberi",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Piselli",qt:"100g"},{nome:"Carote",qt:"80g"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"10ml"}],_dbEntry:{n:"Riso alla cantonese con gamberi e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:22,gs:2,g:9,z:3,ch:65,fi:3,ca:60,fe:2,mg:45,k2:400,na:620,zn:1.5,fo:40,se:28,col:150}},{id:"tpl_1336",nome:"Buddha bowl vegetariano con tofu",nome_en:"Vegetarian tofu Buddha bowl",categoria:"Piatto unico",porzioni:2,note:"Marinare il tofu a cubetti con salsa di soia e zenzero, poi saltare in padella fino a dorare. Comporre la bowl con quinoa, cavolo rosso, carote julienne, avocado ed edamame. Condire con salsa tahina e limone.",note_en:"Marinate diced tofu with soy sauce and ginger, then pan-fry until golden. Assemble bowl with quinoa, red cabbage, julienne carrots, avocado and edamame. Dress with tahini and lemon sauce.",ingredienti:[{nome:"Tofu",qt:"200g"},{nome:"Quinoa",qt:"150g"},{nome:"Cavolo rosso",qt:"100g"},{nome:"Carote",qt:"80g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"80g"},{nome:"Tahina",qt:"30g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Buddha bowl vegetariano con tofu (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:20,gs:3,g:24,z:4,ch:42,fi:11,ca:220,fe:4,mg:110,k2:750,na:380,zn:2.5,fo:110,se:8,col:0}},{id:"tpl_1337",nome:"Parmigiana di melanzane",nome_en:"Eggplant parmigiana",categoria:"Piatto unico",porzioni:6,note:"Grigliare le melanzane a fette senza friggere. Alternare in teglia strati di melanzane, sugo di pomodoro, mozzarella e parmigiano. Terminare con parmigiano e basilico. Cuocere in forno a 190 C per 35 minuti.",note_en:"Grill eggplant slices without frying. Layer in baking dish alternating eggplant, tomato sauce, mozzarella and parmesan. Finish with parmesan and basil. Bake at 190 C for 35 minutes.",ingredienti:[{nome:"Melanzane",qt:"1kg"},{nome:"Passata di pomodoro",qt:"500g"},{nome:"Mozzarella",qt:"300g"},{nome:"Parmigiano",qt:"80g"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Parmigiana di melanzane (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:16,gs:6,g:20,z:6,ch:14,fi:5,ca:280,fe:1.5,mg:35,k2:520,na:420,zn:2,fo:40,se:10,col:35}},{id:"tpl_1338",nome:"Cassoulet di fagioli e salsiccia",nome_en:"Bean and sausage cassoulet",categoria:"Piatto unico",porzioni:6,note:"Rosolare la salsiccia a tocchetti con cipolla, carota e sedano. Aggiungere i fagioli borlotti lessati, pomodori pelati e alloro. Cuocere in forno a 180 C per 40 minuti finché si forma una crosticina in superficie.",note_en:"Brown diced sausage with onion, carrot and celery. Add boiled borlotti beans, peeled tomatoes and bay leaf. Bake at 180 C for 40 minutes until a crust forms on top.",ingredienti:[{nome:"Salsiccia",qt:"400g"},{nome:"Fagioli borlotti",qt:"500g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Alloro",qt:"2 foglie"}],_dbEntry:{n:"Cassoulet di fagioli e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:26,gs:9,g:26,z:5,ch:35,fi:10,ca:90,fe:4,mg:70,k2:850,na:680,zn:3,fo:120,se:18,col:60}},{id:"tpl_1339",nome:"Zuppa di pesce con crostini",nome_en:"Fish soup with croutons",categoria:"Piatto unico",porzioni:4,note:"Rosolare aglio e peperoncino in olio. Aggiungere pomodori pelati e vino bianco. Unire pesce misto e frutti di mare, cuocere 15 minuti. Servire con crostini di pane tostato strofinati con aglio.",note_en:"Brown garlic and chili in oil. Add peeled tomatoes and white wine. Add mixed fish and seafood, cook 15 minutes. Serve with toasted bread croutons rubbed with garlic.",ingredienti:[{nome:"Pesce misto",qt:"600g"},{nome:"Cozze",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Pane casereccio",qt:"200g"}],_dbEntry:{n:"Zuppa di pesce con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:34,gs:1.5,g:8,z:3,ch:38,fi:2.5,ca:100,fe:3,mg:60,k2:650,na:620,zn:2,fo:35,se:45,col:100}},{id:"tpl_1340",nome:"Chili con carne e riso integrale",nome_en:"Chili con carne with brown rice",categoria:"Piatto unico",porzioni:4,note:"Rosolare la carne macinata con cipolla e aglio. Aggiungere fagioli rossi, pomodori pelati, peperoncino e cumino. Cuocere 30 minuti a fuoco lento. Servire con riso integrale lessato.",note_en:"Brown minced meat with onion and garlic. Add kidney beans, peeled tomatoes, chili and cumin. Simmer 30 minutes on low heat. Serve with boiled brown rice.",ingredienti:[{nome:"Macinato di manzo",qt:"400g"},{nome:"Fagioli rossi",qt:"300g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Riso integrale",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Peperoncino",qt:"1"},{nome:"Cumino",qt:"5g"}],_dbEntry:{n:"Chili con carne e riso integrale (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:32,gs:5,g:14,z:4,ch:62,fi:10,ca:70,fe:5,mg:90,k2:850,na:380,zn:5,fo:100,se:22,col:65}},{id:"tpl_1341",nome:"Insalata di riso estiva completa",nome_en:"Complete summer rice salad",categoria:"Piatto unico",porzioni:4,note:"Lessare il riso e raffreddarlo sotto acqua corrente. Condire con tonno, prosciutto cotto a dadini, mais, olive, pomodorini e mozzarelline. Aggiungere olio extravergine e origano.",note_en:"Boil rice and cool under running water. Dress with tuna, diced cooked ham, corn, olives, cherry tomatoes and mozzarella balls. Add extra virgin oil and oregano.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Tonno sott olio",qt:"150g"},{nome:"Prosciutto cotto",qt:"100g"},{nome:"Mais",qt:"100g"},{nome:"Mozzarelline",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olive",qt:"60g"}],_dbEntry:{n:"Insalata di riso estiva completa (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:22,gs:6,g:16,z:4,ch:58,fi:2.5,ca:150,fe:2,mg:40,k2:420,na:680,zn:2,fo:25,se:30,col:55}},{id:"tpl_1342",nome:"Farrotto con funghi e salsiccia",nome_en:"Farro risotto with mushrooms and sausage",categoria:"Piatto unico",porzioni:4,note:"Rosolare la salsiccia sbriciolata con funghi porcini. Tostare il farro e sfumare con vino bianco. Aggiungere brodo vegetale a mestoli, cuocendo come un risotto per 25 minuti. Mantecare con parmigiano.",note_en:"Brown crumbled sausage with porcini mushrooms. Toast farro and deglaze with white wine. Add vegetable stock ladle by ladle, cooking like a risotto for 25 minutes. Finish with parmesan.",ingredienti:[{nome:"Farro perlato",qt:"320g"},{nome:"Salsiccia",qt:"200g"},{nome:"Funghi porcini",qt:"250g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Parmigiano",qt:"50g"}],_dbEntry:{n:"Farrotto con funghi e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:22,gs:7,g:18,z:2,ch:58,fi:8,ca:110,fe:3,mg:80,k2:600,na:520,zn:3,fo:35,se:20,col:45}},{id:"tpl_1343",nome:"Cotoletta di pollo con insalata e patate",nome_en:"Chicken cutlet with salad and potatoes",categoria:"Piatto unico",porzioni:4,note:"Impanare le fettine di pollo con pangrattato e parmigiano. Cuocere in forno su carta forno con poco olio a 200 C per 20 minuti. Servire con patate al forno e insalata mista condita.",note_en:"Bread chicken slices with breadcrumbs and parmesan. Bake on parchment paper with a little oil at 200 C for 20 minutes. Serve with baked potatoes and dressed mixed salad.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Pangrattato",qt:"80g"},{nome:"Parmigiano",qt:"30g"},{nome:"Patate",qt:"500g"},{nome:"Insalata mista",qt:"150g"},{nome:"Uova",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Cotoletta di pollo con insalata e patate (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:36,gs:3,g:14,z:3,ch:45,fi:5,ca:100,fe:2.5,mg:60,k2:900,na:380,zn:2,fo:45,se:30,col:110}},{id:"tpl_1344",nome:"Wok di tofu, verdure e noodles",nome_en:"Tofu, vegetable and noodle stir-fry",categoria:"Piatto unico",porzioni:2,note:"Cuocere i noodles secondo le istruzioni e scolare. Saltare in wok tofu a cubetti fino a dorare, poi aggiungere carote, peperoni, cavolo cinese e germogli di soia. Unire i noodles e salsa di soia, saltare 3 minuti.",note_en:"Cook noodles per instructions and drain. Stir-fry diced tofu in wok until golden, then add carrots, peppers, Chinese cabbage and bean sprouts. Add noodles and soy sauce, stir-fry 3 minutes.",ingredienti:[{nome:"Noodles di riso",qt:"160g"},{nome:"Tofu",qt:"200g"},{nome:"Carote",qt:"80g"},{nome:"Peperoni",qt:"100g"},{nome:"Cavolo cinese",qt:"100g"},{nome:"Germogli di soia",qt:"80g"},{nome:"Salsa di soia",qt:"30ml"}],_dbEntry:{n:"Wok di tofu, verdure e noodles (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:2,g:10,z:5,ch:62,fi:5,ca:180,fe:3,mg:70,k2:520,na:650,zn:1.5,fo:60,se:6,col:0}},{id:"tpl_1345",nome:"Piadina con prosciutto, stracchino e rucola",nome_en:"Piadina with ham, stracchino and rocket",categoria:"Piatto unico",porzioni:2,note:"Preparare la piada con farina, acqua, olio e un pizzico di sale, cuocere su piastra antiaderente. Farcire con stracchino, prosciutto crudo e rucola fresca. Piegare a metà e servire calda.",note_en:"Make flatbread with flour, water, oil and a pinch of salt, cook on non-stick griddle. Fill with stracchino cheese, raw ham and fresh rocket. Fold in half and serve warm.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Stracchino",qt:"150g"},{nome:"Prosciutto crudo",qt:"100g"},{nome:"Rucola",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Piadina con prosciutto, stracchino e rucola (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:24,gs:8,g:22,z:2,ch:58,fi:2,ca:150,fe:2,mg:35,k2:280,na:850,zn:2,fo:25,se:20,col:60}},{id:"tpl_1346",nome:"Bowl mediterraneo con quinoa, feta e verdure grigliate",nome_en:"Mediterranean bowl with quinoa, feta and grilled vegetables",categoria:"Piatto unico",porzioni:2,note:"Cuocere la quinoa e lasciarla raffreddare. Grigliare zucchine, melanzane e peperoni. Comporre la bowl con quinoa, verdure grigliate, feta sbriciolata e olive taggiasche. Condire con olio e origano.",note_en:"Cook quinoa and let it cool. Grill courgettes, eggplant and peppers. Assemble bowl with quinoa, grilled vegetables, crumbled feta and Taggiasca olives. Dress with oil and oregano.",ingredienti:[{nome:"Quinoa",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"100g"},{nome:"Feta",qt:"100g"},{nome:"Olive taggiasche",qt:"40g"}],_dbEntry:{n:"Bowl mediterraneo con quinoa, feta e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:6,g:18,z:5,ch:48,fi:8,ca:220,fe:3,mg:80,k2:650,na:520,zn:2,fo:90,se:8,col:35}},{id:"tpl_1347",nome:"Riso al salto con verdure e uovo",nome_en:"Fried rice cake with vegetables and egg",categoria:"Piatto unico",porzioni:2,note:"Compattare il riso avanzato in una padella antiaderente con poco olio, cuocere fino a formare una crosticina dorata su entrambi i lati. Servire con verdure saltate e un uovo all occhio di bue.",note_en:"Press leftover rice into a non-stick pan with a little oil, cook until a golden crust forms on both sides. Serve with sautéed vegetables and a sunny-side-up egg.",ingredienti:[{nome:"Riso avanzato",qt:"300g"},{nome:"Uova",qt:"2"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"80g"},{nome:"Parmigiano",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Riso al salto con verdure e uovo (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:16,gs:3,g:14,z:3,ch:52,fi:3,ca:110,fe:2,mg:40,k2:380,na:280,zn:1.5,fo:30,se:18,col:190}},{id:"tpl_1348",nome:"Minestrone con orzo e parmigiano",nome_en:"Minestrone with barley and parmesan",categoria:"Piatto unico",porzioni:4,note:"Rosolare cipolla, carota e sedano in olio. Aggiungere zucchine, patate, fagiolini e pomodori pelati. Coprire con brodo vegetale e unire l orzo. Cuocere 30 minuti. Servire con parmigiano grattugiato.",note_en:"Brown onion, carrot and celery in oil. Add courgettes, potatoes, green beans and peeled tomatoes. Cover with vegetable stock and add barley. Cook 30 minutes. Serve with grated parmesan.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Zucchine",qt:"150g"},{nome:"Patate",qt:"150g"},{nome:"Fagiolini",qt:"100g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Minestrone con orzo e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:2.5,g:8,z:5,ch:56,fi:8,ca:150,fe:2.5,mg:60,k2:650,na:380,zn:1.5,fo:60,se:8,col:10}},{id:"tpl_1349",nome:"Involtini di pollo ripieni con contorno di verdure",nome_en:"Stuffed chicken rolls with vegetable side",categoria:"Piatto unico",porzioni:4,note:"Appiattire le fettine di pollo e farcire con spinaci, ricotta e parmigiano. Arrotolare e fissare con stecchini. Rosolare e cuocere in forno a 190 C per 20 minuti. Servire con verdure al vapore.",note_en:"Flatten chicken slices and stuff with spinach, ricotta and parmesan. Roll up and secure with toothpicks. Brown and bake at 190 C for 20 minutes. Serve with steamed vegetables.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Spinaci",qt:"200g"},{nome:"Ricotta",qt:"150g"},{nome:"Parmigiano",qt:"40g"},{nome:"Carote",qt:"150g"},{nome:"Broccoli",qt:"200g"}],_dbEntry:{n:"Involtini di pollo ripieni con contorno di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:40,gs:4,g:14,z:3,ch:12,fi:5,ca:220,fe:2.5,mg:60,k2:750,na:280,zn:2,fo:80,se:32,col:130}},{id:"tpl_1350",nome:"Ciambotta di verdure con uova in camicia",nome_en:"Vegetable ciambotta with poached eggs",categoria:"Piatto unico",porzioni:4,note:"Cuocere in olio patate, melanzane, peperoni, zucchine e pomodori a tocchetti fino a renderli morbidi. Fare delle piccole conche nel composto e cuocere le uova in camicia direttamente nella verdura per 4 minuti.",note_en:"Cook potatoes, eggplant, peppers, courgettes and tomatoes in oil until soft. Make small wells in the mixture and poach eggs directly in the vegetables for 4 minutes.",ingredienti:[{nome:"Patate",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Peperoni",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Pomodori",qt:"200g"},{nome:"Uova",qt:"4"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Ciambotta di verdure con uova in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:2.5,g:16,z:6,ch:32,fi:7,ca:80,fe:2.5,mg:50,k2:850,na:220,zn:1.5,fo:70,se:20,col:190}},{id:"tpl_1351",nome:"Yogurt greco con miele e noci",nome_en:"Greek yogurt with honey and walnuts",categoria:"Spuntino",porzioni:1,note:"Versare lo yogurt greco in una ciotola, aggiungere un cucchiaino di miele e le noci sgusciate spezzettate. Mescolare leggermente e servire subito.",note_en:"Pour Greek yogurt into a bowl, add a teaspoon of honey and crushed shelled walnuts. Stir lightly and serve immediately.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"10g"},{nome:"Noci",qt:"15g"}],_dbEntry:{n:"Yogurt greco con miele e noci (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:14,gs:3,g:11,z:12,ch:12,fi:.5,ca:150,fe:.5,mg:25,k2:220,na:50,zn:1,fo:8,se:5,col:15}},{id:"tpl_1352",nome:"Frullato verde detox",nome_en:"Green detox smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare spinaci freschi, mela, sedano, limone e acqua fino a ottenere un composto omogeneo. Servire fresco appena preparato per mantenere le vitamine.",note_en:"Blend fresh spinach, apple, celery, lemon and water until smooth. Serve fresh right after preparation to preserve vitamins.",ingredienti:[{nome:"Spinaci",qt:"50g"},{nome:"Mela",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Limone",qt:"0.5"},{nome:"Acqua",qt:"150ml"}],_dbEntry:{n:"Frullato verde detox (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2,gs:.1,g:.5,z:16,ch:20,fi:4,ca:60,fe:1.5,mg:35,k2:400,na:40,zn:.4,fo:80,se:2,col:0}},{id:"tpl_1353",nome:"Chips di ceci al forno",nome_en:"Oven-baked chickpea chips",categoria:"Spuntino",porzioni:4,note:"Asciugare bene i ceci lessati con carta assorbente. Condire con olio, paprika e sale. Distribuire su una teglia e cuocere in forno a 200 C per 30-35 minuti girando a metà cottura, finché croccanti.",note_en:"Dry boiled chickpeas well with paper towel. Season with oil, paprika and salt. Spread on a tray and bake at 200 C for 30-35 minutes turning halfway, until crispy.",ingredienti:[{nome:"Ceci lessati",qt:"400g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Paprika",qt:"5g"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di ceci al forno (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:8,gs:.5,g:5,z:2,ch:22,fi:6,ca:50,fe:2,mg:40,k2:280,na:180,zn:1.2,fo:130,se:3,col:0}},{id:"tpl_1354",nome:"Muffin salati con zucchine e feta",nome_en:"Savoury muffins with courgette and feta",categoria:"Spuntino",porzioni:12,note:"Grattugiare le zucchine e strizzarle. Mescolare farina, uova, olio, lievito, zucchine e feta sbriciolata. Versare negli stampini da muffin e cuocere in forno a 180 C per 25 minuti.",note_en:"Grate courgettes and squeeze out water. Mix flour, eggs, oil, baking powder, courgettes and crumbled feta. Pour into muffin tins and bake at 180 C for 25 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Zucchine",qt:"200g"},{nome:"Feta",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Lievito per torte salate",qt:"1 bustina"}],_dbEntry:{n:"Muffin salati con zucchine e feta (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:2,g:8,z:2,ch:15,fi:1,ca:80,fe:1,mg:15,k2:80,na:180,zn:.5,fo:20,se:8,col:45}},{id:"tpl_1355",nome:"Toast integrale con hummus e pomodorini",nome_en:"Wholewheat toast with hummus and cherry tomatoes",categoria:"Spuntino",porzioni:1,note:"Tostare il pane integrale. Spalmare abbondante hummus e guarnire con pomodorini tagliati a metà, un filo di olio e origano.",note_en:"Toast wholewheat bread. Spread plenty of hummus and top with halved cherry tomatoes, a drizzle of oil and oregano.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Hummus",qt:"60g"},{nome:"Pomodorini",qt:"80g"},{nome:"Olio extravergine",qt:"5ml"}],_dbEntry:{n:"Toast integrale con hummus e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:1,g:9,z:3,ch:28,fi:5,ca:40,fe:2,mg:35,k2:280,na:280,zn:1,fo:35,se:4,col:0}},{id:"tpl_1356",nome:"Spiedini di frutta fresca",nome_en:"Fresh fruit skewers",categoria:"Spuntino",porzioni:4,note:"Tagliare la frutta a cubetti di dimensione simile. Infilzare alternando i colori su spiedini di legno. Servire freschi, eventualmente con una spolverata di cocco rapé.",note_en:"Cut fruit into similarly-sized cubes. Skewer alternating colours on wooden sticks. Serve fresh, optionally dusted with desiccated coconut.",ingredienti:[{nome:"Ananas",qt:"150g"},{nome:"Fragole",qt:"150g"},{nome:"Melone",qt:"150g"},{nome:"Uva",qt:"100g"},{nome:"Cocco rapé",qt:"10g"}],_dbEntry:{n:"Spiedini di frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1,gs:.5,g:1,z:18,ch:20,fi:2.5,ca:20,fe:.4,mg:15,k2:250,na:5,zn:.2,fo:25,se:1,col:0}},{id:"tpl_1357",nome:"Popcorn leggero al forno",nome_en:"Light oven-air popcorn",categoria:"Spuntino",porzioni:4,note:"Scoppiare il mais in padella coperta con un filo di olio a fuoco medio, scuotendo di tanto in tanto. Versare in una ciotola e condire con un pizzico di sale, evitando burro aggiunto.",note_en:"Pop corn in a covered pan with a drizzle of oil over medium heat, shaking occasionally. Pour into a bowl and season with a pinch of salt, avoiding added butter.",ingredienti:[{nome:"Mais da popcorn",qt:"100g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Popcorn leggero al forno (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3,gs:.5,g:4,z:.5,ch:20,fi:3.5,ca:5,fe:1,mg:35,k2:100,na:150,zn:.8,fo:10,se:2,col:0}},{id:"tpl_1358",nome:"Palline di cocco e mandorle",nome_en:"Coconut and almond energy balls",categoria:"Spuntino",porzioni:10,note:"Frullare mandorle, datteri denocciolati e cocco rapé fino a ottenere un impasto compatto. Formare delle palline con le mani e passarle nel cocco rapé. Conservare in frigo.",note_en:"Blend almonds, pitted dates and desiccated coconut until a compact dough forms. Shape into balls by hand and roll in desiccated coconut. Store in the fridge.",ingredienti:[{nome:"Mandorle",qt:"150g"},{nome:"Datteri",qt:"150g"},{nome:"Cocco rapé",qt:"60g"}],_dbEntry:{n:"Palline di cocco e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:3,gs:2,g:7,z:11,ch:12,fi:2,ca:35,fe:.8,mg:30,k2:180,na:2,zn:.5,fo:8,se:1,col:0}},{id:"tpl_1359",nome:"Crema di ceci e limone con verdure crude",nome_en:"Lemon chickpea dip with raw vegetables",categoria:"Spuntino",porzioni:4,note:"Frullare ceci lessati, tahina, succo di limone, aglio e olio fino a ottenere una crema liscia. Servire con bastoncini di carota, sedano e finocchio crudi.",note_en:"Blend boiled chickpeas, tahini, lemon juice, garlic and oil until smooth. Serve with raw carrot, celery and fennel sticks.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Tahina",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Carote",qt:"150g"},{nome:"Sedano",qt:"100g"},{nome:"Finocchio",qt:"150g"}],_dbEntry:{n:"Crema di ceci e limone con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:8,gs:1,g:8,z:5,ch:22,fi:7,ca:60,fe:2,mg:45,k2:380,na:150,zn:1.2,fo:90,se:3,col:0}},{id:"tpl_1360",nome:"Frullato di banana e burro di arachidi",nome_en:"Banana and peanut butter smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare la banana con latte, un cucchiaio di burro di arachidi e ghiaccio fino a ottenere una consistenza cremosa. Servire subito.",note_en:"Blend banana with milk, a spoon of peanut butter and ice until creamy. Serve immediately.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Latte",qt:"200ml"},{nome:"Burro di arachidi",qt:"20g"},{nome:"Ghiaccio",qt:"q.b."}],_dbEntry:{n:"Frullato di banana e burro di arachidi (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:11,gs:3,g:12,z:24,ch:34,fi:3,ca:220,fe:.8,mg:60,k2:600,na:120,zn:1,fo:25,se:4,col:10}},{id:"tpl_1361",nome:"Cracker di riso con avocado",nome_en:"Rice crackers with avocado",categoria:"Spuntino",porzioni:1,note:"Schiacciare l avocado con succo di limone e un pizzico di sale. Spalmare sui cracker di riso e guarnire con semi di chia o peperoncino a piacere.",note_en:"Mash avocado with lemon juice and a pinch of salt. Spread on rice crackers and top with chia seeds or chili to taste.",ingredienti:[{nome:"Cracker di riso",qt:"4"},{nome:"Avocado",qt:"0.5"},{nome:"Limone",qt:"0.5"},{nome:"Semi di chia",qt:"5g"}],_dbEntry:{n:"Cracker di riso con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:2,g:12,z:1,ch:16,fi:4,ca:20,fe:1,mg:30,k2:350,na:60,zn:.6,fo:40,se:1,col:0}},{id:"tpl_1362",nome:"Uova sode con verdure crude",nome_en:"Hard-boiled eggs with raw vegetables",categoria:"Spuntino",porzioni:1,note:"Cuocere le uova sode per 9 minuti in acqua bollente, raffreddare e sgusciare. Tagliare a metà e servire con bastoncini di carota e cetriolo, un pizzico di sale e pepe.",note_en:"Hard-boil eggs for 9 minutes in boiling water, cool and shell. Cut in half and serve with carrot and cucumber sticks, a pinch of salt and pepper.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Carote",qt:"80g"},{nome:"Cetriolo",qt:"80g"}],_dbEntry:{n:"Uova sode con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:14,gs:3,g:10,z:4,ch:6,fi:2,ca:60,fe:1.8,mg:20,k2:320,na:140,zn:1.2,fo:45,se:20,col:370}},{id:"tpl_1363",nome:"Mix di frutta secca e semi",nome_en:"Nut and seed mix",categoria:"Spuntino",porzioni:6,note:"Mescolare in una ciotola mandorle, noci, nocciole, semi di zucca e semi di girasole. Conservare in un barattolo ermetico e consumare una porzione da 30 grammi al giorno.",note_en:"Mix almonds, walnuts, hazelnuts, pumpkin seeds and sunflower seeds in a bowl. Store in an airtight jar and eat a 30 gram portion per day.",ingredienti:[{nome:"Mandorle",qt:"80g"},{nome:"Noci",qt:"80g"},{nome:"Nocciole",qt:"60g"},{nome:"Semi di zucca",qt:"40g"},{nome:"Semi di girasole",qt:"40g"}],_dbEntry:{n:"Mix di frutta secca e semi (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1.5,g:17,z:1,ch:5,fi:3,ca:50,fe:1.5,mg:70,k2:220,na:2,zn:1.5,fo:20,se:5,col:0}},{id:"tpl_1364",nome:"Yogurt con granola fatta in casa",nome_en:"Yogurt with homemade granola",categoria:"Spuntino",porzioni:1,note:"Preparare la granola tostando in forno fiocchi d avena, miele, olio e frutta secca a pezzi fino a doratura. Servire lo yogurt in coppa con la granola sopra.",note_en:"Prepare granola by baking oat flakes, honey, oil and chopped nuts until golden. Serve yogurt in a bowl topped with granola.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Fiocchi di avena",qt:"30g"},{nome:"Miele",qt:"10g"},{nome:"Mandorle",qt:"15g"}],_dbEntry:{n:"Yogurt con granola fatta in casa (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:10,gs:2,g:9,z:14,ch:26,fi:3,ca:200,fe:1.2,mg:40,k2:280,na:60,zn:1,fo:15,se:6,col:12}},{id:"tpl_1365",nome:"Toast con ricotta e miele",nome_en:"Toast with ricotta and honey",categoria:"Spuntino",porzioni:1,note:"Tostare il pane integrale e spalmare la ricotta fresca. Aggiungere un cucchiaino di miele e una spolverata di cannella a piacere.",note_en:"Toast wholewheat bread and spread fresh ricotta. Add a teaspoon of honey and a dusting of cinnamon to taste.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Ricotta",qt:"80g"},{nome:"Miele",qt:"10g"},{nome:"Cannella",qt:"q.b."}],_dbEntry:{n:"Toast con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:11,gs:3,g:8,z:11,ch:28,fi:3,ca:150,fe:1.5,mg:30,k2:180,na:180,zn:1,fo:20,se:6,col:25}},{id:"tpl_1366",nome:"Bruschetta leggera con pomodoro",nome_en:"Light tomato bruschetta",categoria:"Spuntino",porzioni:2,note:"Tostare le fette di pane. Tagliare i pomodori a cubetti e condire con basilico, olio, sale e aglio tritato. Distribuire il composto sulle fette di pane appena tostate.",note_en:"Toast bread slices. Dice tomatoes and season with basil, oil, salt and minced garlic. Spoon mixture onto freshly toasted bread slices.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Pomodori",qt:"200g"},{nome:"Basilico",qt:"10g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Bruschetta leggera con pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:5,gs:1,g:5,z:3,ch:26,fi:2.5,ca:30,fe:1.5,mg:25,k2:220,na:220,zn:.8,fo:20,se:4,col:0}},{id:"tpl_1367",nome:"Frappè proteico alla fragola",nome_en:"Strawberry protein shake",categoria:"Spuntino",porzioni:1,note:"Frullare fragole fresche, latte, proteine in polvere e ghiaccio fino a ottenere una consistenza omogenea e cremosa. Servire subito in un bicchiere alto.",note_en:"Blend fresh strawberries, milk, protein powder and ice until smooth and creamy. Serve immediately in a tall glass.",ingredienti:[{nome:"Fragole",qt:"150g"},{nome:"Latte",qt:"200ml"},{nome:"Proteine in polvere",qt:"25g"},{nome:"Ghiaccio",qt:"q.b."}],_dbEntry:{n:"Frappè proteico alla fragola (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:24,gs:1.5,g:3,z:20,ch:22,fi:2,ca:280,fe:.8,mg:35,k2:450,na:120,zn:1,fo:20,se:5,col:10}},{id:"tpl_1368",nome:"Involtini di bresaola e formaggio spalmabile",nome_en:"Bresaola and cream cheese rolls",categoria:"Spuntino",porzioni:2,note:"Spalmare le fette di bresaola con formaggio fresco spalmabile e una foglia di rucola. Arrotolare strette e fissare con uno stecchino. Servire fresche.",note_en:"Spread bresaola slices with fresh cream cheese and a rocket leaf. Roll up tightly and secure with a toothpick. Serve chilled.",ingredienti:[{nome:"Bresaola",qt:"100g"},{nome:"Formaggio spalmabile",qt:"60g"},{nome:"Rucola",qt:"20g"}],_dbEntry:{n:"Involtini di bresaola e formaggio spalmabile (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:20,gs:3,g:7,z:.5,ch:2,fi:.3,ca:70,fe:1.8,mg:20,k2:280,na:520,zn:2,fo:8,se:15,col:35}},{id:"tpl_1369",nome:"Muffin ai mirtilli integrali",nome_en:"Wholewheat blueberry muffins",categoria:"Spuntino",porzioni:12,note:"Mescolare farina integrale, uova, yogurt, olio e zucchero di canna. Incorporare delicatamente i mirtilli. Versare negli stampini e cuocere in forno a 180 C per 22 minuti.",note_en:"Mix wholewheat flour, eggs, yogurt, oil and cane sugar. Gently fold in blueberries. Pour into muffin tins and bake at 180 C for 22 minutes.",ingredienti:[{nome:"Farina integrale",qt:"220g"},{nome:"Mirtilli",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Yogurt bianco",qt:"120g"},{nome:"Zucchero di canna",qt:"80g"},{nome:"Olio di semi",qt:"50ml"}],_dbEntry:{n:"Muffin ai mirtilli integrali (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1,g:6,z:9,ch:22,fi:2.5,ca:40,fe:1,mg:20,k2:100,na:80,zn:.5,fo:15,se:5,col:30}},{id:"tpl_1370",nome:"Barrette di frutta secca e cioccolato fondente",nome_en:"Nut and dark chocolate bars",categoria:"Spuntino",porzioni:10,note:"Sciogliere il cioccolato fondente a bagnomaria. Mescolare con frutta secca tritata, fiocchi d avena e miele. Versare in uno stampo rettangolare, raffreddare in frigo e tagliare a barrette.",note_en:"Melt dark chocolate in a double boiler. Mix with chopped nuts, oat flakes and honey. Pour into a rectangular mold, chill in the fridge and cut into bars.",ingredienti:[{nome:"Cioccolato fondente",qt:"100g"},{nome:"Fiocchi di avena",qt:"100g"},{nome:"Mandorle",qt:"80g"},{nome:"Miele",qt:"40g"}],_dbEntry:{n:"Barrette di frutta secca e cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:3,g:10,z:10,ch:18,fi:2.5,ca:30,fe:1.2,mg:40,k2:150,na:5,zn:.6,fo:10,se:3,col:0}},{id:"tpl_1371",nome:"Pancake proteici alla banana",nome_en:"Protein banana pancakes",categoria:"Colazione",porzioni:2,note:"Schiacciare la banana e mescolarla con uova, proteine in polvere e un pizzico di lievito. Versare piccole quantità in padella antiaderente e cuocere 2 minuti per lato fino a doratura.",note_en:"Mash banana and mix with eggs, protein powder and a pinch of baking powder. Pour small amounts into a non-stick pan and cook 2 minutes per side until golden.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Proteine in polvere",qt:"20g"},{nome:"Lievito",qt:"2g"}],_dbEntry:{n:"Pancake proteici alla banana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:22,gs:2,g:8,z:14,ch:22,fi:2,ca:60,fe:1.5,mg:35,k2:450,na:120,zn:1.2,fo:25,se:15,col:190}},{id:"tpl_1372",nome:"Overnight oats con frutti di bosco",nome_en:"Overnight oats with berries",categoria:"Colazione",porzioni:1,note:"Mescolare fiocchi d avena, latte, yogurt e un cucchiaino di miele in un barattolo. Lasciare riposare in frigo tutta la notte. Al mattino guarnire con frutti di bosco freschi.",note_en:"Mix oat flakes, milk, yogurt and a teaspoon of honey in a jar. Let rest in the fridge overnight. In the morning top with fresh berries.",ingredienti:[{nome:"Fiocchi di avena",qt:"50g"},{nome:"Latte",qt:"100ml"},{nome:"Yogurt bianco",qt:"80g"},{nome:"Miele",qt:"10g"},{nome:"Frutti di bosco",qt:"80g"}],_dbEntry:{n:"Overnight oats con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:13,gs:2.5,g:8,z:18,ch:46,fi:6,ca:220,fe:2,mg:60,k2:400,na:70,zn:1.2,fo:25,se:8,col:12}},{id:"tpl_1373",nome:"Uova strapazzate con avocado toast",nome_en:"Scrambled eggs with avocado toast",categoria:"Colazione",porzioni:1,note:"Strapazzare le uova in padella a fuoco basso mescolando continuamente. Tostare il pane e spalmare l avocado schiacciato con limone e sale. Servire le uova sopra il toast.",note_en:"Scramble eggs in a pan over low heat, stirring constantly. Toast bread and spread mashed avocado with lemon and salt. Serve eggs on top of the toast.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"0.5"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Uova strapazzate con avocado toast (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:17,gs:4,g:20,z:2,ch:24,fi:5,ca:60,fe:2.5,mg:45,k2:520,na:280,zn:1.5,fo:60,se:22,col:370}},{id:"tpl_1374",nome:"Smoothie bowl tropicale",nome_en:"Tropical smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare mango, banana congelata e latte di cocco fino a ottenere una consistenza densa. Versare in una ciotola e guarnire con granola, semi di chia e frutta fresca a fette.",note_en:"Blend mango, frozen banana and coconut milk until thick. Pour into a bowl and top with granola, chia seeds and sliced fresh fruit.",ingredienti:[{nome:"Mango",qt:"150g"},{nome:"Banana congelata",qt:"1"},{nome:"Latte di cocco",qt:"80ml"},{nome:"Granola",qt:"30g"},{nome:"Semi di chia",qt:"10g"}],_dbEntry:{n:"Smoothie bowl tropicale (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:7,gs:6,g:12,z:36,ch:58,fi:7,ca:70,fe:1.8,mg:60,k2:650,na:20,zn:1,fo:40,se:4,col:0}},{id:"tpl_1375",nome:"French toast integrale",nome_en:"Wholewheat French toast",categoria:"Colazione",porzioni:2,note:"Sbattere le uova con latte e cannella. Immergere le fette di pane integrale nel composto e cuocere in padella con poco burro fino a doratura su entrambi i lati. Servire con frutta fresca.",note_en:"Beat eggs with milk and cinnamon. Dip wholewheat bread slices in the mixture and cook in a pan with a little butter until golden on both sides. Serve with fresh fruit.",ingredienti:[{nome:"Pane integrale",qt:"4 fette"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"100ml"},{nome:"Cannella",qt:"q.b."},{nome:"Burro",qt:"15g"}],_dbEntry:{n:"French toast integrale (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:12,gs:3,g:11,z:6,ch:34,fi:4,ca:80,fe:2,mg:35,k2:220,na:280,zn:1,fo:30,se:15,col:200}},{id:"tpl_1376",nome:"Porridge di quinoa al cocco",nome_en:"Coconut quinoa porridge",categoria:"Colazione",porzioni:2,note:"Cuocere la quinoa in latte di cocco e acqua per 15 minuti mescolando di tanto in tanto. Dolcificare con miele e servire caldo guarnito con frutta fresca e cocco rapé.",note_en:"Cook quinoa in coconut milk and water for 15 minutes, stirring occasionally. Sweeten with honey and serve warm topped with fresh fruit and desiccated coconut.",ingredienti:[{nome:"Quinoa",qt:"100g"},{nome:"Latte di cocco",qt:"150ml"},{nome:"Acqua",qt:"150ml"},{nome:"Miele",qt:"15g"},{nome:"Cocco rapé",qt:"10g"}],_dbEntry:{n:"Porridge di quinoa al cocco (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:6,g:12,z:12,ch:40,fi:4,ca:35,fe:2.5,mg:70,k2:320,na:15,zn:1.5,fo:55,se:5,col:0}},{id:"tpl_1377",nome:"Yogurt bowl con frutta e granola",nome_en:"Yogurt bowl with fruit and granola",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt in una ciotola. Aggiungere frutta fresca a fette, granola e un cucchiaino di miele. Mescolare leggermente prima di servire.",note_en:"Pour yogurt into a bowl. Add sliced fresh fruit, granola and a teaspoon of honey. Stir lightly before serving.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Banana",qt:"0.5"},{nome:"Fragole",qt:"80g"},{nome:"Granola",qt:"30g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Yogurt bowl con frutta e granola (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:16,gs:2,g:8,z:26,ch:44,fi:4,ca:180,fe:1.5,mg:40,k2:480,na:60,zn:1.2,fo:35,se:8,col:12}},{id:"tpl_1378",nome:"Frittata di albumi con spinaci",nome_en:"Egg white frittata with spinach",categoria:"Colazione",porzioni:2,note:"Sbattere gli albumi con sale e pepe. Saltare gli spinaci in padella fino ad appassire. Versare gli albumi sugli spinaci e cuocere a fuoco basso coperto fino a rapprendere.",note_en:"Beat egg whites with salt and pepper. Sauté spinach in a pan until wilted. Pour egg whites over spinach and cook covered on low heat until set.",ingredienti:[{nome:"Albumi",qt:"6"},{nome:"Spinaci",qt:"150g"},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Frittata di albumi con spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:20,gs:.5,g:4,z:1,ch:3,fi:2,ca:80,fe:2,mg:35,k2:400,na:250,zn:.8,fo:120,se:20,col:0}},{id:"tpl_1379",nome:"Pane tostato con burro di mandorle e banana",nome_en:"Toast with almond butter and banana",categoria:"Colazione",porzioni:1,note:"Tostare il pane integrale. Spalmare il burro di mandorle e disporre sopra fette sottili di banana. Aggiungere una spolverata di cannella.",note_en:"Toast wholewheat bread. Spread almond butter and arrange thin banana slices on top. Add a dusting of cinnamon.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Burro di mandorle",qt:"20g"},{nome:"Banana",qt:"1"},{nome:"Cannella",qt:"q.b."}],_dbEntry:{n:"Pane tostato con burro di mandorle e banana (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:10,gs:1.5,g:12,z:18,ch:48,fi:6,ca:60,fe:2,mg:80,k2:550,na:220,zn:1,fo:35,se:5,col:0}},{id:"tpl_1380",nome:"Chia pudding alla vaniglia",nome_en:"Vanilla chia pudding",categoria:"Colazione",porzioni:2,note:"Mescolare i semi di chia con latte, estratto di vaniglia e miele. Lasciare riposare in frigo per almeno 4 ore o tutta la notte, mescolando dopo i primi 10 minuti per evitare grumi. Servire con frutta fresca.",note_en:"Mix chia seeds with milk, vanilla extract and honey. Rest in the fridge for at least 4 hours or overnight, stirring after the first 10 minutes to avoid clumps. Serve with fresh fruit.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte",qt:"250ml"},{nome:"Miele",qt:"15g"},{nome:"Estratto di vaniglia",qt:"q.b."}],_dbEntry:{n:"Chia pudding alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:9,gs:2,g:10,z:12,ch:20,fi:8,ca:280,fe:2,mg:70,k2:320,na:60,zn:1,fo:15,se:6,col:8}},{id:"tpl_1381",nome:"Muesli fatto in casa con frutta secca",nome_en:"Homemade muesli with dried fruit",categoria:"Colazione",porzioni:4,note:"Mescolare fiocchi d avena, frutta secca a pezzi, uvetta e semi in una ciotola. Conservare in un barattolo ermetico e servire con latte o yogurt.",note_en:"Mix oat flakes, chopped nuts, raisins and seeds in a bowl. Store in an airtight jar and serve with milk or yogurt.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Mandorle",qt:"40g"},{nome:"Uvetta",qt:"40g"},{nome:"Semi di girasole",qt:"20g"}],_dbEntry:{n:"Muesli fatto in casa con frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:6,gs:1,g:6,z:9,ch:32,fi:4,ca:30,fe:1.8,mg:50,k2:250,na:5,zn:1,fo:20,se:5,col:0}},{id:"tpl_1382",nome:"Crepes integrali con ricotta e miele",nome_en:"Wholewheat crepes with ricotta and honey",categoria:"Colazione",porzioni:2,note:"Preparare la pastella con farina integrale, uova e latte. Cuocere sottili crepes in padella antiaderente. Farcire con ricotta e un filo di miele, arrotolare e servire.",note_en:"Prepare batter with wholewheat flour, eggs and milk. Cook thin crepes in a non-stick pan. Fill with ricotta and a drizzle of honey, roll up and serve.",ingredienti:[{nome:"Farina integrale",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"150ml"},{nome:"Ricotta",qt:"150g"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Crepes integrali con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:16,gs:4,g:11,z:14,ch:42,fi:4,ca:180,fe:2,mg:45,k2:280,na:120,zn:1.2,fo:30,se:15,col:180}},{id:"tpl_1383",nome:"Uova alla benedict light",nome_en:"Light eggs benedict",categoria:"Colazione",porzioni:2,note:"Cuocere le uova in camicia in acqua leggermente acidulata. Tostare il pane integrale e adagiare le uova sopra. Preparare una salsa leggera con yogurt greco, senape e limone al posto della classica olandese.",note_en:"Poach eggs in slightly acidulated water. Toast wholewheat bread and place eggs on top. Prepare a light sauce with Greek yogurt, mustard and lemon instead of classic hollandaise.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Uova alla benedict light (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:22,gs:3,g:16,z:2,ch:22,fi:3,ca:100,fe:2.5,mg:35,k2:320,na:320,zn:1.5,fo:60,se:28,col:380}},{id:"tpl_1384",nome:"Toast con formaggio spalmabile e salmone affumicato",nome_en:"Toast with cream cheese and smoked salmon",categoria:"Colazione",porzioni:1,note:"Tostare il pane di segale. Spalmare il formaggio fresco e adagiare sopra le fette di salmone affumicato. Guarnire con erba cipollina e un giro di limone.",note_en:"Toast rye bread. Spread fresh cheese and lay smoked salmon slices on top. Garnish with chives and a squeeze of lemon.",ingredienti:[{nome:"Pane di segale",qt:"2 fette"},{nome:"Formaggio spalmabile",qt:"40g"},{nome:"Salmone affumicato",qt:"60g"},{nome:"Erba cipollina",qt:"5g"}],_dbEntry:{n:"Toast con formaggio spalmabile e salmone affumicato (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:4,g:13,z:2,ch:24,fi:3,ca:60,fe:1.5,mg:30,k2:280,na:680,zn:1,fo:20,se:20,col:35}},{id:"tpl_1385",nome:"Bowl di yogurt skyr con frutta fresca",nome_en:"Skyr yogurt bowl with fresh fruit",categoria:"Colazione",porzioni:1,note:"Versare lo skyr in una ciotola. Aggiungere frutta fresca tagliata a pezzi, un cucchiaio di semi misti e un filo di miele.",note_en:"Pour skyr into a bowl. Add chopped fresh fruit, a spoon of mixed seeds and a drizzle of honey.",ingredienti:[{nome:"Yogurt skyr",qt:"150g"},{nome:"Mirtilli",qt:"80g"},{nome:"Semi misti",qt:"15g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Bowl di yogurt skyr con frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:.5,g:4,z:20,ch:24,fi:3,ca:200,fe:1,mg:35,k2:280,na:70,zn:1,fo:15,se:10,col:8}},{id:"tpl_1386",nome:"Pancakes di farina d avena",nome_en:"Oat flour pancakes",categoria:"Colazione",porzioni:2,note:"Frullare fiocchi d avena fino a ottenere una farina fine. Mescolare con uova, latte e lievito. Cuocere in padella antiaderente piccole porzioni fino a doratura su entrambi i lati.",note_en:"Blend oat flakes into fine flour. Mix with eggs, milk and baking powder. Cook small portions in a non-stick pan until golden on both sides.",ingredienti:[{nome:"Fiocchi di avena",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"100ml"},{nome:"Lievito",qt:"3g"}],_dbEntry:{n:"Pancakes di farina d avena (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:14,gs:2,g:9,z:4,ch:38,fi:5,ca:100,fe:2.2,mg:60,k2:320,na:150,zn:1.2,fo:25,se:15,col:190}},{id:"tpl_1387",nome:"Cereali integrali con latte e frutta",nome_en:"Wholegrain cereal with milk and fruit",categoria:"Colazione",porzioni:1,note:"Versare i cereali integrali in una ciotola con il latte freddo. Aggiungere frutta fresca a fette come banana o fragole per completare la colazione.",note_en:"Pour wholegrain cereal into a bowl with cold milk. Add fresh sliced fruit like banana or strawberries to complete breakfast.",ingredienti:[{nome:"Cereali integrali",qt:"50g"},{nome:"Latte",qt:"200ml"},{nome:"Banana",qt:"0.5"}],_dbEntry:{n:"Cereali integrali con latte e frutta (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:2,g:6,z:16,ch:44,fi:5,ca:250,fe:3,mg:50,k2:450,na:180,zn:1.5,fo:30,se:8,col:10}},{id:"tpl_1388",nome:"Brioche integrale fatta in casa",nome_en:"Homemade wholewheat brioche",categoria:"Colazione",porzioni:8,note:"Impastare farina integrale, lievito, latte tiepido, uova, burro e poco zucchero. Lasciare lievitare 2 ore. Formare le brioche e cuocere in forno a 180 C per 20 minuti.",note_en:"Knead wholewheat flour, yeast, warm milk, eggs, butter and a little sugar. Let rise 2 hours. Shape brioches and bake at 180 C for 20 minutes.",ingredienti:[{nome:"Farina integrale",qt:"400g"},{nome:"Latte",qt:"150ml"},{nome:"Uova",qt:"2"},{nome:"Burro",qt:"80g"},{nome:"Lievito di birra",qt:"10g"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Brioche integrale fatta in casa (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:4,g:11,z:6,ch:38,fi:3.5,ca:40,fe:1.8,mg:35,k2:180,na:120,zn:.8,fo:25,se:10,col:75}},{id:"tpl_1389",nome:"Smoothie proteico al cioccolato e banana",nome_en:"Chocolate banana protein smoothie",categoria:"Colazione",porzioni:1,note:"Frullare banana, latte, proteine al cioccolato e un cucchiaio di cacao amaro fino a ottenere una crema omogenea. Servire subito ben freddo.",note_en:"Blend banana, milk, chocolate protein powder and a spoon of unsweetened cocoa until smooth. Serve immediately, well chilled.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Latte",qt:"200ml"},{nome:"Proteine al cioccolato",qt:"25g"},{nome:"Cacao amaro",qt:"10g"}],_dbEntry:{n:"Smoothie proteico al cioccolato e banana (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:26,gs:2,g:5,z:24,ch:38,fi:4,ca:250,fe:1.8,mg:70,k2:650,na:150,zn:1.5,fo:30,se:8,col:10}},{id:"tpl_1390",nome:"Uova in camicia su letto di spinaci",nome_en:"Poached eggs on a bed of spinach",categoria:"Colazione",porzioni:2,note:"Saltare gli spinaci in padella con un filo di olio fino ad appassire. Cuocere le uova in camicia in acqua leggermente acidulata per 3 minuti. Adagiare le uova sugli spinaci e servire con pane tostato.",note_en:"Sauté spinach in a pan with a drizzle of oil until wilted. Poach eggs in slightly acidulated water for 3 minutes. Place eggs on the spinach and serve with toasted bread.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Spinaci",qt:"200g"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Uova in camicia su letto di spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:22,gs:3,g:15,z:2,ch:20,fi:4,ca:120,fe:3.5,mg:60,k2:600,na:280,zn:1.8,fo:150,se:28,col:370}},{id:"tpl_1391",nome:"Insalata di pollo e avocado",nome_en:"Chicken and avocado salad",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e tagliarlo a listarelle. Comporre l insalata con lattuga, avocado a fette, pomodorini e pollo. Condire con olio, limone e un pizzico di sale.",note_en:"Grill chicken breast and cut into strips. Assemble salad with lettuce, sliced avocado, cherry tomatoes and chicken. Dress with oil, lemon and a pinch of salt.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di pollo e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:32,gs:3,g:20,z:2,ch:8,fi:6,ca:40,fe:2,mg:55,k2:750,na:220,zn:1.5,fo:60,se:26,col:80}},{id:"tpl_1392",nome:"Insalata di ceci e tonno",nome_en:"Chickpea and tuna salad",categoria:"Insalata",porzioni:2,note:"Sciacquare i ceci lessati e mescolarli con il tonno sgocciolato, cipolla rossa a fettine sottili e prezzemolo. Condire con olio extravergine, limone e pepe.",note_en:"Rinse boiled chickpeas and mix with drained tuna, thinly sliced red onion and parsley. Dress with extra virgin oil, lemon and pepper.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Tonno sott olio",qt:"160g"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di ceci e tonno (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:28,gs:2,g:14,z:2,ch:34,fi:9,ca:60,fe:3,mg:60,k2:520,na:420,zn:2,fo:120,se:35,col:35}},{id:"tpl_1393",nome:"Insalata di farro e verdure grigliate",nome_en:"Farro salad with grilled vegetables",categoria:"Insalata",porzioni:4,note:"Lessare il farro e raffreddarlo. Grigliare zucchine, melanzane e peperoni a listarelle. Mescolare tutto con olio, aceto balsamico e basilico fresco spezzettato.",note_en:"Boil farro and let cool. Grill courgettes, eggplant and peppers into strips. Mix everything with oil, balsamic vinegar and torn fresh basil.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"100g"},{nome:"Basilico",qt:"15g"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Insalata di farro e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:9,gs:1,g:6,z:5,ch:54,fi:9,ca:60,fe:2.5,mg:70,k2:480,na:120,zn:1.5,fo:40,se:8,col:0}},{id:"tpl_1394",nome:"Insalata caesar leggera",nome_en:"Light caesar salad",categoria:"Insalata",porzioni:2,note:"Grigliare il pollo e tagliarlo a striscioline. Preparare una salsa leggera con yogurt greco, acciughe, limone e parmigiano. Condire la lattuga romana con la salsa, pollo e crostini integrali.",note_en:"Grill chicken and cut into strips. Prepare a light dressing with Greek yogurt, anchovies, lemon and parmesan. Dress romaine lettuce with sauce, chicken and wholewheat croutons.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Lattuga romana",qt:"150g"},{nome:"Yogurt greco",qt:"60g"},{nome:"Acciughe",qt:"3"},{nome:"Parmigiano",qt:"30g"},{nome:"Pane integrale",qt:"50g"}],_dbEntry:{n:"Insalata caesar leggera (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:36,gs:3,g:11,z:3,ch:22,fi:3,ca:150,fe:2,mg:50,k2:600,na:520,zn:2,fo:60,se:35,col:85}},{id:"tpl_1395",nome:"Insalata di quinoa, feta e melograno",nome_en:"Quinoa salad with feta and pomegranate",categoria:"Insalata",porzioni:4,note:"Lessare la quinoa e lasciarla raffreddare. Mescolare con feta sbriciolata, chicchi di melograno, menta fresca e olio extravergine. Aggiustare di sale.",note_en:"Boil quinoa and let cool. Mix with crumbled feta, pomegranate seeds, fresh mint and extra virgin oil. Adjust salt.",ingredienti:[{nome:"Quinoa",qt:"250g"},{nome:"Feta",qt:"120g"},{nome:"Melograno",qt:"1"},{nome:"Menta",qt:"10g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata di quinoa, feta e melograno (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:13,gs:5,g:15,z:9,ch:44,fi:6,ca:180,fe:3,mg:80,k2:480,na:420,zn:1.5,fo:80,se:8,col:30}},{id:"tpl_1396",nome:"Insalata di polpo e patate",nome_en:"Octopus and potato salad",categoria:"Insalata",porzioni:4,note:"Lessare il polpo in acqua con alloro finché tenero, circa 40 minuti. Lessare separatamente le patate e tagliarle a cubetti. Mescolare polpo e patate con prezzemolo, olio, limone e olive.",note_en:"Boil octopus in water with bay leaf until tender, about 40 minutes. Separately boil potatoes and dice. Mix octopus and potatoes with parsley, oil, lemon and olives.",ingredienti:[{nome:"Polpo",qt:"800g"},{nome:"Patate",qt:"300g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olive nere",qt:"50g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata di polpo e patate (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:26,gs:1,g:9,z:2,ch:24,fi:2.5,ca:50,fe:3.5,mg:60,k2:650,na:380,zn:2.5,fo:35,se:60,col:70}},{id:"tpl_1397",nome:"Insalata di lenticchie e feta",nome_en:"Lentil and feta salad",categoria:"Insalata",porzioni:4,note:"Lessare le lenticchie e lasciarle raffreddare. Mescolare con feta a cubetti, pomodorini, cipolla rossa e prezzemolo. Condire con olio extravergine e succo di limone.",note_en:"Boil lentils and let cool. Mix with diced feta, cherry tomatoes, red onion and parsley. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Lenticchie",qt:"300g"},{nome:"Feta",qt:"100g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Insalata di lenticchie e feta (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:18,gs:4,g:11,z:4,ch:38,fi:12,ca:150,fe:5,mg:80,k2:650,na:380,zn:2,fo:180,se:8,col:25}},{id:"tpl_1398",nome:"Insalata di riso venere con gamberi",nome_en:"Black rice salad with prawns",categoria:"Insalata",porzioni:4,note:"Lessare il riso venere e lasciarlo raffreddare. Saltare i gamberi in padella con aglio. Mescolare riso, gamberi, avocado a cubetti e coriandolo. Condire con olio e lime.",note_en:"Boil black rice and let cool. Sauté prawns in a pan with garlic. Mix rice, prawns, diced avocado and coriander. Dress with oil and lime.",ingredienti:[{nome:"Riso venere",qt:"250g"},{nome:"Gamberi",qt:"300g"},{nome:"Avocado",qt:"1"},{nome:"Coriandolo",qt:"10g"},{nome:"Lime",qt:"1"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Insalata di riso venere con gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:24,gs:2,g:12,z:2,ch:50,fi:4,ca:60,fe:2,mg:70,k2:650,na:320,zn:1.5,fo:50,se:38,col:145}},{id:"tpl_1399",nome:"Insalata di finocchi, arance e olive",nome_en:"Fennel, orange and olive salad",categoria:"Insalata",porzioni:4,note:"Affettare finemente i finocchi. Pelare le arance a vivo e tagliarle a fette. Comporre l insalata con finocchi, arance e olive nere. Condire con olio extravergine e un pizzico di pepe.",note_en:"Thinly slice fennel. Peel oranges to the flesh and slice. Assemble salad with fennel, oranges and black olives. Dress with extra virgin oil and a pinch of pepper.",ingredienti:[{nome:"Finocchi",qt:"300g"},{nome:"Arance",qt:"3"},{nome:"Olive nere",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata di finocchi, arance e olive (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:2,gs:1,g:7,z:16,ch:20,fi:5,ca:80,fe:1,mg:30,k2:450,na:220,zn:.4,fo:60,se:1,col:0}},{id:"tpl_1400",nome:"Insalata di spinacini, noci e gorgonzola",nome_en:"Baby spinach salad with walnuts and gorgonzola",categoria:"Insalata",porzioni:2,note:"Disporre gli spinacini freschi in una ciotola. Aggiungere noci sgusciate, gorgonzola a cubetti e qualche fetta di pera. Condire con olio extravergine e un cucchiaino di miele.",note_en:"Arrange fresh baby spinach in a bowl. Add shelled walnuts, diced gorgonzola and a few pear slices. Dress with extra virgin oil and a teaspoon of honey.",ingredienti:[{nome:"Spinacini",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Gorgonzola",qt:"80g"},{nome:"Pera",qt:"1"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Insalata di spinacini, noci e gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:11,gs:7,g:24,z:12,ch:16,fi:4,ca:180,fe:2.5,mg:60,k2:520,na:420,zn:1.5,fo:120,se:8,col:25}},{id:"tpl_1401",nome:"Insalata di orzo perlato estiva",nome_en:"Summer pearl barley salad",categoria:"Insalata",porzioni:4,note:"Lessare l orzo perlato e raffreddarlo. Mescolare con pomodorini, cetrioli, feta e olive. Condire con olio extravergine, origano e succo di limone.",note_en:"Boil pearl barley and let cool. Mix with cherry tomatoes, cucumbers, feta and olives. Dress with extra virgin oil, oregano and lemon juice.",ingredienti:[{nome:"Orzo perlato",qt:"280g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cetrioli",qt:"150g"},{nome:"Feta",qt:"100g"},{nome:"Olive",qt:"50g"}],_dbEntry:{n:"Insalata di orzo perlato estiva (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:11,gs:4,g:10,z:5,ch:52,fi:8,ca:150,fe:2.5,mg:60,k2:420,na:420,zn:1.5,fo:40,se:8,col:25}},{id:"tpl_1402",nome:"Insalata di cavolo rosso e mela",nome_en:"Red cabbage and apple coleslaw",categoria:"Insalata",porzioni:4,note:"Affettare finemente il cavolo rosso e la mela a julienne. Mescolare con yogurt greco, senape, succo di limone e un pizzico di sale al posto della maionese classica.",note_en:"Thinly slice red cabbage and julienne the apple. Mix with Greek yogurt, mustard, lemon juice and a pinch of salt instead of classic mayonnaise.",ingredienti:[{nome:"Cavolo rosso",qt:"300g"},{nome:"Mela",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Insalata di cavolo rosso e mela (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4,gs:.5,g:1.5,z:14,ch:18,fi:4,ca:80,fe:1,mg:25,k2:350,na:80,zn:.4,fo:50,se:2,col:2}},{id:"tpl_1403",nome:"Insalata tiepida di fagiolini e uova",nome_en:"Warm green bean and egg salad",categoria:"Insalata",porzioni:2,note:"Lessare i fagiolini al dente e le uova sode. Tagliare le uova a spicchi. Condire i fagiolini tiepidi con olio, aceto e cipollotto tritato, guarnendo con le uova.",note_en:"Boil green beans al dente and hard-boil eggs. Cut eggs into wedges. Dress warm green beans with oil, vinegar and chopped spring onion, garnishing with eggs.",ingredienti:[{nome:"Fagiolini",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Cipollotto",qt:"1"},{nome:"Aceto di vino",qt:"10ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata tiepida di fagiolini e uova (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:3,g:14,z:4,ch:10,fi:4,ca:80,fe:2.5,mg:40,k2:450,na:150,zn:1.2,fo:90,se:22,col:280}},{id:"tpl_1404",nome:"Insalata di kamut con verdure croccanti",nome_en:"Kamut salad with crunchy vegetables",categoria:"Insalata",porzioni:4,note:"Lessare il kamut secondo le istruzioni e raffreddare. Mescolare con carote, sedano e ravanelli tagliati sottili. Condire con olio, limone e semi di sesamo tostati.",note_en:"Boil kamut per instructions and cool. Mix with thinly sliced carrots, celery and radishes. Dress with oil, lemon and toasted sesame seeds.",ingredienti:[{nome:"Kamut",qt:"250g"},{nome:"Carote",qt:"100g"},{nome:"Sedano",qt:"100g"},{nome:"Ravanelli",qt:"80g"},{nome:"Semi di sesamo",qt:"10g"}],_dbEntry:{n:"Insalata di kamut con verdure croccanti (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:9,gs:1,g:6,z:5,ch:54,fi:8,ca:60,fe:3,mg:70,k2:480,na:60,zn:1.5,fo:40,se:8,col:0}},{id:"tpl_1405",nome:"Insalata di rucola, pere e noci",nome_en:"Rocket, pear and walnut salad",categoria:"Insalata",porzioni:2,note:"Disporre la rucola in un piatto. Aggiungere fette sottili di pera, noci sgusciate e scaglie di parmigiano. Condire con olio extravergine e aceto balsamico.",note_en:"Arrange rocket on a plate. Add thin pear slices, shelled walnuts and parmesan shavings. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"80g"},{nome:"Pera",qt:"1"},{nome:"Noci",qt:"40g"},{nome:"Parmigiano",qt:"30g"},{nome:"Aceto balsamico",qt:"10ml"}],_dbEntry:{n:"Insalata di rucola, pere e noci (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:5,g:20,z:14,ch:16,fi:4,ca:180,fe:1.5,mg:50,k2:350,na:220,zn:1.2,fo:60,se:6,col:15}},{id:"tpl_1406",nome:"Insalata di gamberi e avocado",nome_en:"Prawn and avocado salad",categoria:"Insalata",porzioni:2,note:"Sbollentare i gamberi 2 minuti in acqua salata e raffreddare in acqua e ghiaccio. Tagliare l avocado a fette. Comporre l insalata con lattuga, gamberi e avocado. Condire con olio, limone e un pizzico di paprika.",note_en:"Blanch prawns 2 minutes in salted water and cool in ice water. Slice avocado. Assemble salad with lettuce, prawns and avocado. Dress with oil, lemon and a pinch of paprika.",ingredienti:[{nome:"Gamberi",qt:"300g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Paprika",qt:"q.b."}],_dbEntry:{n:"Insalata di gamberi e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:26,gs:2,g:14,z:2,ch:8,fi:6,ca:60,fe:1.5,mg:55,k2:650,na:280,zn:1.5,fo:70,se:38,col:180}},{id:"tpl_1407",nome:"Insalata mediterranea con feta e olive",nome_en:"Mediterranean salad with feta and olives",categoria:"Insalata",porzioni:4,note:"Tagliare a cubetti pomodori, cetrioli e peperoni. Mescolare con feta a cubetti, olive nere e cipolla rossa a fettine. Condire con olio extravergine e origano.",note_en:"Dice tomatoes, cucumbers and peppers. Mix with diced feta, black olives and sliced red onion. Dress with extra virgin oil and oregano.",ingredienti:[{nome:"Pomodori",qt:"250g"},{nome:"Cetrioli",qt:"200g"},{nome:"Peperoni",qt:"100g"},{nome:"Feta",qt:"120g"},{nome:"Olive nere",qt:"60g"},{nome:"Cipolla rossa",qt:"0.5"}],_dbEntry:{n:"Insalata mediterranea con feta e olive (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:9,gs:5,g:16,z:7,ch:12,fi:3,ca:220,fe:1.5,mg:40,k2:480,na:520,zn:1.2,fo:50,se:6,col:30}},{id:"tpl_1408",nome:"Insalata di sedano rapa e mela",nome_en:"Celeriac and apple salad",categoria:"Insalata",porzioni:4,note:"Tagliare il sedano rapa e la mela a julienne sottile. Condire subito con succo di limone per evitare l ossidazione. Aggiungere yogurt greco, senape e un pizzico di sale.",note_en:"Julienne celeriac and apple thinly. Dress immediately with lemon juice to prevent browning. Add Greek yogurt, mustard and a pinch of salt.",ingredienti:[{nome:"Sedano rapa",qt:"300g"},{nome:"Mela",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di sedano rapa e mela (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:4,gs:.5,g:1.5,z:12,ch:20,fi:5,ca:70,fe:1,mg:25,k2:400,na:70,zn:.4,fo:40,se:2,col:2}},{id:"tpl_1409",nome:"Insalata di legumi misti",nome_en:"Mixed legume salad",categoria:"Insalata",porzioni:4,note:"Mescolare ceci, fagioli borlotti e lenticchie lessati in una ciotola capiente. Aggiungere sedano, carota a cubetti e prezzemolo. Condire con olio extravergine e aceto di mele.",note_en:"Mix boiled chickpeas, borlotti beans and lentils in a large bowl. Add celery, diced carrot and parsley. Dress with extra virgin oil and apple vinegar.",ingredienti:[{nome:"Ceci lessati",qt:"150g"},{nome:"Fagioli borlotti",qt:"150g"},{nome:"Lenticchie",qt:"150g"},{nome:"Sedano",qt:"80g"},{nome:"Carota",qt:"80g"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Insalata di legumi misti (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:.5,g:5,z:5,ch:42,fi:14,ca:100,fe:4.5,mg:80,k2:700,na:180,zn:2.2,fo:180,se:5,col:0}},{id:"tpl_1410",nome:"Insalata waldorf light",nome_en:"Light waldorf salad",categoria:"Insalata",porzioni:4,note:"Tagliare mele e sedano a cubetti. Aggiungere noci sgusciate e uvetta. Condire con una salsa leggera di yogurt greco e succo di limone al posto della maionese classica.",note_en:"Dice apples and celery. Add shelled walnuts and raisins. Dress with a light sauce of Greek yogurt and lemon juice instead of classic mayonnaise.",ingredienti:[{nome:"Mele",qt:"2"},{nome:"Sedano",qt:"150g"},{nome:"Noci",qt:"50g"},{nome:"Uvetta",qt:"30g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Insalata waldorf light (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:6,gs:1.5,g:12,z:22,ch:26,fi:5,ca:80,fe:1,mg:45,k2:420,na:40,zn:.8,fo:20,se:3,col:2}},{id:"tpl_1411",nome:"Tagliere di formaggi e miele",nome_en:"Cheese board with honey",categoria:"Antipasto",porzioni:4,note:"Disporre su un tagliere una selezione di formaggi misti a pezzi o fette. Accompagnare con miele, noci sgusciate e qualche fetta di pera fresca.",note_en:"Arrange a selection of mixed cheeses cut into pieces or slices on a board. Accompany with honey, shelled walnuts and a few fresh pear slices.",ingredienti:[{nome:"Formaggi misti",qt:"300g"},{nome:"Miele",qt:"40g"},{nome:"Noci",qt:"50g"},{nome:"Pera",qt:"1"}],_dbEntry:{n:"Tagliere di formaggi e miele (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:11,g:26,z:14,ch:16,fi:1.5,ca:450,fe:1,mg:35,k2:220,na:620,zn:2.5,fo:20,se:15,col:70}},{id:"tpl_1412",nome:"Involtini di melanzane grigliate con ricotta",nome_en:"Grilled eggplant rolls with ricotta",categoria:"Antipasto",porzioni:4,note:"Grigliare le fette di melanzana senza olio fino a doratura. Farcire con ricotta mescolata a basilico e un pizzico di sale. Arrotolare e disporre su un piatto da portata.",note_en:"Grill eggplant slices without oil until golden. Fill with ricotta mixed with basil and a pinch of salt. Roll up and arrange on a serving plate.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Ricotta",qt:"250g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Involtini di melanzane grigliate con ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:9,gs:3,g:11,z:5,ch:8,fi:3,ca:150,fe:.8,mg:25,k2:350,na:120,zn:.8,fo:25,se:6,col:25}},{id:"tpl_1413",nome:"Crostini con paté di fegatini",nome_en:"Crostini with chicken liver pâté",categoria:"Antipasto",porzioni:4,note:"Rosolare i fegatini di pollo con cipolla, salvia e capperi. Frullare fino a ottenere un composto omogeneo con un filo di brodo. Spalmare sui crostini di pane tostato.",note_en:"Brown chicken livers with onion, sage and capers. Blend until smooth with a splash of stock. Spread on toasted bread crostini.",ingredienti:[{nome:"Fegatini di pollo",qt:"250g"},{nome:"Cipolla",qt:"0.5"},{nome:"Capperi",qt:"20g"},{nome:"Salvia",qt:"4 foglie"},{nome:"Pane casereccio",qt:"150g"}],_dbEntry:{n:"Crostini con paté di fegatini (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:16,gs:2,g:9,z:2,ch:26,fi:2,ca:30,fe:6,mg:30,k2:380,na:380,zn:2.5,fo:250,se:20,col:280}},{id:"tpl_1414",nome:"Cocktail di gamberi",nome_en:"Prawn cocktail",categoria:"Antipasto",porzioni:4,note:"Sbollentare i gamberi 2 minuti e raffreddare. Preparare una salsa leggera con yogurt greco, ketchup e un goccio di brandy. Servire i gamberi su un letto di lattuga con la salsa.",note_en:"Blanch prawns 2 minutes and cool. Prepare a light sauce with Greek yogurt, ketchup and a splash of brandy. Serve prawns on a bed of lettuce with the sauce.",ingredienti:[{nome:"Gamberi",qt:"400g"},{nome:"Lattuga",qt:"100g"},{nome:"Yogurt greco",qt:"60g"},{nome:"Ketchup",qt:"30g"}],_dbEntry:{n:"Cocktail di gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:26,gs:.5,g:3,z:5,ch:10,fi:1,ca:80,fe:1,mg:45,k2:400,na:420,zn:1.5,fo:35,se:38,col:200}},{id:"tpl_1415",nome:"Polpette di melanzane al forno",nome_en:"Baked eggplant balls",categoria:"Antipasto",porzioni:4,note:"Cuocere le melanzane a vapore e schiacciarle. Mescolare con pangrattato, uovo, parmigiano e prezzemolo. Formare le polpette e cuocere in forno a 200 C per 20 minuti.",note_en:"Steam eggplant and mash. Mix with breadcrumbs, egg, parmesan and parsley. Shape into balls and bake at 200 C for 20 minutes.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Pangrattato",qt:"80g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano",qt:"50g"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Polpette di melanzane al forno (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:8,gs:2,g:6,z:5,ch:20,fi:4,ca:120,fe:1.2,mg:30,k2:350,na:220,zn:1,fo:30,se:8,col:45}},{id:"tpl_1416",nome:"Bruschette miste",nome_en:"Mixed bruschette",categoria:"Antipasto",porzioni:4,note:"Tostare fette di pane casereccio. Preparare tre farciture: pomodoro e basilico, funghi trifolati e formaggio spalmabile con rucola. Distribuire sulle fette e servire subito.",note_en:"Toast slices of country bread. Prepare three toppings: tomato and basil, sautéed mushrooms, and spreadable cheese with rocket. Top slices and serve immediately.",ingredienti:[{nome:"Pane casereccio",qt:"8 fette"},{nome:"Pomodori",qt:"150g"},{nome:"Funghi champignon",qt:"150g"},{nome:"Formaggio spalmabile",qt:"80g"},{nome:"Rucola",qt:"30g"}],_dbEntry:{n:"Bruschette miste (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:3,g:9,z:4,ch:38,fi:3,ca:60,fe:1.8,mg:35,k2:320,na:320,zn:1,fo:35,se:6,col:15}},{id:"tpl_1417",nome:"Carpaccio di salmone con agrumi",nome_en:"Salmon carpaccio with citrus",categoria:"Antipasto",porzioni:4,note:"Affettare sottilmente il salmone fresco e disporlo su un piatto. Condire con succo di lime e arancia, un filo di olio, sale e pepe rosa. Guarnire con scorza di agrumi grattugiata.",note_en:"Thinly slice fresh salmon and arrange on a plate. Dress with lime and orange juice, a drizzle of oil, salt and pink pepper. Garnish with grated citrus zest.",ingredienti:[{nome:"Salmone fresco",qt:"350g"},{nome:"Lime",qt:"1"},{nome:"Arancia",qt:"1"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Pepe rosa",qt:"q.b."}],_dbEntry:{n:"Carpaccio di salmone con agrumi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:2,g:14,z:3,ch:4,fi:.5,ca:20,fe:.8,mg:30,k2:450,na:60,zn:.8,fo:20,se:30,col:45}},{id:"tpl_1418",nome:"Flan di verdure con fonduta leggera",nome_en:"Vegetable flan with light fondue",categoria:"Antipasto",porzioni:4,note:"Cuocere le verdure a vapore e frullarle con uova e poco latte. Versare negli stampini e cuocere a bagnomaria in forno a 170 C per 30 minuti. Servire con una fonduta leggera di formaggio.",note_en:"Steam vegetables and blend with eggs and a little milk. Pour into molds and bake in a water bath at 170 C for 30 minutes. Serve with a light cheese fondue.",ingredienti:[{nome:"Zucchine",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Latte",qt:"100ml"},{nome:"Formaggio grattugiato",qt:"40g"}],_dbEntry:{n:"Flan di verdure con fonduta leggera (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:11,gs:3,g:9,z:3,ch:6,fi:2,ca:120,fe:1,mg:25,k2:320,na:180,zn:1,fo:45,se:18,col:200}},{id:"tpl_1419",nome:"Involtini di zucchine con formaggio fresco",nome_en:"Courgette rolls with fresh cheese",categoria:"Antipasto",porzioni:4,note:"Grigliare fette sottili di zucchina. Farcire con formaggio fresco spalmabile e menta. Arrotolare e fissare con uno stecchino. Servire freddi o a temperatura ambiente.",note_en:"Grill thin courgette slices. Fill with fresh spreadable cheese and mint. Roll up and secure with a toothpick. Serve cold or at room temperature.",ingredienti:[{nome:"Zucchine",qt:"400g"},{nome:"Formaggio spalmabile",qt:"150g"},{nome:"Menta",qt:"10g"}],_dbEntry:{n:"Involtini di zucchine con formaggio fresco (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:8,gs:4,g:11,z:4,ch:5,fi:1.5,ca:120,fe:.6,mg:20,k2:300,na:150,zn:.6,fo:25,se:5,col:30}},{id:"tpl_1420",nome:"Crema di zucca con crostini",nome_en:"Pumpkin cream with croutons",categoria:"Antipasto",porzioni:4,note:"Cuocere la zucca a cubetti con cipolla in brodo vegetale per 25 minuti. Frullare fino a ottenere una crema liscia. Servire con crostini di pane tostato e un filo di olio.",note_en:"Cook diced pumpkin with onion in vegetable stock for 25 minutes. Blend until smooth. Serve with toasted bread croutons and a drizzle of oil.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Cipolla",qt:"0.5"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane casereccio",qt:"100g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Crema di zucca con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:1,g:6,z:8,ch:30,fi:3,ca:60,fe:1.2,mg:35,k2:450,na:280,zn:.6,fo:30,se:3,col:0}},{id:"tpl_1421",nome:"Tartare di tonno con avocado",nome_en:"Tuna tartare with avocado",categoria:"Antipasto",porzioni:4,note:"Tagliare il tonno fresco a cubetti piccoli. Condire con salsa di soia, olio di sesamo e succo di lime. Servire su una base di avocado schiacciato guarnendo con semi di sesamo.",note_en:"Cut fresh tuna into small cubes. Dress with soy sauce, sesame oil and lime juice. Serve on a bed of mashed avocado, garnishing with sesame seeds.",ingredienti:[{nome:"Tonno fresco",qt:"350g"},{nome:"Avocado",qt:"1"},{nome:"Salsa di soia",qt:"20ml"},{nome:"Olio di sesamo",qt:"10ml"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Tartare di tonno con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:24,gs:2,g:15,z:2,ch:6,fi:4,ca:20,fe:1.2,mg:45,k2:550,na:480,zn:.8,fo:35,se:60,col:40}},{id:"tpl_1422",nome:"Frittatine di verdure in miniatura",nome_en:"Mini vegetable frittatas",categoria:"Antipasto",porzioni:6,note:"Sbattere le uova con verdure miste a cubetti e parmigiano. Versare in stampini da muffin e cuocere in forno a 180 C per 18 minuti finché sode. Servire tiepide.",note_en:"Beat eggs with mixed diced vegetables and parmesan. Pour into muffin tins and bake at 180 C for 18 minutes until set. Serve warm.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Zucchine",qt:"100g"},{nome:"Peperoni",qt:"100g"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Frittatine di verdure in miniatura (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:9,gs:2,g:7,z:2,ch:3,fi:1,ca:70,fe:1,mg:15,k2:180,na:150,zn:.8,fo:25,se:15,col:190}},{id:"tpl_1423",nome:"Chips di verdure al forno con salsa yogurt",nome_en:"Baked vegetable chips with yogurt sauce",categoria:"Antipasto",porzioni:4,note:"Affettare sottilmente barbabietola, carota e zucchina. Condire con olio e cuocere in forno a 180 C per 20 minuti finché croccanti. Servire con una salsa di yogurt greco ed erba cipollina.",note_en:"Thinly slice beetroot, carrot and courgette. Season with oil and bake at 180 C for 20 minutes until crispy. Serve with a Greek yogurt and chive sauce.",ingredienti:[{nome:"Barbabietola",qt:"150g"},{nome:"Carota",qt:"150g"},{nome:"Zucchina",qt:"150g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Chips di verdure al forno con salsa yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:5,gs:.5,g:5,z:9,ch:16,fi:4,ca:80,fe:1,mg:25,k2:420,na:80,zn:.5,fo:35,se:2,col:2}},{id:"tpl_1424",nome:"Antipasto di mare misto al forno",nome_en:"Baked mixed seafood antipasto",categoria:"Antipasto",porzioni:4,note:"Disporre in teglia cozze, vongole e gamberi con aglio, prezzemolo e un filo di olio. Cuocere in forno a 200 C per 12 minuti finché i molluschi si aprono. Servire caldo con limone.",note_en:"Arrange mussels, clams and prawns in a baking dish with garlic, parsley and a drizzle of oil. Bake at 200 C for 12 minutes until shellfish open. Serve hot with lemon.",ingredienti:[{nome:"Cozze",qt:"300g"},{nome:"Vongole",qt:"300g"},{nome:"Gamberi",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Antipasto di mare misto al forno (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:26,gs:.5,g:6,z:1,ch:5,fi:.5,ca:80,fe:4,mg:50,k2:400,na:480,zn:2,fo:30,se:45,col:110}},{id:"tpl_1425",nome:"Terrina di verdure grigliate",nome_en:"Grilled vegetable terrine",categoria:"Antipasto",porzioni:6,note:"Grigliare melanzane, zucchine e peperoni a fette. Alternare gli strati in uno stampo da plumcake foderato di pellicola. Pressare, raffreddare in frigo 3 ore e affettare per servire.",note_en:"Grill eggplant, courgette and pepper slices. Layer alternately in a loaf tin lined with cling film. Press, chill in the fridge 3 hours and slice to serve.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Zucchine",qt:"300g"},{nome:"Peperoni",qt:"250g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Terrina di verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2,gs:.5,g:6,z:6,ch:8,fi:3,ca:25,fe:.7,mg:20,k2:300,na:80,zn:.4,fo:35,se:1,col:0}},{id:"tpl_1426",nome:"Uova ripiene light",nome_en:"Light stuffed eggs",categoria:"Antipasto",porzioni:4,note:"Lessare le uova, tagliarle a metà e prelevare i tuorli. Mescolare i tuorli con yogurt greco, senape ed erba cipollina. Farcire gli albumi con il composto usando una tasca da pasticcere.",note_en:"Boil eggs, halve and remove yolks. Mix yolks with Greek yogurt, mustard and chives. Fill egg whites with the mixture using a piping bag.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Yogurt greco",qt:"40g"},{nome:"Senape",qt:"10g"},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Uova ripiene light (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:12,gs:2.5,g:9,z:1,ch:2,fi:.2,ca:50,fe:1.6,mg:15,k2:180,na:150,zn:1,fo:40,se:20,col:370}},{id:"tpl_1427",nome:"Salmone marinato con agrumi",nome_en:"Citrus-marinated salmon",categoria:"Antipasto",porzioni:4,note:"Marinare il salmone fresco con sale, zucchero, succo e scorza di agrumi per almeno 6 ore in frigo. Sciacquare, asciugare e affettare sottilmente prima di servire.",note_en:"Marinate fresh salmon with salt, sugar, citrus juice and zest for at least 6 hours in the fridge. Rinse, pat dry and slice thinly before serving.",ingredienti:[{nome:"Salmone fresco",qt:"400g"},{nome:"Sale",qt:"40g"},{nome:"Zucchero",qt:"20g"},{nome:"Arancia",qt:"1"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Salmone marinato con agrumi (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:22,gs:2,g:15,z:3,ch:3,fi:.2,ca:15,fe:.6,mg:28,k2:420,na:580,zn:.6,fo:20,se:32,col:50}},{id:"tpl_1428",nome:"Involtini di prosciutto e melone",nome_en:"Ham and melon rolls",categoria:"Antipasto",porzioni:4,note:"Tagliare il melone a fette sottili. Avvolgere ogni fetta con una fetta di prosciutto crudo. Disporre su un piatto da portata e servire fresco.",note_en:"Cut melon into thin slices. Wrap each slice with a slice of raw ham. Arrange on a serving plate and serve chilled.",ingredienti:[{nome:"Melone",qt:"1"},{nome:"Prosciutto crudo",qt:"150g"}],_dbEntry:{n:"Involtini di prosciutto e melone (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:14,gs:2,g:6,z:10,ch:12,fi:1,ca:15,fe:.8,mg:20,k2:350,na:680,zn:1.5,fo:20,se:15,col:35}},{id:"tpl_1429",nome:"Vellutata di carciofi con crostini",nome_en:"Artichoke velouté with croutons",categoria:"Antipasto",porzioni:4,note:"Pulire i carciofi e cuocerli con cipolla e patata in brodo vegetale per 25 minuti. Frullare fino a ottenere una crema vellutata. Servire con crostini di pane e un filo di olio.",note_en:"Clean artichokes and cook with onion and potato in vegetable stock for 25 minutes. Blend until velvety. Serve with bread croutons and a drizzle of oil.",ingredienti:[{nome:"Carciofi",qt:"400g"},{nome:"Patata",qt:"150g"},{nome:"Cipolla",qt:"0.5"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane casereccio",qt:"100g"}],_dbEntry:{n:"Vellutata di carciofi con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:.8,g:5,z:4,ch:32,fi:6,ca:60,fe:1.8,mg:40,k2:480,na:280,zn:.8,fo:60,se:3,col:0}},{id:"tpl_1430",nome:"Cesto di verdure crude in pinzimonio",nome_en:"Raw vegetable basket with pinzimonio dip",categoria:"Antipasto",porzioni:4,note:"Tagliare a bastoncini carote, sedano, finocchio e peperoni. Preparare il pinzimonio con olio extravergine, sale e pepe in ciotoline individuali. Servire le verdure crude con la salsa per intingere.",note_en:"Cut carrots, celery, fennel and peppers into sticks. Prepare pinzimonio with extra virgin oil, salt and pepper in individual bowls. Serve raw vegetables with the dipping sauce.",ingredienti:[{nome:"Carote",qt:"150g"},{nome:"Sedano",qt:"150g"},{nome:"Finocchio",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cesto di verdure crude in pinzimonio (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2,gs:1,g:9,z:6,ch:8,fi:4,ca:60,fe:.8,mg:25,k2:450,na:120,zn:.4,fo:50,se:1,col:0}},{id:"tpl_1431",nome:"Tiramisu light con yogurt",nome_en:"Light yogurt tiramisu",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco con un cucchiaio di zucchero e mascarpone in piccola quantità. Inzuppare leggermente i savoiardi nel caffè. Alternare strati di savoiardi e crema, spolverare con cacao amaro e riposare in frigo 4 ore.",note_en:"Mix Greek yogurt with a spoon of sugar and a small amount of mascarpone. Lightly dip ladyfingers in coffee. Alternate layers of ladyfingers and cream, dust with unsweetened cocoa and chill 4 hours.",ingredienti:[{nome:"Yogurt greco",qt:"400g"},{nome:"Mascarpone",qt:"100g"},{nome:"Savoiardi",qt:"200g"},{nome:"Caffè",qt:"200ml"},{nome:"Cacao amaro",qt:"15g"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Tiramisu light con yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:5,g:10,z:18,ch:32,fi:1,ca:120,fe:1,mg:25,k2:220,na:80,zn:.8,fo:15,se:5,col:60}},{id:"tpl_1432",nome:"Torta di mele senza burro",nome_en:"Butter-free apple cake",categoria:"Dolce",porzioni:8,note:"Mescolare farina, uova, zucchero, olio di semi e lievito. Aggiungere le mele tagliate a fette sottili. Versare in una tortiera e cuocere in forno a 180 C per 40 minuti.",note_en:"Mix flour, eggs, sugar, seed oil and baking powder. Add thinly sliced apples. Pour into a cake tin and bake at 180 C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Mele",qt:"4"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"150g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di mele senza burro (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:1,g:9,z:22,ch:44,fi:2.5,ca:30,fe:1,mg:15,k2:180,na:60,zn:.4,fo:20,se:8,col:60}},{id:"tpl_1433",nome:"Cheesecake proteica al forno",nome_en:"Baked protein cheesecake",categoria:"Dolce",porzioni:8,note:"Frullare fiocchi d avena e usarli come base pressata in uno stampo. Mescolare formaggio spalmabile light, proteine in polvere, uova e un dolcificante. Versare sulla base e cuocere in forno a 160 C per 40 minuti.",note_en:"Blend oat flakes and use as a pressed base in a mold. Mix light cream cheese, protein powder, eggs and a sweetener. Pour over the base and bake at 160 C for 40 minutes.",ingredienti:[{nome:"Formaggio spalmabile light",qt:"400g"},{nome:"Proteine in polvere",qt:"50g"},{nome:"Uova",qt:"3"},{nome:"Fiocchi di avena",qt:"100g"},{nome:"Dolcificante",qt:"q.b."}],_dbEntry:{n:"Cheesecake proteica al forno (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:16,gs:4,g:11,z:6,ch:14,fi:1.5,ca:120,fe:1,mg:20,k2:150,na:220,zn:.8,fo:12,se:10,col:110}},{id:"tpl_1434",nome:"Mousse al cioccolato fondente e avocado",nome_en:"Dark chocolate and avocado mousse",categoria:"Dolce",porzioni:4,note:"Frullare avocado maturo con cioccolato fondente fuso, cacao amaro e un cucchiaio di miele fino a ottenere una consistenza cremosa. Raffreddare in frigo 2 ore prima di servire.",note_en:"Blend ripe avocado with melted dark chocolate, unsweetened cocoa and a spoon of honey until creamy. Chill in the fridge 2 hours before serving.",ingredienti:[{nome:"Avocado",qt:"2"},{nome:"Cioccolato fondente",qt:"100g"},{nome:"Cacao amaro",qt:"15g"},{nome:"Miele",qt:"30g"}],_dbEntry:{n:"Mousse al cioccolato fondente e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:4,gs:5,g:16,z:14,ch:18,fi:6,ca:30,fe:2,mg:60,k2:550,na:5,zn:1,fo:35,se:2,col:0}},{id:"tpl_1435",nome:"Crostata di frutta con crema pasticcera light",nome_en:"Fruit tart with light pastry cream",categoria:"Dolce",porzioni:8,note:"Preparare una frolla con farina, poco burro, uova e zucchero. Cuocere in bianco la base. Preparare una crema pasticcera con latte scremato, uova e amido di mais. Farcire con la crema e guarnire con frutta fresca.",note_en:"Prepare shortcrust with flour, a little butter, eggs and sugar. Blind bake the base. Prepare pastry cream with skimmed milk, eggs and cornstarch. Fill with cream and top with fresh fruit.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Burro",qt:"60g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"100g"},{nome:"Latte scremato",qt:"400ml"},{nome:"Amido di mais",qt:"40g"},{nome:"Frutta fresca mista",qt:"300g"}],_dbEntry:{n:"Crostata di frutta con crema pasticcera light (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:6,gs:3,g:8,z:20,ch:42,fi:2,ca:70,fe:1,mg:20,k2:220,na:60,zn:.5,fo:20,se:10,col:80}},{id:"tpl_1436",nome:"Budino di chia e cioccolato",nome_en:"Chia and chocolate pudding",categoria:"Dolce",porzioni:2,note:"Mescolare i semi di chia con latte, cacao amaro e un cucchiaio di miele. Lasciare riposare in frigo almeno 4 ore mescolando dopo i primi 10 minuti. Servire con frutti di bosco freschi.",note_en:"Mix chia seeds with milk, unsweetened cocoa and a spoon of honey. Rest in the fridge at least 4 hours, stirring after the first 10 minutes. Serve with fresh berries.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte",qt:"250ml"},{nome:"Cacao amaro",qt:"15g"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Budino di chia e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:8,gs:2,g:9,z:14,ch:20,fi:9,ca:270,fe:2.5,mg:80,k2:350,na:60,zn:1,fo:15,se:6,col:8}},{id:"tpl_1437",nome:"Torta di carote e mandorle",nome_en:"Carrot and almond cake",categoria:"Dolce",porzioni:8,note:"Grattugiare le carote finemente. Mescolare con farina di mandorle, uova, zucchero di canna e lievito. Versare in una tortiera e cuocere in forno a 170 C per 45 minuti.",note_en:"Finely grate carrots. Mix with almond flour, eggs, cane sugar and baking powder. Pour into a cake tin and bake at 170 C for 45 minutes.",ingredienti:[{nome:"Carote",qt:"250g"},{nome:"Farina di mandorle",qt:"150g"},{nome:"Farina 00",qt:"100g"},{nome:"Uova",qt:"4"},{nome:"Zucchero di canna",qt:"120g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di carote e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:8,gs:1.5,g:14,z:16,ch:32,fi:3,ca:60,fe:1.5,mg:45,k2:280,na:60,zn:.8,fo:30,se:8,col:80}},{id:"tpl_1438",nome:"Semifreddo allo yogurt e frutti di bosco",nome_en:"Yogurt and berry semifreddo",categoria:"Dolce",porzioni:6,note:"Montare gli albumi a neve con lo zucchero. Incorporare delicatamente lo yogurt greco e i frutti di bosco frullati. Versare in uno stampo e congelare per almeno 5 ore. Servire a fette.",note_en:"Whip egg whites to stiff peaks with sugar. Gently fold in Greek yogurt and blended berries. Pour into a mold and freeze at least 5 hours. Serve sliced.",ingredienti:[{nome:"Yogurt greco",qt:"300g"},{nome:"Albumi",qt:"3"},{nome:"Zucchero",qt:"80g"},{nome:"Frutti di bosco",qt:"200g"}],_dbEntry:{n:"Semifreddo allo yogurt e frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:9,gs:.5,g:2,z:20,ch:22,fi:2,ca:120,fe:.5,mg:20,k2:220,na:40,zn:.6,fo:15,se:4,col:2}},{id:"tpl_1439",nome:"Biscotti integrali all avena e miele",nome_en:"Wholewheat oat and honey biscuits",categoria:"Dolce",porzioni:20,note:"Mescolare fiocchi d avena, farina integrale, miele, olio di semi e un uovo. Formare piccole palline e schiacciarle su una teglia foderata. Cuocere in forno a 170 C per 15 minuti.",note_en:"Mix oat flakes, wholewheat flour, honey, seed oil and an egg. Shape small balls and flatten on a lined tray. Bake at 170 C for 15 minutes.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Farina integrale",qt:"150g"},{nome:"Miele",qt:"100g"},{nome:"Olio di semi",qt:"60ml"},{nome:"Uova",qt:"1"}],_dbEntry:{n:"Biscotti integrali all avena e miele (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:.5,g:4,z:7,ch:16,fi:1.5,ca:10,fe:.8,mg:15,k2:80,na:10,zn:.4,fo:8,se:3,col:10}},{id:"tpl_1440",nome:"Panna cotta light alla vaniglia",nome_en:"Light vanilla panna cotta",categoria:"Dolce",porzioni:4,note:"Scaldare il latte scremato con estratto di vaniglia e poco zucchero. Sciogliere la gelatina ammollata nel latte caldo. Versare negli stampini e raffreddare in frigo per almeno 4 ore. Servire con salsa di frutti di bosco.",note_en:"Heat skimmed milk with vanilla extract and a little sugar. Dissolve soaked gelatin in the warm milk. Pour into molds and chill in the fridge for at least 4 hours. Serve with berry sauce.",ingredienti:[{nome:"Latte scremato",qt:"400ml"},{nome:"Zucchero",qt:"50g"},{nome:"Gelatina in fogli",qt:"8g"},{nome:"Frutti di bosco",qt:"150g"},{nome:"Estratto di vaniglia",qt:"q.b."}],_dbEntry:{n:"Panna cotta light alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:6,gs:.2,g:1,z:20,ch:24,fi:1.5,ca:180,fe:.4,mg:20,k2:250,na:60,zn:.5,fo:10,se:4,col:5}},{id:"tpl_1441",nome:"Torta soffice al limone",nome_en:"Soft lemon cake",categoria:"Dolce",porzioni:8,note:"Montare le uova con lo zucchero fino a renderle spumose. Incorporare farina, olio di semi, succo e scorza di limone e lievito. Versare in una tortiera e cuocere in forno a 180 C per 35 minuti.",note_en:"Whip eggs with sugar until fluffy. Fold in flour, seed oil, lemon juice and zest, and baking powder. Pour into a cake tin and bake at 180 C for 35 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Limone",qt:"2"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta soffice al limone (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:6,gs:1.5,g:10,z:20,ch:44,fi:1,ca:30,fe:1,mg:12,k2:100,na:70,zn:.5,fo:20,se:10,col:90}},{id:"tpl_1442",nome:"Gelato allo yogurt fatto in casa",nome_en:"Homemade frozen yogurt",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco, miele e succo di limone. Versare nella gelatiera e mantecare secondo le istruzioni, oppure congelare mescolando ogni 30 minuti per 3 ore. Servire con frutta fresca.",note_en:"Mix Greek yogurt, honey and lemon juice. Churn in an ice cream maker per instructions, or freeze stirring every 30 minutes for 3 hours. Serve with fresh fruit.",ingredienti:[{nome:"Yogurt greco",qt:"500g"},{nome:"Miele",qt:"80g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Gelato allo yogurt fatto in casa (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:9,gs:1,g:3,z:20,ch:20,fi:.2,ca:150,fe:.2,mg:15,k2:180,na:40,zn:.8,fo:8,se:4,col:8}},{id:"tpl_1443",nome:"Mousse di ricotta e cacao",nome_en:"Ricotta and cocoa mousse",categoria:"Dolce",porzioni:4,note:"Setacciare la ricotta e mescolarla con cacao amaro, miele e un pizzico di cannella fino a ottenere una crema liscia. Servire fredda in coppette guarnendo con granella di nocciole.",note_en:"Sieve ricotta and mix with unsweetened cocoa, honey and a pinch of cinnamon until smooth. Serve chilled in cups, garnishing with chopped hazelnuts.",ingredienti:[{nome:"Ricotta",qt:"300g"},{nome:"Cacao amaro",qt:"20g"},{nome:"Miele",qt:"40g"},{nome:"Nocciole",qt:"20g"}],_dbEntry:{n:"Mousse di ricotta e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:11,gs:5,g:12,z:12,ch:14,fi:2,ca:180,fe:1.5,mg:35,k2:250,na:60,zn:1,fo:20,se:8,col:35}},{id:"tpl_1444",nome:"Crumble di mele e pere",nome_en:"Apple and pear crumble",categoria:"Dolce",porzioni:6,note:"Tagliare mele e pere a cubetti e disporle in una teglia. Preparare un impasto sbriciolato con farina integrale, fiocchi d avena, burro e zucchero di canna. Distribuirlo sopra la frutta e cuocere in forno a 180 C per 30 minuti.",note_en:"Dice apples and pears and arrange in a baking dish. Prepare a crumbly mix with wholewheat flour, oat flakes, butter and cane sugar. Sprinkle over fruit and bake at 180 C for 30 minutes.",ingredienti:[{nome:"Mele",qt:"3"},{nome:"Pere",qt:"2"},{nome:"Farina integrale",qt:"120g"},{nome:"Fiocchi di avena",qt:"80g"},{nome:"Burro",qt:"60g"},{nome:"Zucchero di canna",qt:"60g"}],_dbEntry:{n:"Crumble di mele e pere (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:4,gs:4,g:9,z:22,ch:44,fi:5,ca:25,fe:1.2,mg:25,k2:280,na:40,zn:.5,fo:15,se:5,col:20}},{id:"tpl_1445",nome:"Plumcake integrale alla banana",nome_en:"Wholewheat banana plumcake",categoria:"Dolce",porzioni:10,note:"Schiacciare le banane mature e mescolarle con farina integrale, uova, olio di semi, miele e lievito. Versare in uno stampo da plumcake e cuocere in forno a 170 C per 45 minuti.",note_en:"Mash ripe bananas and mix with wholewheat flour, eggs, seed oil, honey and baking powder. Pour into a loaf tin and bake at 170 C for 45 minutes.",ingredienti:[{nome:"Banane",qt:"3"},{nome:"Farina integrale",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Plumcake integrale alla banana (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:1,g:7,z:16,ch:36,fi:3.5,ca:25,fe:1.2,mg:30,k2:280,na:60,zn:.5,fo:20,se:6,col:40}},{id:"tpl_1446",nome:"Sorbetto di frutta fresca",nome_en:"Fresh fruit sorbet",categoria:"Dolce",porzioni:4,note:"Congelare la frutta fresca a pezzi per almeno 4 ore. Frullare la frutta congelata con succo di limone e un cucchiaio di miele fino a ottenere una consistenza cremosa. Servire subito.",note_en:"Freeze fresh fruit pieces for at least 4 hours. Blend frozen fruit with lemon juice and a spoon of honey until creamy. Serve immediately.",ingredienti:[{nome:"Frutta fresca mista",qt:"500g"},{nome:"Limone",qt:"0.5"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Sorbetto di frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1,gs:.1,g:.3,z:24,ch:26,fi:3,ca:20,fe:.4,mg:15,k2:280,na:2,zn:.2,fo:20,se:1,col:0}},{id:"tpl_1447",nome:"Torta di ricotta e pere",nome_en:"Ricotta and pear cake",categoria:"Dolce",porzioni:8,note:"Mescolare ricotta, uova, zucchero e farina fino a ottenere un composto omogeneo. Aggiungere le pere tagliate a cubetti. Versare in una tortiera e cuocere in forno a 175 C per 45 minuti.",note_en:"Mix ricotta, eggs, sugar and flour until smooth. Add diced pears. Pour into a cake tin and bake at 175 C for 45 minutes.",ingredienti:[{nome:"Ricotta",qt:"400g"},{nome:"Pere",qt:"2"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"120g"},{nome:"Farina 00",qt:"80g"}],_dbEntry:{n:"Torta di ricotta e pere (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:3,g:11,z:18,ch:30,fi:2,ca:130,fe:1,mg:20,k2:200,na:70,zn:.7,fo:20,se:10,col:90}},{id:"tpl_1448",nome:"Bavarese ai frutti di bosco",nome_en:"Berry bavarian cream",categoria:"Dolce",porzioni:6,note:"Frullare i frutti di bosco con zucchero. Scaldare parte del latte e sciogliere la gelatina ammollata. Unire panna montata leggera e la purea di frutta. Versare negli stampini e raffreddare in frigo per 4 ore.",note_en:"Blend berries with sugar. Heat part of the milk and dissolve soaked gelatin. Fold in lightly whipped cream and fruit purée. Pour into molds and chill in the fridge for 4 hours.",ingredienti:[{nome:"Frutti di bosco",qt:"300g"},{nome:"Latte",qt:"150ml"},{nome:"Panna da montare",qt:"150ml"},{nome:"Zucchero",qt:"70g"},{nome:"Gelatina in fogli",qt:"8g"}],_dbEntry:{n:"Bavarese ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:3,gs:5,g:9,z:18,ch:22,fi:2,ca:70,fe:.5,mg:15,k2:150,na:30,zn:.4,fo:10,se:3,col:25}},{id:"tpl_1449",nome:"Biscotti proteici al cioccolato",nome_en:"Chocolate protein cookies",categoria:"Dolce",porzioni:12,note:"Mescolare proteine in polvere al cioccolato, farina di avena, banana schiacciata e gocce di cioccolato fondente. Formare i biscotti e cuocere in forno a 170 C per 12 minuti.",note_en:"Mix chocolate protein powder, oat flour, mashed banana and dark chocolate chips. Shape cookies and bake at 170 C for 12 minutes.",ingredienti:[{nome:"Proteine al cioccolato",qt:"80g"},{nome:"Farina di avena",qt:"150g"},{nome:"Banana",qt:"1"},{nome:"Gocce di cioccolato fondente",qt:"40g"}],_dbEntry:{n:"Biscotti proteici al cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:7,gs:1,g:3,z:6,ch:14,fi:1.5,ca:20,fe:.8,mg:20,k2:120,na:30,zn:.5,fo:8,se:4,col:2}},{id:"tpl_1450",nome:"Macedonia con yogurt e miele",nome_en:"Fruit salad with yogurt and honey",categoria:"Dolce",porzioni:4,note:"Tagliare a cubetti la frutta fresca di stagione. Condire con succo di limone per evitare l ossidazione. Servire con una quenelle di yogurt greco e un filo di miele.",note_en:"Dice fresh seasonal fruit. Dress with lemon juice to prevent browning. Serve with a quenelle of Greek yogurt and a drizzle of honey.",ingredienti:[{nome:"Frutta fresca mista",qt:"500g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"30g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Macedonia con yogurt e miele (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:5,gs:.3,g:2,z:26,ch:28,fi:3,ca:80,fe:.5,mg:20,k2:350,na:30,zn:.4,fo:20,se:2,col:2}}],"function"==typeof rebuildDB&&rebuildDB();